ADMIN_PASSWORD = os.environ.get('ADMIN_PASSWORD') or db.get_setting('admin_password_hash')

# Build type check - controls admin-only features
# Environment variable takes priority over code-level BUILD_TYPE
# This allows overriding USER builds to ADMIN via environment (e.g., Replit Secrets)
_env_build_type = os.environ.get('BUILD_TYPE', '').upper()

def _read_build_type_from_source() -> str:
    """Read BUILD_TYPE from selfbot_webull.py source without importing/executing it.
    
    Importing selfbot_webull executes ~600 lines of top-level code (SSL patches,
    license checks, broker imports, print statements). When Flask is started from
    a PySide6 Qt timer callback (Windows EXE builds), this re-execution on the
    Flask thread deadlocks the Qt event loop, hanging the entire startup before
    Discord ever connects.
    
    This function safely reads the file and extracts the BUILD_TYPE constant
    via regex — no code execution, no side effects.
    """
    import sys
    candidates = []
    repo_root = Path(__file__).resolve().parent.parent
    candidates.extend([
        repo_root / 'src' / 'selfbot_webull.py',
        repo_root / 'selfbot_webull.py',
    ])
    meipass = getattr(sys, '_MEIPASS', None)
    if meipass:
        meipass_path = Path(meipass)
        candidates.extend([
            meipass_path / 'src' / 'selfbot_webull.py',
            meipass_path / 'selfbot_webull.py',
        ])
    for path in candidates:
        try:
            text = path.read_text(encoding='utf-8', errors='ignore')
        except Exception:
            continue
        m = re.search(r"^BUILD_TYPE\s*=\s*['\"](\w+)['\"]", text, re.MULTILINE)
        if m and m.group(1).upper() in ('ADMIN', 'USER'):
            return m.group(1).upper()
    return 'USER'

if _env_build_type in ('ADMIN', 'USER'):
    BUILD_TYPE = _env_build_type
else:
    BUILD_TYPE = _read_build_type_from_source()

def is_admin_build():
    """Check if this is an admin build with full features"""
    return str(BUILD_TYPE).upper() == 'ADMIN'

def admin_feature_required(f):
    """Decorator to restrict endpoints to admin builds only"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not is_admin_build():
            return jsonify({'success': False, 'error': 'This feature is not available'}), 403
        return f(*args, **kwargs)
    return decorated_function


# Module-level function for multiprocessing (must be picklable)
def _launch_wizard_process_target():
    """Run wizard in a separate process to avoid Qt threading issues.
    This function must be at module level for multiprocessing to work.
    """
    import tempfile
    import time
    import os
    import sys
    
    process_log_path = os.path.join(tempfile.gettempdir(), 'botifytrades_wizard_process.log')
    
    def log_to_file(msg):
        try:
            with open(process_log_path, 'a') as f:
                f.write(f"[{time.strftime('%H:%M:%S')}] {msg}\n")
        except:
            pass
    
    log_to_file("=" * 50)
    log_to_file("[Process] Starting wizard process...")
    log_to_file(f"[Process] PID: {os.getpid()}")
    log_to_file(f"[Process] sys._MEIPASS: {getattr(sys, '_MEIPASS', 'N/A')}")
    
    try:
        log_to_file("[Process] Attempting to import ui.wizard.launcher...")
        from ui.wizard.launcher import launch_wizard
        log_to_file("[Process] Import successful!")
        
        log_to_file("[Process] Calling launch_wizard(skip_first_run_check=True)...")
        result = launch_wizard(skip_first_run_check=True)
        log_to_file(f"[Process] launch_wizard returned: {result}")
        
    except Exception as e:
        log_to_file(f"[Process] EXCEPTION: {type(e).__name__}: {e}")
        import traceback
        log_to_file(traceback.format_exc())
    
    log_to_file("[Process] Process function exiting")

# Public routes that don't require authentication
PUBLIC_ROUTES = ['/login', '/architecture', '/static', '/signup', '/user/login', '/google_login', '/consent', '/api/consent', '/privacy-policy']

# Rate limiting for login attempts (brute force protection)
_login_attempts: Dict[str, list] = {}  # {ip: [timestamp1, timestamp2, ...]}
_max_attempts = 5  # Max attempts per window
_lockout_window = 300  # 5 minutes in seconds

import math

def _cboe_round_option_price(price: float, is_sell: bool = True) -> float:
    if price <= 0:
        return 0.05
    tick = 0.05 if price < 3.0 else 0.10
    if is_sell:
        rounded = math.floor(price / tick) * tick
    else:
        rounded = math.ceil(price / tick) * tick
    rounded = round(rounded, 2)
    return max(tick, rounded)

def fetch_stock_price_reliable(symbol: str) -> float:
    """Fetch stock price using yfinance as primary source (works for stocks and indices like SPX).
    Returns the price or 0 if unable to fetch.
    """
    try:
        import yfinance as yf
        # For index options, map to the correct yfinance ticker
        yf_symbol = symbol
        if symbol == 'SPX':
            yf_symbol = '^GSPC'  # S&P 500 Index
        elif symbol == 'NDX':
            yf_symbol = '^NDX'  # Nasdaq 100 Index
        elif symbol == 'RUT':
            yf_symbol = '^RUT'  # Russell 2000
        elif symbol == 'VIX':
            yf_symbol = '^VIX'  # VIX
        elif symbol == 'DJI' or symbol == 'DJX':
            yf_symbol = '^DJI'  # Dow Jones
            
        ticker = yf.Ticker(yf_symbol)
        hist = ticker.history(period="1d")
        if not hist.empty and 'Close' in hist.columns:
            price = float(hist['Close'].iloc[-1])
            if price and price > 0:
                print(f"[OPTIONS] ✓ Fetched {symbol} price via yfinance: ${price:.2f}", flush=True)
                return price
        print(f"[OPTIONS] yfinance returned no data for {symbol} (yf: {yf_symbol})", flush=True)
    except Exception as e:
        print(f"[OPTIONS] yfinance error for {symbol}: {e}", flush=True)
    return 0

def _check_rate_limit(ip: str) -> tuple:
    """Check if IP is rate limited. Returns (is_allowed, seconds_remaining)"""
    now = time.time()
    
    if ip not in _login_attempts:
        _login_attempts[ip] = []
    
    # Clean old attempts outside the window
    _login_attempts[ip] = [t for t in _login_attempts[ip] if now - t < _lockout_window]
    
    if len(_login_attempts[ip]) >= _max_attempts:
        oldest = min(_login_attempts[ip])
        remaining = int(_lockout_window - (now - oldest))
        return False, remaining
    
    return True, 0

def _record_failed_attempt(ip: str):
    """Record a failed login attempt"""
    now = time.time()
    if ip not in _login_attempts:
        _login_attempts[ip] = []
    _login_attempts[ip].append(now)

def _clear_attempts(ip: str):
    """Clear login attempts after successful login"""
    if ip in _login_attempts:
        del _login_attempts[ip]

def check_consent_accepted():
    """Check if user has accepted the agreement."""
    try:
        consent_accepted = db.get_setting('user_consent_accepted', 'false')
        consent_version = db.get_setting('user_consent_version', None)
        return consent_accepted.lower() == 'true' and consent_version == '3.0'
    except:
        return False

def login_required(f):
    """Decorator to require login for protected routes"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('logged_in'):
            if request.path.startswith('/api/'):
                return jsonify({'success': False, 'error': 'Authentication required'}), 401
            return redirect(url_for('login'))
        if not check_consent_accepted() and request.path not in ['/consent', '/consent/declined']:
            return redirect(url_for('consent_page'))
        return f(*args, **kwargs)
    return decorated_function

def admin_required(f):
    """Decorator to require admin access for protected routes"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('logged_in'):
            if request.path.startswith('/api/'):
                return jsonify({'success': False, 'error': 'Authentication required'}), 401
            return redirect(url_for('login'))
        if not session.get('is_admin'):
            if request.path.startswith('/api/'):
                return jsonify({'success': False, 'error': 'Admin access required'}), 403
            return render_template('error.html', 
                                   error_title='Access Denied',
                                   error_message='This page requires administrator access.'), 403
        return f(*args, **kwargs)
    return decorated_function

# Import Alpaca data provider for option chains
import sys
import os
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))
from src.data_providers.alpaca_data_provider import get_alpaca_provider

# Global variable to store bot instance reference (set by main bot)
_bot_instance: Optional[Any] = None

# Cache for API responses to prevent rate limiting
_api_cache: Dict[str, tuple] = {}  # {key: (value, timestamp)}

# Option chain cache to avoid re-fetching for same symbol/expiry
_option_chain_cache: Dict[str, tuple] = {}  # {symbol_expiry: (chain_data, timestamp)}
_CHAIN_CACHE_TTL = 3  # Cache for 3 seconds (options move fast)
_TRAILING_ZERO_RE = re.compile(r'_(\d+)\.0_([CP])$')

_standalone_webull_broker = None

def get_webull_broker():
    """Get the Webull broker instance from the bot for option data.
    Falls back to creating standalone broker from database credentials.
    """
    global _standalone_webull_broker
    if _bot_instance and hasattr(_bot_instance, 'broker') and _bot_instance.broker:
        return _bot_instance.broker
    
    if _standalone_webull_broker is not None:
        return _standalone_webull_broker
    
    try:
        credentials = db.get_webull_credentials()
        if credentials and credentials.get('access_token'):
            from src.brokers.webull_broker import WebullBroker
            _standalone_webull_broker = WebullBroker(credentials, paper_trade=True)
            if _standalone_webull_broker.client:
                print("[OPTIONS] Created standalone Webull broker from database credentials")
                return _standalone_webull_broker
    except Exception as e:
        print(f"[OPTIONS] Could not create standalone Webull broker: {e}")
    
    return None

_standalone_loop = None

def get_webull_loop():
    """Get the bot's event loop for async calls.
    Falls back to creating a standalone loop when bot isn't running.
    """
    global _standalone_loop
    
    if _bot_instance and hasattr(_bot_instance, 'loop') and _bot_instance.loop and not _bot_instance.loop.is_closed():
        return _bot_instance.loop
    
    if _standalone_loop is None or _standalone_loop.is_closed():
        _standalone_loop = asyncio.new_event_loop()
    
    return _standalone_loop

def get_cached_option_chain_webull(symbol: str, expiry: str) -> dict:
    """Get option chain from Webull with caching to prevent repeated API calls.
    Returns chain data with 'data_source' field indicating 'Webull' or 'Alpaca (fallback)'
    """
    import sys
    cache_key = f"{symbol}_{expiry}"
    now = time.time()
    
    print(f"[OPTIONS] get_cached_option_chain_webull called for {symbol} {expiry}", flush=True)
    sys.stdout.flush()
    
    if cache_key in _option_chain_cache:
        cached_data, cached_time = _option_chain_cache[cache_key]
        if now - cached_time < _CHAIN_CACHE_TTL:
            return cached_data
    
    broker = get_webull_broker()
    loop = get_webull_loop()
    
    if broker and loop:
        try:
            future = asyncio.run_coroutine_threadsafe(
                broker.get_option_chain(symbol, expiry),
                loop
            )
            chain = future.result(timeout=25)
            calls_count = len(chain.get('calls', [])) if chain else 0
            puts_count = len(chain.get('puts', [])) if chain else 0
            
            if chain and (chain.get('calls') or chain.get('puts')):
                has_valid_prices = False
                all_options = chain.get('calls', []) + chain.get('puts', [])
                for opt in all_options:
                    if opt.get('bid', 0) > 0 or opt.get('ask', 0) > 0:
                        has_valid_prices = True
                        break
                
                if has_valid_prices:
                    chain['data_source'] = 'Webull'
                else:
                    chain['data_source'] = 'Webull (no live quotes)'
                    print(f"[OPTIONS] Webull chain has no live bid/ask for {symbol} — may be after hours", flush=True)
                
                if not chain.get('stock_price') or chain.get('stock_price', 0) <= 0:
                    stock_price = fetch_stock_price_reliable(symbol)
                    if stock_price > 0:
                        chain['stock_price'] = stock_price
                _option_chain_cache[cache_key] = (chain, now)
                print(f"[OPTIONS] ✓ Using {chain['data_source']} for {cache_key} ({calls_count}C/{puts_count}P)", flush=True)
                return chain
            else:
                print(f"[OPTIONS] Webull returned empty chain for {symbol}, trying Alpaca fallback...", flush=True)
        except Exception as e:
            print(f"[OPTIONS] Webull option chain error for {symbol}: {type(e).__name__}: {e}", flush=True)
            import traceback
            traceback.print_exc()
    else:
        print(f"[OPTIONS] Webull broker or loop not available, trying Alpaca fallback", flush=True)
    
    alpaca = get_alpaca_provider()
    if alpaca:
        new_loop = asyncio.new_event_loop()
        asyncio.set_event_loop(new_loop)
        try:
            chain = new_loop.run_until_complete(alpaca.get_option_chain(symbol, expiry))
            chain['data_source'] = 'Alpaca'
            _option_chain_cache[cache_key] = (chain, now)
            print(f"[OPTIONS] Using Alpaca data for {cache_key}")
            return chain
        except Exception as e:
            print(f"[OPTIONS] Alpaca fallback also failed: {e}")
        finally:
            new_loop.close()
    
    return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Error'}

def get_cached_option_chain(symbol: str, expiry: str, alpaca) -> dict:
    """Get option chain with caching to prevent repeated API calls (legacy Alpaca fallback)"""
    cache_key = f"{symbol}_{expiry}"
    now = time.time()
    
    if cache_key in _option_chain_cache:
        cached_data, cached_time = _option_chain_cache[cache_key]
        if now - cached_time < _CHAIN_CACHE_TTL:
            print(f"[CACHE] Using cached option chain for {cache_key}")
            return cached_data
    
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    try:
        chain = loop.run_until_complete(alpaca.get_option_chain(symbol, expiry))
        _option_chain_cache[cache_key] = (chain, now)
        print(f"[CACHE] Fetched and cached option chain for {cache_key}")
        return chain
    finally:
        loop.close()

def get_cached_option_chain_alpaca(symbol: str, expiry: str) -> dict:
    """Get option chain from Alpaca with caching.
    Returns chain data with 'data_source' field indicating 'Alpaca'
    """
    cache_key = f"ALPACA_{symbol}_{expiry}"
    now = time.time()
    
    print(f"[OPTIONS] get_cached_option_chain_alpaca called for {symbol} {expiry}", flush=True)
    
    if cache_key in _option_chain_cache:
        cached_data, cached_time = _option_chain_cache[cache_key]
        if now - cached_time < _CHAIN_CACHE_TTL:
            print(f"[OPTIONS] Using cached Alpaca option chain for {cache_key}", flush=True)
            return cached_data
    
    alpaca = get_alpaca_provider()
    if not alpaca:
        print(f"[OPTIONS] Alpaca provider not available", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Error: Alpaca not configured'}
    
    new_loop = asyncio.new_event_loop()
    asyncio.set_event_loop(new_loop)
    try:
        chain = new_loop.run_until_complete(alpaca.get_option_chain(symbol, expiry))
        chain['data_source'] = 'Alpaca'
        # Fetch stock price if not in chain - use yfinance for reliability
        if not chain.get('stock_price') or chain.get('stock_price', 0) <= 0:
            stock_price = fetch_stock_price_reliable(symbol)
            if stock_price > 0:
                chain['stock_price'] = stock_price
        _option_chain_cache[cache_key] = (chain, now)
        print(f"[OPTIONS] ✓ Using Alpaca data for {symbol} {expiry} (stock_price={chain.get('stock_price')})", flush=True)
        return chain
    except Exception as e:
        print(f"[OPTIONS] Alpaca option chain error: {e}", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': f'Error: {str(e)}'}
    finally:
        new_loop.close()

def get_cached_option_chain_ibkr(symbol: str, expiry: str) -> dict:
    """Get option chain from IBKR with caching.
    Returns chain data with 'data_source' field indicating 'IBKR'
    """
    cache_key = f"IBKR_{symbol}_{expiry}"
    now = time.time()
    
    print(f"[OPTIONS] get_cached_option_chain_ibkr called for {symbol} {expiry}", flush=True)
    
    if cache_key in _option_chain_cache:
        cached_data, cached_time = _option_chain_cache[cache_key]
        if now - cached_time < _CHAIN_CACHE_TTL:
            print(f"[OPTIONS] Using cached IBKR option chain for {cache_key}", flush=True)
            return cached_data
    
    if not _bot_instance or not hasattr(_bot_instance, 'ibkr_broker') or not _bot_instance.ibkr_broker:
        print(f"[OPTIONS] IBKR broker not available", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Error: IBKR not configured'}
    
    if not hasattr(_bot_instance, 'loop') or not _bot_instance.loop or _bot_instance.loop.is_closed():
        print(f"[OPTIONS] Bot event loop not available for IBKR", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Error: Bot loop unavailable'}
    
    try:
        import asyncio
        
        async def _get_chain():
            return await _bot_instance.ibkr_broker.get_option_chain(symbol, expiry)
        
        future = asyncio.run_coroutine_threadsafe(
            _get_chain(),
            _bot_instance.loop
        )
        chain = future.result(timeout=15)
        
        if not chain:
            print(f"[OPTIONS] IBKR returned empty chain for {symbol} {expiry}", flush=True)
            return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'IBKR (no data)'}
        
        chain['data_source'] = 'IBKR'
        # Fetch stock price if not in chain - use yfinance for reliability
        if not chain.get('stock_price') or chain.get('stock_price', 0) <= 0:
            stock_price = fetch_stock_price_reliable(symbol)
            if stock_price > 0:
                chain['stock_price'] = stock_price
        _option_chain_cache[cache_key] = (chain, now)
        print(f"[OPTIONS] ✓ Using IBKR data for {symbol} {expiry} (stock_price={chain.get('stock_price')})", flush=True)
        return chain
    except Exception as e:
        print(f"[OPTIONS] IBKR option chain error: {e}", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': f'Error: {str(e)}'}

def get_cached_option_chain_tastytrade(symbol: str, expiry: str) -> dict:
    """Get option chain from Tastytrade with caching.
    Returns chain data with 'data_source' field indicating 'Tastytrade'
    """
    cache_key = f"TASTYTRADE_{symbol}_{expiry}"
    now = time.time()
    
    print(f"[OPTIONS] get_cached_option_chain_tastytrade called for {symbol} {expiry}", flush=True)
    
    if cache_key in _option_chain_cache:
        cached_data, cached_time = _option_chain_cache[cache_key]
        if now - cached_time < _CHAIN_CACHE_TTL:
            print(f"[OPTIONS] Using cached Tastytrade option chain for {cache_key}", flush=True)
            return cached_data
    
    if not _bot_instance or not hasattr(_bot_instance, 'tastytrade_broker') or not _bot_instance.tastytrade_broker:
        print(f"[OPTIONS] Tastytrade broker not available", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Error: Tastytrade not configured'}
    
    try:
        import concurrent.futures
        
        def _get_chain_sync():
            return _bot_instance.tastytrade_broker.get_option_chain(symbol, expiry)
        
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(_get_chain_sync)
            chain = future.result(timeout=15)
        
        if not chain:
            print(f"[OPTIONS] Tastytrade returned empty chain for {symbol} {expiry}", flush=True)
            return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': 'Tastytrade (no data)'}
        
        # Fetch stock price if not in chain - use yfinance for reliability
        if not chain.get('stock_price') or chain.get('stock_price', 0) <= 0:
            stock_price = fetch_stock_price_reliable(symbol)
            if stock_price > 0:
                chain['stock_price'] = stock_price
        
        _option_chain_cache[cache_key] = (chain, now)
        data_source = chain.get('data_source', 'Tastytrade')
        print(f"[OPTIONS] ✓ Using Tastytrade data for {symbol} {expiry} (source: {data_source}, stock_price={chain.get('stock_price')})", flush=True)
        return chain
    except Exception as e:
        print(f"[OPTIONS] Tastytrade option chain error: {e}", flush=True)
        return {'calls': [], 'puts': [], 'stock_price': None, 'data_source': f'Error: {str(e)}'}

