    @app.route('/api/webull/balance', methods=['GET'])
    def api_webull_balance() -> Any:
        """Get Webull account balance"""
        import asyncio
        
        # Check cache first (5 second TTL)
        cache_key = 'webull_balance'
        if cache_key in _api_cache:
            cached_value, timestamp = _api_cache[cache_key]
            if time.time() - timestamp < 5:
                return cached_value
        
        if not _bot_instance or not hasattr(_bot_instance, 'broker'):
            # Fallback: Use WebullAuth directly when bot is not running
            try:
                from src.webull_auth import WebullAuth
                from .broker_credentials_service import webull_credentials_adapter, get_webull_credentials
                
                creds = get_webull_credentials()
                if creds.get('email') and creds.get('password') and creds.get('trade_pin'):
                    auth = WebullAuth(paper_trading=creds.get('paper_mode', True), credentials_adapter=webull_credentials_adapter)
                    login_result = auth.login(
                        email=creds.get('email'),
                        password=creds.get('password'),
                        trading_pin=creds.get('trade_pin'),
                        device_id=creds.get('device_id')
                    )
                    if login_result.get('success'):
                        account_result = auth.get_account_info()
                        if account_result.get('success'):
                            raw_acct = account_result.get('account', {})
                            acct_data = {}
                            acct_members = raw_acct.get('accountMembers', [])
                            if acct_members and isinstance(acct_members, list):
                                for item in acct_members:
                                    if isinstance(item, dict) and 'key' in item and 'value' in item:
                                        acct_data[item['key']] = item['value']
                            for k, v in raw_acct.items():
                                if k != 'accountMembers' and k not in acct_data:
                                    acct_data[k] = v
                            def _sf(keys, fb=0.0):
                                for key in keys:
                                    if key in acct_data:
                                        try: return float(acct_data[key])
                                        except: pass
                                return fb
                            result = jsonify({
                                'buying_power': _sf(['buyingPower', 'dayBuyingPower', 'usableCash']),
                                'cash_balance': _sf(['cashBalance', 'totalCashValue', 'usableCash']),
                                'net_liquidation': _sf(['netLiquidation', 'totalMarketValue']),
                                'total_profit_loss': _sf(['unrealizedProfitLoss']),
                                'day_profit_loss': _sf(['dayProfitLoss']),
                                'settled_cash': _sf(['settledCash', 'settledFunds']),
                                'unsettled_cash': _sf(['unsettledCash', 'unsettledFunds']),
                                'status': 'ok'
                            })
                            _api_cache[cache_key] = (result, time.time())
                            return result
            except Exception as e:
                print(f"[WEBULL_BALANCE] WebullAuth fallback error: {e}")
            
            result = jsonify({
                'buying_power': 0,
                'cash_balance': 0,
                'net_liquidation': 0,
                'total_profit_loss': 0,
                'day_profit_loss': 0,
                'settled_cash': 0,
                'unsettled_cash': 0,
                'status': 'initializing'
            })
            _api_cache[cache_key] = (result, time.time())
            return result
        
        try:
            import concurrent.futures
            
            def _direct_webull_balance():
                elapsed = time.time() - _startup_time
                if elapsed < _startup_delay_seconds:
                    return None
                if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
                    return None
                try:
                    from src.services.webull_data_hub import get_webull_data_hub
                    hub = get_webull_data_hub()
                    cached = hub.get_account_info(max_age_seconds=300)
                    if cached and isinstance(cached, dict) and not cached.get('code'):
                        return cached
                except Exception:
                    pass
                wb = getattr(_bot_instance.broker, '_client', None)
                if not wb:
                    return None
                raw_account = wb.get_account()
                if isinstance(raw_account, dict) and raw_account.get('code') == 'auth.token.expire':
                    return None
                if not raw_account:
                    return None
                
                account_data = {}
                account_members = raw_account.get('accountMembers', [])
                if account_members and isinstance(account_members, list):
                    for item in account_members:
                        if isinstance(item, dict) and 'key' in item and 'value' in item:
                            account_data[item['key']] = item['value']
                for k, v in raw_account.items():
                    if k != 'accountMembers' and k not in account_data:
                        account_data[k] = v
                
                def _safe_float(keys, fallback=0.0):
                    for key in keys:
                        if key in account_data:
                            try:
                                val = float(account_data[key])
                                return val
                            except (ValueError, TypeError):
                                pass
                    return fallback
                
                buying_power = _safe_float(['buyingPower', 'dayBuyingPower', 'usableCash', 'cashAvailableForTrade'])
                cash_balance = _safe_float(['cashBalance', 'totalCashValue', 'usableCash', 'cash'])
                net_liq = _safe_float(['netLiquidation', 'totalMarketValue', 'accountValue'])
                total_pl = _safe_float(['unrealizedProfitLoss', 'unrealizedPL'])
                day_pl = _safe_float(['dayProfitLoss', 'dayPnl'])
                settled = _safe_float(['settledCash', 'settledFunds'])
                unsettled = _safe_float(['unsettledCash', 'unsettledFunds'])
                options_bp = _safe_float(['optionBuyingPower'])
                if options_bp <= 0:
                    options_bp = buying_power
                
                return {
                    'buying_power': buying_power, 'cash_balance': cash_balance,
                    'net_liquidation': net_liq, 'total_profit_loss': total_pl,
                    'day_profit_loss': day_pl, 'settled_cash': settled,
                    'unsettled_cash': unsettled, 'options_buying_power': options_bp,
                    'status': 'ok'
                }
            
            with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                account_data = executor.submit(_direct_webull_balance).result(timeout=10)
            
            if account_data:
                result = jsonify(account_data)
                _api_cache[cache_key] = (result, time.time())
                return result
            else:
                result = jsonify({
                    'buying_power': 0, 'cash_balance': 0, 'net_liquidation': 0,
                    'total_profit_loss': 0, 'day_profit_loss': 0, 'status': 'loading'
                })
                _api_cache[cache_key] = (result, time.time())
                return result
                
        except Exception as e:
            err_type = type(e).__name__
            err_msg = str(e) or 'no details'
            print(f"[API] Exception in balance endpoint: {err_type}: {err_msg}")
            import traceback
            traceback.print_exc()
            result = jsonify({
                'buying_power': 0, 'cash_balance': 0, 'net_liquidation': 0,
                'total_profit_loss': 0, 'day_profit_loss': 0,
                'status': 'error', 'error': f"{err_type}: {err_msg}"
            })
            _api_cache[cache_key] = (result, time.time())
            return result
    
