    @app.route('/api/alpaca/balance', methods=['GET'])
    def api_alpaca_balance() -> Any:
        """Get Alpaca paper account balance for Dashboard"""
        import asyncio
        
        # Check cache first (5 second TTL)
        cache_key = 'alpaca_balance'
        if cache_key in _api_cache:
            cached_value, timestamp = _api_cache[cache_key]
            if time.time() - timestamp < 5:
                return cached_value
        
        if not _bot_instance or not hasattr(_bot_instance, 'paper_broker') or not _bot_instance.paper_broker:
            result = jsonify({
                'buying_power': 0,
                'cash_balance': 0,
                'net_liquidation': 0,
                'equity': 0,
                'unrealized_pnl': 0,
                'status': 'not_initialized'
            })
            _api_cache[cache_key] = (result, time.time())
            return result
        
        try:
            import concurrent.futures
            
            def _direct_alpaca_balance():
                paper_broker = _bot_instance.paper_broker
                if not hasattr(paper_broker, 'trading_client') or not paper_broker.trading_client:
                    return None
                try:
                    from pydantic import ValidationError
                    try:
                        account = paper_broker.trading_client.get_account()
                    except ValidationError:
                        return None
                    
                    buying_power = float(account.buying_power)
                    cash = float(account.cash)
                    equity = float(account.equity)
                    unrealized_pnl = 0.0
                    if hasattr(account, 'unrealized_plpc') and account.unrealized_plpc:
                        unrealized_pnl = float(equity) * (float(account.unrealized_plpc) / 100.0)
                    
                    return {
                        'buying_power': buying_power, 'cash_balance': cash,
                        'net_liquidation': equity, 'equity': equity,
                        'unrealized_pnl': unrealized_pnl, 'status': 'ok'
                    }
                except Exception as inner_e:
                    print(f"[API] Alpaca direct balance error: {inner_e}")
                    return None
            
            with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                account_data = executor.submit(_direct_alpaca_balance).result(timeout=10)
            
            if account_data:
                result = jsonify(account_data)
                _api_cache[cache_key] = (result, time.time())
                return result
            else:
                result = jsonify({
                    'buying_power': 0, 'cash_balance': 0, 'net_liquidation': 0,
                    'equity': 0, 'unrealized_pnl': 0, 'status': 'loading'
                })
                _api_cache[cache_key] = (result, time.time())
                return result
                
        except Exception as e:
            print(f"[API] Exception in Alpaca balance endpoint: {e}")
            result = jsonify({
                'buying_power': 0,
                'cash_balance': 0,
                'net_liquidation': 0,
                'equity': 0,
                'unrealized_pnl': 0,
                'status': 'error',
                'error': str(e)
            })
            _api_cache[cache_key] = (result, time.time())
            return result
    
    @app.route('/api/tastytrade/balance', methods=['GET'])
    def api_tastytrade_balance() -> Any:
        """Get Tastytrade account balance for Dashboard — uses bot's live broker instance"""
        import asyncio
        
        paper_mode = request.args.get('paper', 'false').lower() == 'true'
        
        cache_key = f'tastytrade_balance_{"paper" if paper_mode else "live"}'
        if cache_key in _api_cache:
            cached_value, timestamp = _api_cache[cache_key]
            if time.time() - timestamp < 5:
                return cached_value
        
        try:
            broker = None
            if _bot_instance:
                broker = getattr(_bot_instance, 'tastytrade_broker', None)
            
            if broker and getattr(broker, 'connected', False):
                loop = asyncio.new_event_loop()
                asyncio.set_event_loop(loop)
                try:
                    account_info = loop.run_until_complete(broker.get_account_info())
                    result = jsonify({
                        'buying_power': account_info.get('buying_power', 0),
                        'cash_balance': account_info.get('cash', 0),
                        'net_liquidation': account_info.get('portfolio_value', 0),
                        'equity': account_info.get('portfolio_value', 0),
                        'unrealized_pnl': 0,
                        'options_buying_power': account_info.get('options_buying_power', 0),
                        'account_number': account_info.get('account_number', ''),
                        'status': 'ok'
                    })
                    _api_cache[cache_key] = (result, time.time())
                    return result
                finally:
                    loop.close()
            else:
                from .broker_credentials_service import get_broker_status
                broker_id = 'tastytrade_paper' if paper_mode else 'tastytrade_live'
                status = get_broker_status(broker_id)
                acct_info = status.get('account_info') or {}
                result = jsonify({
                    'buying_power': acct_info.get('buying_power', 0),
                    'cash_balance': acct_info.get('cash', 0),
                    'net_liquidation': acct_info.get('portfolio_value', 0),
                    'equity': acct_info.get('portfolio_value', 0),
                    'unrealized_pnl': 0,
                    'options_buying_power': acct_info.get('options_buying_power', 0),
                    'account_number': acct_info.get('account_number', ''),
                    'status': 'ok' if status.get('connected') else 'disconnected',
                })
                return result
                
        except Exception as e:
            print(f"[API] Exception in Tastytrade balance endpoint: {e}")
            import traceback
            traceback.print_exc()
            result = jsonify({
                'buying_power': 0,
                'cash_balance': 0,
                'net_liquidation': 0,
                'equity': 0,
                'unrealized_pnl': 0,
                'status': 'error',
                'error': str(e)
            })
            return result

