    async def _get_webull_open_orders():
        """Helper to get Webull open orders"""
        if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
            return None
        
        wb = _bot_instance.broker._client
        if not wb:
            return None
        
        def _blocking_call():
            try:
                from src.services.webull_data_hub import get_webull_data_hub
                hub = get_webull_data_hub()
                cached_orders = hub.get_pending_orders(max_age_seconds=15)
                if cached_orders is not None:
                    return cached_orders
            except Exception:
                pass
            account_info = wb.get_account()
            open_orders = account_info.get('openOrders', [])
            
            # Format orders for frontend
            formatted_orders = []
            for order in open_orders:
                # Convert numeric fields to proper types
                quantity = order.get('totalQuantity', 0)
                filled_quantity = order.get('filledQuantity', 0)
                limit_price = order.get('lmtPrice', 0)
                
                # Ensure numeric fields are floats/ints
                try:
                    quantity = int(quantity) if quantity else 0
                except (ValueError, TypeError):
                    quantity = 0
                
                try:
                    filled_quantity = int(filled_quantity) if filled_quantity else 0
                except (ValueError, TypeError):
                    filled_quantity = 0
                
                try:
                    limit_price = float(limit_price) if limit_price else 0.0
                except (ValueError, TypeError):
                    limit_price = 0.0
                
                # Detect asset type (option vs stock)
                asset_type = 'option' if order.get('optionId') or order.get('optionType') else 'stock'
                
                formatted_orders.append({
                    'order_id': order.get('orderId', 'N/A'),
                    'symbol': order.get('ticker', {}).get('symbol', 'N/A'),
                    'action': order.get('action', 'N/A'),
                    'quantity': quantity,
                    'filled_quantity': filled_quantity,
                    'limit_price': limit_price,
                    'order_type': order.get('orderType', 'N/A'),
                    'status': order.get('status', 'N/A'),
                    'created_time': order.get('createTime0', 'N/A'),
                    'asset_type': asset_type
                })
            
            return formatted_orders
        
        return await run_async_safely(_blocking_call)
    
    @app.route('/api/webull/order-history')
    def get_webull_order_history():
        """Get filled/executed order history from Webull"""
        print(f"[API] /api/webull/order-history called")
        if _bot_instance is None:
            print("[API] Bot not initialized - using database fallback")
            return _get_webull_orders_from_db()
        
        try:
            count = int(request.args.get('count', 50))
            status = request.args.get('status', 'Filled')  # Default to filled orders
            
            future = asyncio.run_coroutine_threadsafe(
                _get_webull_order_history(status=status, count=count),
                _bot_instance.loop
            )
            orders_data = future.result(timeout=15)
            
            if orders_data is not None and len(orders_data) > 0:
                return jsonify({'orders': orders_data})
            else:
                # Fallback to database filled_orders if Webull API returns empty
                print("[API] Webull API returned empty, falling back to database")
                return _get_webull_orders_from_db(count)
                
        except Exception as e:
            print(f"[API] Error fetching order history: {e} - using database fallback")
            return _get_webull_orders_from_db()
    
    def _get_webull_orders_from_db(count=50):
        """Fallback: Get Webull orders from synced filled_orders database table"""
        try:
            from gui_app.database import get_filled_orders
            orders = get_filled_orders(broker='Webull', days=30, limit=count)
            
            # Format orders to match expected structure
            formatted_orders = []
            for order in orders:
                formatted_orders.append({
                    'order_id': order.get('broker_order_id', 'N/A'),
                    'symbol': order.get('symbol', 'N/A'),
                    'action': 'BUY' if order.get('side') == 'BTO' else 'SELL',
                    'side': order.get('side', 'N/A'),
                    'quantity': order.get('quantity', 0),
                    'filled_quantity': order.get('quantity', 0),
                    'limit_price': order.get('filled_price', 0),
                    'avg_filled_price': order.get('filled_price', 0),
                    'order_type': 'LIMIT',
                    'status': 'Filled',
                    'fill_status': 'Filled',
                    'created_time': order.get('filled_at', ''),
                    'filled_time': order.get('filled_at', ''),
                    'asset_type': order.get('asset_type', 'option'),
                    'broker': 'WEBULL',
                    'source': 'database_sync',
                    'strike': order.get('strike', ''),
                    'expiry': order.get('expiry', ''),
                    'option_type': order.get('option_type', '')
                })
            
            print(f"[API] Returning {len(formatted_orders)} Webull orders from database")
            return jsonify({'orders': formatted_orders, 'source': 'database'})
            
        except Exception as e:
            print(f"[API] Database fallback also failed: {e}")
            return jsonify({'error': str(e), 'orders': []}), 500
    
    async def _get_webull_order_history(status='Filled', count=50):
        """Helper to get Webull order history (filled/executed orders)"""
        if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
            return None
        
        wb = _bot_instance.broker._client
        if not wb:
            return None
        
        def _blocking_call():
            try:
                history_orders = wb.get_history_orders(status=status, count=count)
                
                # If Filled returns nothing, try All status
                if not history_orders and status == 'Filled':
                    history_orders = wb.get_history_orders(status='All', count=count)
                
                if not history_orders:
                    return []
                
                formatted_orders = []
                for order in history_orders:
                    # Extract order details
                    ticker_info = order.get('ticker', {})
                    symbol = ticker_info.get('symbol', 'N/A')
                    
                    # Get quantities
                    quantity = order.get('totalQuantity', 0)
                    filled_quantity = order.get('filledQuantity', 0)
                    
                    try:
                        quantity = int(quantity) if quantity else 0
                        filled_quantity = int(filled_quantity) if filled_quantity else 0
                    except (ValueError, TypeError):
                        quantity = 0
                        filled_quantity = 0
                    
                    # Get prices
                    limit_price = order.get('lmtPrice', 0)
                    avg_filled_price = order.get('avgFilledPrice', 0)
                    
                    try:
                        limit_price = float(limit_price) if limit_price else 0.0
                        avg_filled_price = float(avg_filled_price) if avg_filled_price else 0.0
                    except (ValueError, TypeError):
                        limit_price = 0.0
                        avg_filled_price = 0.0
                    
                    # Detect asset type
                    is_option = bool(order.get('optionId') or order.get('optionType'))
                    asset_type = 'option' if is_option else 'stock'
                    
                    # Get action (BUY/SELL)
                    action = order.get('action', 'N/A')
                    
                    # Get timestamps
                    create_time = order.get('createTime0', '')
                    filled_time = order.get('filledTime0', '') or order.get('updateTime0', '')
                    
                    # Option-specific fields
                    option_info = {}
                    if is_option:
                        option_info = {
                            'strike': order.get('optionExercisePrice', ''),
                            'expiry': order.get('optionExpireDate', ''),
                            'option_type': order.get('optionType', ''),  # call/put
                            'option_id': order.get('optionId', '')
                        }
                    
                    formatted_orders.append({
                        'order_id': order.get('orderId', 'N/A'),
                        'symbol': symbol,
                        'action': action,
                        'side': 'BTO' if action == 'BUY' else 'STC',
                        'quantity': quantity,
                        'filled_quantity': filled_quantity,
                        'limit_price': limit_price,
                        'avg_filled_price': avg_filled_price,
                        'order_type': order.get('orderType', 'N/A'),
                        'status': order.get('status', 'N/A'),
                        'fill_status': order.get('status', 'Filled'),
                        'created_time': create_time,
                        'filled_time': filled_time,
                        'asset_type': asset_type,
                        'broker': 'WEBULL',
                        'source': 'webull_history',
                        **option_info
                    })
                
                return formatted_orders
                
            except Exception as e:
                print(f"[API] Error in _get_webull_order_history: {e}")
                import traceback
                traceback.print_exc()
                return []
        
        return await run_async_safely(_blocking_call)
    
    @app.route('/api/webull/orders/<order_id>/cancel', methods=['POST'])
    def cancel_webull_order(order_id):
        """Cancel an open order at Webull"""
        if _bot_instance is None:
            return jsonify({'error': 'Bot not initialized'}), 500
        
        try:
            # Run async call in executor
            future = asyncio.run_coroutine_threadsafe(
                _cancel_webull_order(order_id),
                _bot_instance.loop
            )
            result = future.result(timeout=10)
            
            if result['success']:
                return jsonify({'success': True, 'message': f"Order {order_id} cancelled successfully"})
            else:
                return jsonify({'error': result.get('error', 'Failed to cancel order')}), 500
                
        except Exception as e:
            print(f"[API] Error cancelling order: {e}")
            return jsonify({'error': str(e)}), 500
    
    async def _cancel_webull_order(order_id):
        """Helper to cancel Webull order"""
        if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
            return {'success': False, 'error': 'Webull broker not initialized'}
        
        wb = _bot_instance.broker._client
        if not wb:
            return {'success': False, 'error': 'Webull client not available'}
        
        def _blocking_call():
            try:
                order_details = None
                try:
                    orders = None
                    try:
                        from src.services.webull_data_hub import get_webull_data_hub
                        _hub = get_webull_data_hub()
                        cached_orders = _hub.get_pending_orders(max_age_seconds=10)
                        if cached_orders is not None:
                            orders = cached_orders
                    except Exception:
                        pass
                    if orders is None:
                        orders = wb.get_current_orders()
                    if orders:
                        for order in orders:
                            if order.get('orderId') == order_id:
                                order_details = order
                                break
                except Exception as e:
                    print(f"[API] Warning: Could not fetch order details: {e}")
                
                result = wb.cancel_order(order_id)
                
                try:
                    from gui_app import database as db
                    from datetime import datetime
                    pending_trades = db.get_trades(status='PENDING')
                    for pt in pending_trades:
                        if pt.get('order_id') == order_id:
                            db.update_trade(
                                pt['id'],
                                status='CLOSED',
                                closed_at=datetime.now().isoformat(),
                                close_reason='user_cancelled'
                            )
                            print(f"[CANCEL] ✓ Trade #{pt['id']} ({pt.get('symbol')}) marked CLOSED (user cancelled)")
                            try:
                                from gui_app.database import cancel_lot
                                if cancel_lot(trade_id=pt['id'], reason='USER_CANCELLED'):
                                    print(f"[CANCEL] ✓ Cancelled lot linked to trade #{pt['id']}")
                            except Exception:
                                pass
                            break
                except Exception as db_err:
                    print(f"[CANCEL] Warning: Could not update trade in DB: {db_err}")
                
                # Send Discord notification for canceled order
                if order_details:
                    try:
                        from gui_app.discord_notifier import send_cancel_notification
                        
                        symbol = order_details.get('ticker', {}).get('symbol', 'UNKNOWN')
                        action = order_details.get('action', 'BUY')
                        quantity = int(order_details.get('totalQuantity', 0))
                        limit_price = float(order_details.get('lmtPrice', 0))
                        
                        # Check if option or stock
                        option_id = order_details.get('optionId')
                        if option_id:
                            # Option order - extract option details
                            option_symbol = order_details.get('ticker', {}).get('symbol', symbol)
                            # Try to parse option details from symbol or order data
                            send_cancel_notification(
                                symbol=option_symbol,
                                quantity=quantity,
                                price=limit_price,
                                is_option=True,
                                order_id=order_id
                            )
                        else:
                            # Stock order
                            send_cancel_notification(
                                symbol=symbol,
                                quantity=quantity,
                                price=limit_price,
                                is_option=False,
                                order_id=order_id
                            )
                    except Exception as e:
                        print(f"[NOTIFICATION] Failed to send cancel notification: {e}")
                
                return {'success': True, 'result': result}
            except Exception as e:
                print(f"[API] Error in cancel_order: {e}")
                return {'success': False, 'error': str(e)}
        
        return await run_async_safely(_blocking_call)
    
    @app.route('/api/webull/positions/close', methods=['POST'])
    def close_webull_position():
        """Close a position at Webull immediately."""
        try:
            if _bot_instance is None:
                return jsonify({'success': False, 'error': 'Bot not initialized'}), 500

            data = request.get_json(silent=True) or {}
            symbol = data.get('symbol')
            quantity = data.get('quantity')
            asset_type = (data.get('asset_type') or '').lower()

            # Validate input
            if not symbol or quantity is None:
                return jsonify({'success': False, 'error': 'Symbol and quantity are required'}), 400

            if asset_type not in ('stock', 'option'):
                return jsonify({
                    'success': False,
                    'error': 'Invalid or missing asset_type. Must be "stock" or "option".'
                }), 400

            # Make sure quantity is an integer
            try:
                qty = int(quantity)
            except (TypeError, ValueError):
                return jsonify({'success': False, 'error': f'Invalid quantity: {quantity}'}), 400

            if qty <= 0:
                return jsonify({'success': False, 'error': f'Quantity must be positive, got {qty}'}), 400

            # Call async helper on the bot loop
            future = asyncio.run_coroutine_threadsafe(
                _close_webull_position(symbol, qty, asset_type),
                _bot_instance.loop
            )
            result = future.result(timeout=20)

            if result.get('success'):
                return jsonify({
                    'success': True,
                    'message': f"Position closed: {qty} {symbol}"
                })
            else:
                return jsonify({
                    'success': False,
                    'error': result.get('error', 'Failed to close position')
                }), 500

        except Exception as e:
            # This ensures even unexpected errors return JSON, not HTML
            print(f"[API] Error closing position: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    async def _close_webull_position(symbol: str, quantity: int, asset_type: str, option_id=None, user_limit_price=None):
        """
        Helper to close a position at Webull.
        - Stocks: market SELL (or limit if user_limit_price provided).
        - Options: limit SELL using optionId and user price or small discount to last price.
        For options, requires option_id to match the correct position.
        user_limit_price: If provided, use this as the limit price. None = market/auto-calculated.
        """
        import sys
        print(f"[API] _close_webull_position ENTERED: symbol={symbol}, qty={quantity}, asset={asset_type}", flush=True)
        sys.stdout.flush()
        
        # Ensure we have a broker and client
        if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
            return {'success': False, 'error': 'Broker not initialized'}

        broker = _bot_instance.broker
        wb = getattr(broker, '_client', None) or getattr(broker, 'wb', None)
        print(f"[API] Broker: {broker}, wb client: {wb is not None}", flush=True)

        if wb is None:
            return {'success': False, 'error': 'Webull client not available'}

        def _blocking_call():
            import sys
            print(f"[API] _blocking_call started: symbol={symbol}, asset_type={asset_type}, quantity={quantity}", flush=True)
            sys.stdout.flush()
            try:
                # ---------- STOCK CLOSE: market or limit SELL ----------
                if asset_type == 'stock':
                    print(f"[API] Looking up ticker for stock: {symbol}", flush=True)
                    ticker = None
                    try:
                        from src.services.webull_data_hub import get_webull_data_hub
                        hub = get_webull_data_hub()
                        cached_tid = hub.get_ticker_id(symbol)
                        if cached_tid:
                            ticker = int(cached_tid)
                            print(f"[API] Hub cache hit for ticker {symbol}: {ticker}")
                    except Exception:
                        pass
                    if not ticker:
                        ticker = wb.get_ticker(symbol)
                    print(f"[API] get_ticker({symbol}) returned: {ticker} (type: {type(ticker).__name__})", flush=True)
                    
                    if not ticker:
                        return {'success': False, 'error': f'Symbol {symbol} not found at Webull'}

                    # get_ticker can return int or dict depending on webull version
                    if isinstance(ticker, int):
                        ticker_id = ticker
                    elif isinstance(ticker, dict):
                        ticker_id = ticker.get('tickerId') or ticker.get('ticker_id') or ticker.get('id')
                    elif isinstance(ticker, str) and ticker.isdigit():
                        ticker_id = int(ticker)
                    else:
                        return {'success': False, 'error': f'Unexpected ticker format for {symbol}: {type(ticker).__name__} = {ticker}'}

                    if not ticker_id:
                        return {'success': False, 'error': f'Ticker ID not found for {symbol} (raw: {ticker})'}

                    print(f"[API] Using ticker_id={ticker_id} for {symbol}", flush=True)
                    
                    if user_limit_price:
                        # Limit order - use symbol string (ticker_id causes "Stock symbol is required" error)
                        print(f"[API] Placing LIMIT SELL: {quantity} {symbol} @ ${user_limit_price}", flush=True)
                        result = wb.place_order(
                            stock=symbol,
                            price=float(user_limit_price),
                            action='SELL',
                            orderType='LMT',
                            enforce='GTC',
                            quant=quantity
                        )
                    else:
                        # Market order - use symbol string and DAY enforcement (MKT doesn't support GTC)
                        print(f"[API] Placing MARKET SELL: {quantity} {symbol}", flush=True)
                        result = wb.place_order(
                            stock=symbol,
                            price=0,            # market order
                            action='SELL',
                            orderType='MKT',
                            enforce='DAY',      # Market orders require DAY, not GTC
                            quant=quantity
                        )
                        print(f"[API] Order result: {result}", flush=True)
                    
                    # Check if Webull returned an error
                    if isinstance(result, dict) and result.get('msg'):
                        return {'success': False, 'error': f"Webull error: {result.get('msg')}"}
                    
                    return {'success': True, 'result': result}

                # ---------- OPTION CLOSE: limit SELL using optionId ----------
                elif asset_type == 'option':
                    positions = None
                    try:
                        from src.services.webull_data_hub import get_webull_data_hub
                        hub = get_webull_data_hub()
                        cached_pos = hub.get_positions(max_age_seconds=10)
                        if cached_pos is not None:
                            positions = cached_pos
                    except Exception:
                        pass
                    if positions is None:
                        account = wb.get_account()
                        positions = account.get('positions', []) or []

                    print(f"[DEBUG] Searching for option: {symbol} optionId={option_id}")
                    print(f"[DEBUG] Found {len(positions)} total positions")

                    option_position = None
                    ticker_id = None
                    for p in positions:
                        p_asset = (p.get('assetType') or p.get('assetClass') or '').lower()
                        ticker_data = p.get('ticker', {}) or {}
                        pos_symbol = ticker_data.get('symbol', '')
                        pos_ticker_id = p.get('tickerId')
                        
                        if p_asset == 'option' and pos_ticker_id == option_id and float(p.get('position', 0)) > 0:
                            print(f"[DEBUG] MATCH FOUND! {pos_symbol} optionId={pos_ticker_id}")
                            option_position = p
                            ticker_id = ticker_data.get('tickerId')
                            break

                    if not option_position:
                        return {'success': False, 'error': f'Option position not found for {symbol} (optionId={option_id})'}

                    last_price = float(
                        option_position.get('lastPrice')
                        or option_position.get('price')
                        or option_position.get('avgPrice')
                        or 0
                    )

                    if last_price <= 0:
                        last_price = 0.01

                    if user_limit_price:
                        limit_price = _cboe_round_option_price(float(user_limit_price), is_sell=True)
                        print(f"[DEBUG] Using USER limit price: ${limit_price} (CBOE rounded)")
                    else:
                        limit_price = _cboe_round_option_price(last_price * 0.95, is_sell=True)
                        print(f"[DEBUG] Using AUTO limit price: ${limit_price} (95% of last, CBOE rounded)")

                    print(f"[DEBUG] Closing option {symbol} | optionId={option_id}, qty={quantity}, "
                          f"last={last_price}, limit={limit_price}")

                    result = None
                    
                    # Try DIRECT API call first (same as working selfbot implementation)
                    import requests
                    import uuid
                    import time
                    
                    # Refresh trade token before placing order
                    try:
                        wb.get_trade_token(password=wb._trading_pin)
                        print(f"[DEBUG] Trade token refreshed")
                    except Exception as token_err:
                        print(f"[DEBUG] Could not refresh trade token: {token_err}")
                    
                    try:
                        pending_orders = None
                        try:
                            from src.services.webull_data_hub import get_webull_data_hub
                            hub = get_webull_data_hub()
                            cached_orders = hub.get_pending_orders(max_age_seconds=10)
                            if cached_orders is not None:
                                pending_orders = cached_orders
                        except Exception:
                            pass
                        if pending_orders is None:
                            pending_orders = wb.get_current_orders() or []
                        print(f"[DEBUG] Found {len(pending_orders)} total pending orders")
                        for order in pending_orders:
                            order_ticker_id = order.get('ticker', {}).get('tickerId')
                            order_status = order.get('status', '')
                            print(f"[DEBUG] Order tickerId={order_ticker_id}, status={order_status}")
                            if order_ticker_id == option_id:
                                order_id = order.get('orderId')
                                print(f"[DEBUG] Found pending order {order_id} for optionId={option_id}, cancelling...")
                                try:
                                    wb.cancel_order(order_id)
                                    print(f"[DEBUG] Cancelled pending order {order_id}")
                                    time.sleep(1)  # Wait for cancellation to process
                                except Exception as cancel_err:
                                    print(f"[DEBUG] Cancel failed: {cancel_err}")
                    except Exception as pending_err:
                        print(f"[DEBUG] Could not check pending orders: {pending_err}")
                    
                    # Retry logic for "system is busy" errors
                    max_retries = 3
                    for attempt in range(max_retries):
                        try:
                            headers = wb.build_req_headers(include_trade_token=True, include_time=True)
                            api_payload = {
                                'orderType': 'LMT',
                                'serialId': str(uuid.uuid4()),
                                'timeInForce': 'GTC',
                                'orders': [{'quantity': int(quantity), 'action': 'SELL', 'tickerId': int(option_id), 'tickerType': 'OPTION'}],
                                'lmtPrice': float(limit_price)
                            }
                            print(f"[DEBUG] Attempt {attempt+1}/{max_retries} - Direct API payload: {api_payload}")
                            
                            api_url = wb._urls.place_option_orders(wb._account_id)
                            print(f"[DEBUG] API URL: {api_url}")
                            
                            api_response = requests.post(api_url, json=api_payload, headers=headers, timeout=wb.timeout)
                            print(f"[DEBUG] API Response Status: {api_response.status_code}")
                            
                            if api_response.status_code == 200:
                                result = api_response.json()
                                print(f"[DEBUG] Direct API success: {result}")
                                return {'success': True, 'result': result}
                            else:
                                response_text = api_response.text
                                print(f"[DEBUG] Direct API failed: {api_response.status_code} - {response_text}")
                                
                                # Check if it's a "system is busy" error - retry after delay
                                if 'system is busy' in response_text.lower() and attempt < max_retries - 1:
                                    print(f"[DEBUG] System busy, waiting 2 seconds before retry...")
                                    time.sleep(2)
                                    continue
                                else:
                                    break
                        except Exception as direct_error:
                            print(f"[DEBUG] Direct API exception: {direct_error}")
                            if attempt < max_retries - 1:
                                time.sleep(1)
                                continue
                            break
                    
                    # Fallback: Try MARKET order if limit orders keep failing
                    print(f"[DEBUG] Trying MARKET order as fallback...")
                    try:
                        headers = wb.build_req_headers(include_trade_token=True, include_time=True)
                        market_payload = {
                            'orderType': 'MKT',
                            'serialId': str(uuid.uuid4()),
                            'timeInForce': 'DAY',
                            'orders': [{'quantity': int(quantity), 'action': 'SELL', 'tickerId': int(option_id), 'tickerType': 'OPTION'}],
                        }
                        print(f"[DEBUG] Market order payload: {market_payload}")
                        
                        api_url = wb._urls.place_option_orders(wb._account_id)
                        api_response = requests.post(api_url, json=market_payload, headers=headers, timeout=wb.timeout)
                        print(f"[DEBUG] Market order response: {api_response.status_code} - {api_response.text}")
                        
                        if api_response.status_code == 200:
                            result = api_response.json()
                            print(f"[DEBUG] Market order success: {result}")
                            return {'success': True, 'result': result}
                    except Exception as market_err:
                        print(f"[DEBUG] Market order exception: {market_err}")
                    
                    # Final fallback to library method
                    try:
                        result = wb.place_order_option(
                            optionId=int(option_id),
                            lmtPrice=float(limit_price),
                            stpPrice=None,
                            action='SELL',
                            orderType='LMT',
                            enforce='GTC',
                            quant=int(quantity)
                        )
                        print(f"[DEBUG] place_order_option result: {result}")
                        
                        if result and isinstance(result, dict):
                            if result.get('orderId'):
                                return {'success': True, 'result': result}
                            if result.get('msg'):
                                return {'success': False, 'error': f"Webull error: {result.get('msg')}"}
                        
                        return {'success': True, 'result': result}
                    except Exception as e:
                        print(f"[DEBUG] place_order_option exception: {e}")
                        return {'success': False, 'error': f"Webull API error: The system is busy for this option. Please try closing directly in the Webull app, or wait a few minutes and try again."}

                else:
                    return {'success': False, 'error': f'Unsupported asset_type: {asset_type}'}

            except Exception as e:
                print(f"[API] ERROR in _blocking_call: {e}", flush=True)
                print(f"[API] symbol={symbol}, asset_type={asset_type}, quantity={quantity}", flush=True)
                import traceback
                traceback.print_exc()
                return {'success': False, 'error': str(e)}

        # Run the blocking webull calls in a thread so we don't block the event loop
        return await run_async_safely(_blocking_call)
    
    @app.route('/api/orders/<broker>/<order_id>/cancel', methods=['POST'])
    @login_required
    def api_cancel_order_unified(broker: str, order_id: str) -> Any:
        """
        Unified cancel order endpoint for all brokers.
        Routes to the appropriate broker-specific cancel handler.
        
        Supported brokers: alpaca, webull, robinhood, schwab, ibkr, tastytrade, trading212
        Unsupported (returns error): questrade
        """
        import asyncio
        
        broker_lower = broker.lower().replace('_paper', '').replace('-', '')
        
        print(f"[API] Unified cancel: broker={broker}, order_id={order_id}")
        
        SUPPORTED_CANCEL_BROKERS = {
            'alpaca': 'alpaca',
            'alpacapaper': 'alpaca',
            'webull': 'webull',
            'robinhood': 'robinhood',
            'schwab': 'schwab',
            'ibkr': 'ibkr',
            'tastytrade': 'tastytrade',
            'trading212': 'trading212',
        }
        
        UNSUPPORTED_BROKERS = ['questrade']
        
        if broker_lower in UNSUPPORTED_BROKERS:
            return jsonify({
                'success': False,
                'error': f'{broker.title()} does not support order cancellation via API. Please cancel directly in the broker app.',
                'unsupported': True
            }), 400
        
        resolved_broker = SUPPORTED_CANCEL_BROKERS.get(broker_lower)
        
        if not resolved_broker:
            return jsonify({
                'success': False,
                'error': f'Unknown broker: {broker}. Supported: Alpaca, Webull, Robinhood, Schwab, IBKR, Tastytrade, Trading 212'
            }), 400
        
        try:
            if resolved_broker == 'alpaca':
                if not _bot_instance or not hasattr(_bot_instance, 'paper_broker') or not _bot_instance.paper_broker:
                    return jsonify({'success': False, 'error': 'Alpaca broker not initialized'}), 500
                
                async def _cancel():
                    return await _bot_instance.paper_broker.cancel_order(order_id)
                
                future = asyncio.run_coroutine_threadsafe(_cancel(), _bot_instance.loop)
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('error', 'Failed to cancel')}), 400
            
            elif resolved_broker == 'webull':
                if not _bot_instance or not hasattr(_bot_instance, 'broker') or not _bot_instance.broker:
                    return jsonify({'success': False, 'error': 'Webull broker not initialized'}), 500
                
                future = asyncio.run_coroutine_threadsafe(
                    _cancel_webull_order(order_id),
                    _bot_instance.loop
                )
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('error', 'Failed to cancel')}), 400
            
            elif resolved_broker == 'schwab':
                if not _bot_instance or not hasattr(_bot_instance, 'schwab_broker') or not _bot_instance.schwab_broker:
                    return jsonify({'success': False, 'error': 'Schwab broker not initialized'}), 500
                
                future = asyncio.run_coroutine_threadsafe(
                    _bot_instance.schwab_broker.cancel_order(order_id),
                    _bot_instance.loop
                )
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('message', 'Failed to cancel')}), 400
            
            elif resolved_broker == 'robinhood':
                if not _bot_instance or not hasattr(_bot_instance, 'robinhood_broker') or not _bot_instance.robinhood_broker:
                    return jsonify({'success': False, 'error': 'Robinhood broker not initialized'}), 500
                
                loop = _bot_instance.loop if hasattr(_bot_instance, 'loop') else asyncio.get_event_loop()
                future = asyncio.run_coroutine_threadsafe(
                    _bot_instance.robinhood_broker.cancel_order(order_id, 'stock'),
                    loop
                )
                result = future.result(timeout=15)
                
                if result:
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': 'Failed to cancel order'}), 400
            
            elif resolved_broker == 'ibkr':
                if not _bot_instance or not hasattr(_bot_instance, 'ibkr_broker') or not _bot_instance.ibkr_broker:
                    return jsonify({'success': False, 'error': 'IBKR broker not initialized. Ensure TWS/Gateway is running.'}), 500
                
                future = asyncio.run_coroutine_threadsafe(
                    _bot_instance.ibkr_broker.cancel_order(order_id),
                    _bot_instance.loop
                )
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('msg', 'Failed to cancel')}), 400
            
            elif resolved_broker == 'tastytrade':
                tt_broker = getattr(_bot_instance, 'tastytrade_broker', None) if _bot_instance else None
                if not tt_broker:
                    return jsonify({'success': False, 'error': 'Tastytrade broker not initialized'}), 500
                
                future = asyncio.run_coroutine_threadsafe(
                    tt_broker.cancel_order(order_id),
                    _bot_instance.loop
                )
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('msg', 'Failed to cancel')}), 400
            
            elif resolved_broker == 'trading212':
                t212_broker = getattr(_bot_instance, 'trading212_broker', None) if _bot_instance else None
                if not t212_broker:
                    return jsonify({'success': False, 'error': 'Trading 212 broker not initialized'}), 500
                
                future = asyncio.run_coroutine_threadsafe(
                    t212_broker.cancel_order(order_id),
                    _bot_instance.loop
                )
                result = future.result(timeout=15)
                
                if result.get('success'):
                    return jsonify({'success': True, 'message': f'Order {order_id} cancelled'})
                else:
                    return jsonify({'success': False, 'error': result.get('msg', result.get('error', 'Failed to cancel'))}), 400
            
        except Exception as e:
            print(f"[API] Exception in unified cancel: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
        
        return jsonify({'success': False, 'error': 'Unexpected error'}), 500
    
    @app.route('/api/trades/<trade_id>/force-close-db', methods=['POST'])
    def force_close_trade_db(trade_id):
        """Force close a trade in the DB only — no broker order sent.
        Used for stale positions (manual broker close, ticker rename, etc.)."""
        try:
            from datetime import datetime
            numeric_id = int(trade_id)
            trade = db.get_trade(numeric_id)
            if not trade:
                return jsonify({'success': False, 'error': 'Trade not found'}), 404
            if trade.get('status') not in ('OPEN', 'PENDING'):
                return jsonify({'success': False, 'error': f'Trade is already {trade.get("status")}'}), 400

            symbol = trade.get('symbol', '?')
            broker = trade.get('broker', '?')
            print(f"[API] Force-closing trade #{numeric_id} ({symbol} on {broker}) — DB only, no broker order")

            db.update_trade(
                numeric_id,
                status='CLOSED',
                closed_at=datetime.now().isoformat(),
                close_reason='manual_db_close'
            )

            try:
                from src.risk.position_cache import PositionCache
                cache = PositionCache.get_instance() if hasattr(PositionCache, 'get_instance') else None
                if cache:
                    pos_key = f"{broker}_{symbol}_{trade.get('asset_type', 'stock')}"
                    cache.remove(pos_key)
            except Exception:
                pass

            print(f"[API] ✓ Trade #{numeric_id} ({symbol}) force-closed in DB")
            return jsonify({'success': True, 'message': f'{symbol} cleared from database'})
        except Exception as e:
            print(f"[API] Force-close DB error: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500

    @app.route('/api/trades/<trade_id>/close', methods=['POST'])
    def close_position_by_id(trade_id):
        """Close a position by trade ID (used by Dashboard) - Uses LIVE broker quantity"""
        import concurrent.futures
        import asyncio
        print(f"[API] ========== CLOSE ENDPOINT CALLED FOR TRADE ID {trade_id} ==========")
        try:
            if _bot_instance is None:
                print(f"[API] ERROR: Bot instance is None!")
                return jsonify({'success': False, 'error': 'Bot not initialized'}), 500
            
            data = request.get_json(silent=True) or {}
            requested_quantity = data.get('quantity')
            requested_limit_price = data.get('limit_price')
            
            if requested_limit_price is not None:
                try:
                    requested_limit_price = float(requested_limit_price)
                    if requested_limit_price <= 0:
                        return jsonify({'success': False, 'error': 'Limit price must be positive'}), 400
                except (ValueError, TypeError):
                    return jsonify({'success': False, 'error': 'Invalid limit price format'}), 400
            
            order_type = f"LIMIT @ ${requested_limit_price}" if requested_limit_price else "MARKET"
            print(f"[API] Close request: qty={requested_quantity}, order_type={order_type}")
            
            is_db_trade = False
            try:
                numeric_id = int(trade_id)
                is_db_trade = True
            except (ValueError, TypeError):
                numeric_id = None
            
            trade = None
            if is_db_trade:
                print(f"[API] Bot instance OK, fetching trade {trade_id} from database...")
                trade = db.get_trade_by_id(numeric_id)
                print(f"[API] Trade data: {trade}", flush=True)
            
            if not trade:
                symbol = data.get('symbol', '')
                broker_from_body = data.get('broker', '')
                asset_type_from_body = data.get('asset_type', '')
                if not symbol and not is_db_trade:
                    parts = str(trade_id).split('_', 1)
                    if len(parts) == 2:
                        symbol = parts[1]
                if not symbol:
                    return jsonify({'success': False, 'error': f'Trade {trade_id} not found'}), 404
                trade = {
                    'symbol': symbol,
                    'asset_type': asset_type_from_body or 'stock',
                    'strike': data.get('strike'),
                    'expiry': data.get('expiry'),
                    'call_put': data.get('call_put', ''),
                    'broker': broker_from_body or 'Webull',
                    'entry_price': 0,
                    'option_id': data.get('option_id'),
                }
                print(f"[API] Using request body for live position: {trade}", flush=True)
            
            symbol = trade.get('symbol')
            asset_type = (trade.get('asset_type') or 'stock').lower()
            strike = trade.get('strike')
            expiry = trade.get('expiry')
            call_put = (trade.get('call_put') or '').upper()
            entry_price = float(trade.get('executed_price') or trade.get('entry_price') or 0)
            broker = (trade.get('broker') or 'Webull').upper()
            
            print(f"[API] Extracted: symbol={symbol}, broker={broker}, asset_type={asset_type}", flush=True)
            
            if not symbol:
                return jsonify({'success': False, 'error': 'Invalid trade data - missing symbol'}), 400
            
            print(f"[API] Symbol check passed, routing to {broker}...", flush=True)
            
            # Check event loop health BEFORE any async operations
            if not hasattr(_bot_instance, 'loop') or _bot_instance.loop is None:
                print(f"[API] ERROR: Bot event loop is None!", flush=True)
                return jsonify({
                    'success': False,
                    'error': 'Bot event loop not available. Please restart the bot.'
                }), 500
            
            if _bot_instance.loop.is_closed():
                print(f"[API] ERROR: Bot event loop is CLOSED!", flush=True)
                return jsonify({
                    'success': False,
                    'error': 'Bot event loop is closed. Please restart the bot from the System Tray or restart the workflow.'
                }), 500
            
            print(f"[API] Event loop healthy, proceeding with close...", flush=True)
            
            _gui_pos_key = None
            try:
                from src.risk.exit_lease_manager import get_exit_lease_manager
                import time as _gui_time
                _rm = getattr(_bot_instance, '_risk_manager', None) or getattr(_bot_instance, 'risk_manager', None)
                if _rm and hasattr(_rm, 'cache'):
                    _broker_lower = broker.lower()
                    _symbol_lower = symbol.lower()
                    for _pk in _rm.cache.positions:
                        _pk_lower = _pk.lower()
                        _pk_parts = _pk_lower.split('_')
                        _pk_sym = _pk_parts[-1] if len(_pk_parts) >= 2 else ''
                        _pk_broker = _pk_parts[0] if len(_pk_parts) >= 2 else ''
                        if _pk_sym == _symbol_lower and _broker_lower.startswith(_pk_broker):
                            _gui_pos_key = _pk
                            break
                    if not _gui_pos_key:
                        for _pk in _rm.cache.positions:
                            if _symbol_lower in _pk.lower() and _broker_lower in _pk.lower():
                                _gui_pos_key = _pk
                                break
                if _gui_pos_key:
                    print(f"[API] Matched risk cache key: {_gui_pos_key}")
                    _lease_mgr = get_exit_lease_manager()
                    _lease_ok = _lease_mgr.acquire(_gui_pos_key, 'GUI_MANUAL')
                    if not _lease_ok:
                        _lease_state = _lease_mgr.get_state(_gui_pos_key)
                        print(f"[API] ⚠️ Exit lease busy for {_gui_pos_key}: owner={_lease_state.get('owner')} — proceeding with GUI close anyway")
                    else:
                        print(f"[API] ✓ Acquired exit lease for {_gui_pos_key}")
                    if _rm and hasattr(_rm, 'cache'):
                        _pc = _rm.cache.get(_gui_pos_key)
                        if _pc:
                            _rm.cache.mark_closing(_gui_pos_key)
                    if _rm and hasattr(_rm, '_cancel_broker_bracket_orders_inner'):
                        try:
                            import asyncio
                            _pc = _rm.cache.get(_gui_pos_key)
                            if _pc and (getattr(_pc, 'broker_stop_order_id', None) or getattr(_pc, 'broker_pt_order_id', None)):
                                class _FakePos:
                                    pass
                                _fp = _FakePos()
                                _fp.broker = broker
                                _fp.symbol = symbol
                                _fp.position_key = _gui_pos_key
                                _cancel_fut = asyncio.run_coroutine_threadsafe(
                                    _rm._cancel_broker_bracket_orders(_fp, _pc),
                                    _bot_instance.loop
                                )
                                _cancel_fut.result(timeout=5)
                                print(f"[API] ✓ Cancelled bracket orders for {_gui_pos_key}")
                        except Exception as _ce:
                            print(f"[API] ⚠️ Could not cancel bracket orders: {_ce}")
            except Exception as _lease_err:
                print(f"[API] ⚠️ Lease/bracket cleanup skipped: {_lease_err}")
            
            # ========== ALPACA BROKER CLOSE ==========
            if 'ALPACA' in broker:
                print(f"[API] Routing to Alpaca broker for close (direct SDK)...")
                
                trade_qty = int(trade.get('quantity') or 1)
                quantity_to_close = trade_qty
                if requested_quantity is not None:
                    try:
                        quantity_to_close = int(requested_quantity)
                    except (ValueError, TypeError):
                        pass
                
                alpaca_broker = getattr(_bot_instance, 'paper_broker', None)
                if not alpaca_broker or not hasattr(alpaca_broker, 'trading_client'):
                    return jsonify({'success': False, 'error': 'Alpaca broker not initialized'}), 500
                
                close_symbol = symbol
                if asset_type == 'option':
                    try:
                        from datetime import datetime
                        exp_str = expiry or ''
                        if '/' in exp_str:
                            parts = exp_str.split('/')
                            if len(parts) == 2:
                                month, day = parts[0].zfill(2), parts[1].zfill(2)
                                year = str(datetime.now().year)[2:]
                            else:
                                month, day, year = parts[0].zfill(2), parts[1].zfill(2), parts[2][-2:]
                        elif '-' in exp_str:
                            parts = exp_str.split('-')
                            year, month, day = parts[0][-2:], parts[1].zfill(2), parts[2].zfill(2)
                        else:
                            return jsonify({'success': False, 'error': f'Could not parse expiry: {expiry}'}), 400
                        
                        strike_val = float(strike or 0)
                        strike_occ = str(int(strike_val * 1000)).zfill(8)
                        close_symbol = f"{symbol}{year}{month}{day}{call_put[0]}{strike_occ}"
                        print(f"[CLOSE] Alpaca OCC symbol: {close_symbol}")
                    except Exception as e:
                        return jsonify({'success': False, 'error': f'Alpaca close error: {str(e)}'}), 500
                
                def _alpaca_close_direct():
                    tc = alpaca_broker.trading_client
                    try:
                        position = tc.get_open_position(close_symbol)
                    except Exception:
                        return {'success': False, 'error': f'No open position found for {close_symbol}'}
                    if not position:
                        return {'success': False, 'error': f'No position found for {close_symbol}'}
                    
                    position_qty = float(position.qty)
                    is_short = position_qty < 0
                    abs_qty = abs(int(position_qty))
                    qty = quantity_to_close if quantity_to_close else abs_qty
                    
                    if qty == abs_qty and requested_limit_price is None:
                        result = tc.close_position(close_symbol)
                        if result:
                            return {'success': True, 'fill_price': 0, 'message': f'Closed {qty} {close_symbol}'}
                    else:
                        from alpaca.trading.requests import LimitOrderRequest, MarketOrderRequest
                        from alpaca.trading.enums import OrderSide, TimeInForce
                        side = OrderSide.BUY if is_short else OrderSide.SELL
                        import re
                        is_opt = hasattr(position, 'asset_class') and 'option' in str(getattr(position, 'asset_class', '')).lower()
                        if not is_opt:
                            is_opt = bool(re.match(r'^[A-Z]{1,6}\d{6}[CP]\d{8}$', close_symbol))
                        tif = TimeInForce.DAY if is_opt else TimeInForce.GTC
                        if requested_limit_price:
                            order_data = LimitOrderRequest(symbol=close_symbol, qty=qty, side=side, time_in_force=tif, limit_price=requested_limit_price)
                        else:
                            order_data = MarketOrderRequest(symbol=close_symbol, qty=qty, side=side, time_in_force=TimeInForce.DAY)
                        result = tc.submit_order(order_data)
                        if result:
                            return {'success': True, 'fill_price': 0, 'order_id': str(result.id) if hasattr(result, 'id') else None}
                    return {'success': False, 'error': 'Alpaca order submission failed'}
                
                try:
                    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                        result = executor.submit(_alpaca_close_direct).result(timeout=10)
                    
                    if result.get('success'):
                        if is_db_trade:
                            db.close_trade(numeric_id, result.get('fill_price', 0) or requested_limit_price or 0, 'manual_close')
                        return jsonify({'success': True, 'message': f"Position closed: {quantity_to_close} {close_symbol} @ {order_type}"})
                    else:
                        return jsonify({'success': False, 'error': result.get('error', 'Alpaca close failed')}), 500
                except Exception as e:
                    print(f"[CLOSE] Alpaca close error: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': f'Alpaca close error: {str(e)}'}), 500
            
            # ========== ROBINHOOD BROKER CLOSE ==========
            if 'ROBINHOOD' in broker:
                print(f"[API] Routing to Robinhood broker for close (direct SDK)...")
                
                rh_broker = getattr(_bot_instance, 'robinhood_broker', None)
                if not rh_broker:
                    return jsonify({'success': False, 'error': 'Robinhood broker not initialized'}), 500
                
                trade_qty = int(trade.get('quantity') or 1)
                quantity_to_close = trade_qty
                if requested_quantity is not None:
                    try:
                        quantity_to_close = int(requested_quantity)
                    except (ValueError, TypeError):
                        pass
                
                def _rh_close_direct():
                    import robin_stocks.robinhood as rh
                    extended_hours = rh_broker._get_extended_hours_enabled() if hasattr(rh_broker, '_get_extended_hours_enabled') else False
                    if asset_type == 'option':
                        expiry_date = rh_broker._normalize_expiry(expiry) if hasattr(rh_broker, '_normalize_expiry') else expiry
                        opt_type = 'call' if str(call_put).upper().startswith('C') else 'put'
                        price = requested_limit_price
                        if not price or price <= 0:
                            price = 0.01
                        return rh.orders.order_sell_option_limit(
                            positionEffect='close', creditOrDebit='credit',
                            price=price, symbol=symbol, quantity=quantity_to_close,
                            expirationDate=expiry_date, strike=float(strike or 0),
                            optionType=opt_type, timeInForce='gtc'
                        )
                    else:
                        if requested_limit_price:
                            return rh.orders.order_sell_limit(symbol=symbol, quantity=quantity_to_close, limitPrice=requested_limit_price, timeInForce='gtc', extendedHours=extended_hours)
                        else:
                            return rh.orders.order_sell_market(symbol=symbol, quantity=quantity_to_close, timeInForce='gtc', extendedHours=extended_hours)
                
                try:
                    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                        future = executor.submit(_rh_close_direct)
                        raw_result = future.result(timeout=15)
                    
                    success = False
                    fill_price = 0
                    error_msg = ''
                    if hasattr(raw_result, 'success'):
                        success = raw_result.success
                        fill_price = getattr(raw_result, 'fill_price', 0) or 0
                        error_msg = getattr(raw_result, 'message', '') or ''
                    elif isinstance(raw_result, dict):
                        if raw_result.get('id') or raw_result.get('order_id'):
                            success = True
                        elif raw_result.get('detail'):
                            error_msg = raw_result['detail']
                        else:
                            success = True
                    
                    if success:
                        if is_db_trade:
                            db.close_trade(numeric_id, fill_price or requested_limit_price or 0, 'manual_close')
                        return jsonify({'success': True, 'message': f"Position closed: {quantity_to_close} {symbol} @ {order_type}"})
                    else:
                        return jsonify({'success': False, 'error': f'Robinhood close failed: {error_msg or "Unknown error"}'}), 500
                except Exception as e:
                    print(f"[CLOSE] Robinhood close error: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': f'Robinhood close error: {str(e)}'}), 500
            
            # ========== SCHWAB BROKER CLOSE ==========
            if 'SCHWAB' in broker:
                print(f"[API] Routing to Schwab broker for close (isolated loop)...")
                schwab_broker = None
                if hasattr(_bot_instance, 'schwab_broker') and _bot_instance.schwab_broker:
                    schwab_broker = _bot_instance.schwab_broker
                elif hasattr(_bot_instance, 'broker_manager') and hasattr(_bot_instance.broker_manager, 'schwab_broker'):
                    schwab_broker = _bot_instance.broker_manager.schwab_broker
                
                if not schwab_broker or not schwab_broker.is_authenticated():
                    return jsonify({'success': False, 'error': 'Schwab broker not connected or not authenticated'}), 500
                
                trade_qty = int(trade.get('quantity') or 1)
                quantity_to_close = trade_qty
                if requested_quantity is not None:
                    try:
                        quantity_to_close = int(requested_quantity)
                    except (ValueError, TypeError):
                        pass
                
                def _schwab_close_direct():
                    loop = asyncio.new_event_loop()
                    try:
                        if asset_type == 'option':
                            return loop.run_until_complete(schwab_broker.place_option_order(symbol, strike, expiry, call_put, 'STC', quantity_to_close, requested_limit_price))
                        else:
                            return loop.run_until_complete(schwab_broker.place_stock_order(symbol, 'STC', quantity_to_close, requested_limit_price))
                    finally:
                        loop.close()
                
                try:
                    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                        result = executor.submit(_schwab_close_direct).result(timeout=15)
                    
                    if result and result.success:
                        if is_db_trade:
                            db.close_trade(numeric_id, result.price or requested_limit_price or 0, 'manual_close')
                        return jsonify({'success': True, 'message': f"Schwab position closed: {quantity_to_close} {symbol} @ {order_type}"})
                    else:
                        return jsonify({'success': False, 'error': f'Schwab close failed: {result.message if result else "Unknown error"}'}), 500
                except Exception as e:
                    print(f"[CLOSE] Schwab close error: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': f'Schwab close error: {str(e)}'}), 500
            
            # ========== IBKR BROKER CLOSE ==========
            if 'IBKR' in broker or 'INTERACTIVE' in broker:
                print(f"[API] Routing to IBKR broker for close...")
                ibkr_broker = None
                if hasattr(_bot_instance, 'ibkr_broker') and _bot_instance.ibkr_broker:
                    ibkr_broker = _bot_instance.ibkr_broker
                elif hasattr(_bot_instance, 'broker_manager') and hasattr(_bot_instance.broker_manager, 'ibkr_broker'):
                    ibkr_broker = _bot_instance.broker_manager.ibkr_broker
                
                if not ibkr_broker:
                    return jsonify({'success': False, 'error': 'IBKR broker not connected'}), 500
                
                trade_qty = int(trade.get('quantity') or 1)
                quantity_to_close = trade_qty
                if requested_quantity is not None:
                    try:
                        quantity_to_close = int(requested_quantity)
                    except (ValueError, TypeError):
                        pass
                
                try:
                    if asset_type == 'option':
                        future = asyncio.run_coroutine_threadsafe(
                            ibkr_broker.place_option_order(symbol, strike, expiry, call_put, 'STC', quantity_to_close, requested_limit_price),
                            _bot_instance.loop
                        )
                    else:
                        future = asyncio.run_coroutine_threadsafe(
                            ibkr_broker.place_stock_order(symbol, 'STC', quantity_to_close, requested_limit_price),
                            _bot_instance.loop
                        )
                    result = future.result(timeout=15)
                    
                    if result and result.success:
                        if is_db_trade:
                            db.close_trade(numeric_id, result.price or requested_limit_price or 0, 'manual_close')
                        return jsonify({'success': True, 'message': f"IBKR position closed: {quantity_to_close} {symbol} @ {order_type}"})
                    else:
                        return jsonify({'success': False, 'error': f'IBKR close failed: {result.message if result else "Unknown error"}'}), 500
                except Exception as e:
                    print(f"[CLOSE] IBKR close error: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': f'IBKR close error: {str(e)}'}), 500
            
            # ========== TASTYTRADE BROKER CLOSE ==========
            if 'TASTYTRADE' in broker or 'TASTY' in broker:
                print(f"[API] Routing to Tastytrade broker for close (isolated loop)...")
                tt_broker = None
                if hasattr(_bot_instance, 'tastytrade_broker') and _bot_instance.tastytrade_broker:
                    tt_broker = _bot_instance.tastytrade_broker
                elif hasattr(_bot_instance, 'broker_manager') and hasattr(_bot_instance.broker_manager, 'tastytrade_broker'):
                    tt_broker = _bot_instance.broker_manager.tastytrade_broker
                
                if not tt_broker:
                    return jsonify({'success': False, 'error': 'Tastytrade broker not connected'}), 500
                
                trade_qty = int(trade.get('quantity') or 1)
                quantity_to_close = trade_qty
                if requested_quantity is not None:
                    try:
                        quantity_to_close = int(requested_quantity)
                    except (ValueError, TypeError):
                        pass
                
                try:
                    if asset_type == 'option':
                        future = asyncio.run_coroutine_threadsafe(
                            tt_broker.place_option_order(symbol, strike, expiry, call_put, 'STC', quantity_to_close, requested_limit_price),
                            _bot_instance.loop
                        )
                    else:
                        future = asyncio.run_coroutine_threadsafe(
                            tt_broker.place_stock_order(symbol, 'STC', quantity_to_close, requested_limit_price),
                            _bot_instance.loop
                        )
                    result = future.result(timeout=15)
                    
                    if result and result.success:
                        if is_db_trade:
                            db.close_trade(numeric_id, result.price or requested_limit_price or 0, 'manual_close')
                        return jsonify({'success': True, 'message': f"Tastytrade position closed: {quantity_to_close} {symbol} @ {order_type}"})
                    else:
                        return jsonify({'success': False, 'error': f'Tastytrade close failed: {result.message if result else "Unknown error"}'}), 500
                except Exception as e:
                    print(f"[CLOSE] Tastytrade close error: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': f'Tastytrade close error: {str(e)}'}), 500
            
            # ========== WEBULL BROKER CLOSE (direct SDK - zero event loop) ==========
            print(f"[API] Entering Webull close section for {symbol} (direct SDK)", flush=True)
            
            option_id = trade.get('option_id')
            print(f"[API] option_id from trade: {option_id}, asset_type: {asset_type}", flush=True)
            
            wb_broker = getattr(_bot_instance, 'broker', None)
            if not wb_broker:
                return jsonify({'success': False, 'error': 'Webull broker not initialized'}), 500
            wb = getattr(wb_broker, '_client', None) or getattr(wb_broker, 'wb', None)
            if not wb:
                return jsonify({'success': False, 'error': 'Webull client not available'}), 500
            
            def _webull_close_all_in_one():
                """Single synchronous function: lookup + validate + check pending + close"""
                import requests as req_lib
                import uuid
                import time as time_mod
                
                _option_id = option_id
                
                if asset_type == 'option' and not _option_id:
                    print(f"[WEBULL-CLOSE] Looking up option_id from live positions...", flush=True)
                    positions = None
                    try:
                        from src.services.webull_data_hub import get_webull_data_hub
                        hub = get_webull_data_hub()
                        cached_pos = hub.get_positions(max_age_seconds=10)
                        if cached_pos is not None:
                            positions = cached_pos
                            print(f"[WEBULL-CLOSE] Using hub-cached positions ({len(positions)} items)")
                    except Exception:
                        pass
                    if positions is None:
                        try:
                            account = wb.get_account()
                            positions = (account or {}).get('positions', []) or []
                        except Exception as e:
                            return {'success': False, 'error': f'Failed to fetch positions: {e}'}
                    
                    db_strike = float(strike) if strike else 0
                    db_call_put = str(call_put).upper()[0] if call_put else ''
                    
                    for p in positions:
                        p_asset = (p.get('assetType') or '').lower()
                        if p_asset != 'option':
                            continue
                        ticker_data = p.get('ticker', {}) or {}
                        pos_symbol = ticker_data.get('symbol', '')
                        if pos_symbol != symbol:
                            continue
                        pos_strike = float(ticker_data.get('strikePrice', 0) or 0)
                        pos_direction = str(ticker_data.get('direction', '') or '').upper()
                        if pos_direction in ['CALL', 'C']:
                            pos_direction = 'C'
                        elif pos_direction in ['PUT', 'P']:
                            pos_direction = 'P'
                        
                        if abs(pos_strike - db_strike) < 0.01 and pos_direction == db_call_put:
                            _option_id = p.get('tickerId')
                            print(f"[WEBULL-CLOSE] Found option_id={_option_id}", flush=True)
                            break
                    
                    if not _option_id:
                        return {'success': False, 'error': f'Could not find option_id for {symbol} {strike}{call_put}'}
                
                positions = None
                try:
                    from src.services.webull_data_hub import get_webull_data_hub
                    hub = get_webull_data_hub()
                    cached_pos = hub.get_positions(max_age_seconds=10)
                    if cached_pos is not None:
                        positions = cached_pos
                except Exception:
                    pass
                if positions is None:
                    try:
                        account = wb.get_account()
                        positions = (account or {}).get('positions', []) or []
                    except Exception as e:
                        return {'success': False, 'error': f'Failed to fetch positions: {e}'}
                
                live_quantity = None
                for p in positions:
                    if asset_type == 'option':
                        p_asset = (p.get('assetType') or '').lower()
                        pos_ticker_id = p.get('tickerId')
                        if p_asset == 'option' and str(pos_ticker_id) == str(_option_id) and float(p.get('position', 0)) > 0:
                            live_quantity = int(float(p.get('position', 0)))
                            break
                    else:
                        ticker_data = p.get('ticker', {}) or {}
                        if ticker_data.get('symbol') == symbol and (p.get('assetType') or '').lower() == 'stock':
                            live_quantity = int(float(p.get('position', 0)))
                            break
                
                if live_quantity is None or live_quantity <= 0:
                    return {'success': False, 'error': f'No live position found for {symbol}. Position may already be closed.'}
                
                qty_to_close = live_quantity
                if requested_quantity is not None:
                    try:
                        rq = int(requested_quantity)
                        if rq <= 0:
                            return {'success': False, 'error': 'Quantity must be positive'}
                        if rq > live_quantity:
                            return {'success': False, 'error': f'Cannot close {rq}. Only {live_quantity} available.'}
                        qty_to_close = rq
                    except (ValueError, TypeError):
                        return {'success': False, 'error': 'Invalid quantity format'}
                
                pending = None
                try:
                    from src.services.webull_data_hub import get_webull_data_hub
                    hub = get_webull_data_hub()
                    cached_orders = hub.get_pending_orders(max_age_seconds=10)
                    if cached_orders is not None:
                        pending = cached_orders
                except Exception:
                    pass
                if pending is None:
                    pending = []
                try:
                    if not pending:
                        pending = wb.get_current_orders() or []
                    for order in pending:
                        order_action = (order.get('action') or '').upper()
                        order_status = (order.get('status') or '').upper()
                        if order_action != 'SELL' or order_status not in ['SUBMITTED', 'WORKING', 'PENDING', 'ACCEPTED', 'MANUALFILLED']:
                            continue
                        order_ticker_id = order.get('ticker', {}).get('tickerId')
                        if asset_type == 'option' and str(order_ticker_id) == str(_option_id):
                            oid = order.get('orderId', 'Unknown')
                            return {'success': False, 'error': f'Pending SELL order already exists (ID: {oid}). Cancel it first in Pending Orders tab.'}
                        elif asset_type == 'stock':
                            order_sym = order.get('ticker', {}).get('symbol', '')
                            if order_sym == symbol:
                                oid = order.get('orderId', 'Unknown')
                                return {'success': False, 'error': f'Pending SELL order already exists (ID: {oid}). Cancel it first in Pending Orders tab.'}
                except Exception as pe:
                    print(f"[WEBULL-CLOSE] Pending order check failed (non-fatal): {pe}", flush=True)
                
                # Step 4: Execute close
                print(f"[WEBULL-CLOSE] Closing {qty_to_close} {symbol} (asset={asset_type})", flush=True)
                
                if asset_type == 'stock':
                    if requested_limit_price:
                        result = wb.place_order(stock=symbol, price=float(requested_limit_price), action='SELL', orderType='LMT', enforce='GTC', quant=qty_to_close)
                    else:
                        result = wb.place_order(stock=symbol, price=0, action='SELL', orderType='MKT', enforce='DAY', quant=qty_to_close)
                    if isinstance(result, dict) and result.get('msg'):
                        return {'success': False, 'error': f"Webull error: {result.get('msg')}"}
                    return {'success': True, 'result': result, 'quantity': qty_to_close}
                
                elif asset_type == 'option':
                    try:
                        wb.get_trade_token(password=wb._trading_pin)
                    except Exception:
                        pass
                    
                    option_position = None
                    for p in positions:
                        if p.get('tickerId') == _option_id or str(p.get('tickerId')) == str(_option_id):
                            option_position = p
                            break
                    
                    if requested_limit_price:
                        limit_price = float(requested_limit_price)
                    else:
                        hub_bid = 0
                        hub_ask = 0
                        try:
                            from src.services.webull_data_hub import get_webull_data_hub
                            _wb_hub = get_webull_data_hub()
                            if _wb_hub.is_streaming() and _option_id:
                                _hub_data = _wb_hub.get_quote_detailed(str(_option_id))
                                if _hub_data:
                                    hub_bid = float(_hub_data.get('bid', 0) or 0)
                                    hub_ask = float(_hub_data.get('ask', 0) or 0)
                        except Exception:
                            pass

                        if hub_bid > 0 and hub_ask > 0:
                            limit_price = _cboe_round_option_price(hub_bid, is_sell=True)
                            print(f"[WEBULL-CLOSE] Using streaming hub bid: ${hub_bid:.2f} → ${limit_price:.2f} (CBOE rounded)", flush=True)
                        else:
                            last_price = float(
                                (option_position or {}).get('lastPrice') or
                                (option_position or {}).get('price') or
                                (option_position or {}).get('avgPrice') or 0
                            )
                            limit_price = _cboe_round_option_price(last_price * 0.95, is_sell=True) if last_price > 0 else 0.05
                    
                    max_retries = 3
                    for attempt in range(max_retries):
                        try:
                            headers = wb.build_req_headers(include_trade_token=True, include_time=True)
                            api_payload = {
                                'orderType': 'LMT',
                                'serialId': str(uuid.uuid4()),
                                'timeInForce': 'GTC',
                                'orders': [{'quantity': int(qty_to_close), 'action': 'SELL', 'tickerId': int(_option_id), 'tickerType': 'OPTION'}],
                                'lmtPrice': float(limit_price)
                            }
                            api_url = wb._urls.place_option_orders(wb._account_id)
                            api_response = req_lib.post(api_url, json=api_payload, headers=headers, timeout=wb.timeout)
                            
                            if api_response.status_code == 200:
                                return {'success': True, 'result': api_response.json(), 'quantity': qty_to_close}
                            elif 'system is busy' in api_response.text.lower() and attempt < max_retries - 1:
                                time_mod.sleep(2)
                                continue
                            else:
                                break
                        except Exception as e:
                            if attempt < max_retries - 1:
                                time_mod.sleep(1)
                                continue
                            break
                    
                    try:
                        result = wb.place_order_option(optionId=int(_option_id), lmtPrice=float(limit_price), stpPrice=None, action='SELL', orderType='LMT', enforce='GTC', quant=int(qty_to_close))
                        if result and isinstance(result, dict) and result.get('msg'):
                            return {'success': False, 'error': f"Webull error: {result.get('msg')}"}
                        return {'success': True, 'result': result, 'quantity': qty_to_close}
                    except Exception as e:
                        return {'success': False, 'error': f"Webull API error: {str(e)}"}
                
                return {'success': False, 'error': f'Unsupported asset_type: {asset_type}'}
            
            try:
                with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                    result = executor.submit(_webull_close_all_in_one).result(timeout=20)
                print(f"[API] Webull close result: {result}", flush=True)
            except Exception as close_err:
                print(f"[API] ERROR in Webull close: {close_err}", flush=True)
                import traceback
                traceback.print_exc()
                return jsonify({'success': False, 'error': f'Close failed: {str(close_err)}'}), 500
            
            if result.get('success'):
                qty_closed = result.get('quantity', requested_quantity or 0)
                if order_type == 'MARKET':
                    message = f"Position closed: {qty_closed} {symbol} @ MARKET"
                else:
                    message = f"Limit order submitted: SELL {qty_closed} {symbol} @ ${requested_limit_price}\n\nOrder is pending fill. Check 'Pending Orders' tab for status."
                return jsonify({'success': True, 'message': message})
            else:
                error = result.get('error', 'Failed to close position')
                status_code = 409 if 'pending' in error.lower() else (404 if 'not found' in error.lower() else 500)
                return jsonify({'success': False, 'error': error}), status_code
        
        except Exception as e:
            print(f"[API] Error closing position by ID: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    # Real-time pricing and risk management endpoints
    @app.route('/api/refresh_prices', methods=['POST'])
    def api_refresh_prices():
        """Refresh current prices for all open positions and update database"""
        if _bot_instance is None or not hasattr(_bot_instance, 'loop'):
            return jsonify({'success': False, 'error': 'Bot not initialized'})
        
        try:
            # Get all open trades
            open_trades = db.get_trades(status='OPEN', limit=100)
            
            if not open_trades:
                return jsonify({'success': True, 'updated': 0, 'message': 'No open positions'})
            
            updated_count = 0
            
            # Prepare positions for price fetch
            positions = []
            for trade in open_trades:
                positions.append({
                    'trade_id': trade.get('id'),
                    'symbol': trade.get('symbol'),
                    'asset_type': trade.get('asset_type', 'option'),
                    'option_id': trade.get('option_id'),
                    'strike': trade.get('strike'),
                    'expiry': trade.get('expiry'),
                    'call_put': trade.get('call_put'),
                    'entry_price': trade.get('executed_price', 0) or trade.get('intended_price', 0),
                    'quantity': trade.get('quantity', 1),
                    'broker': trade.get('broker', 'Webull')
                })
            
            # Fetch real-time prices
            future = asyncio.run_coroutine_threadsafe(
                _get_realtime_prices(positions),
                _bot_instance.loop
            )
            result = future.result(timeout=30)
            prices = result.get('prices', {})
            
            # Update database with new prices
            for trade in open_trades:
                trade_id = str(trade.get('id'))
                if trade_id in prices:
                    price_data = prices[trade_id]
                    # Use mid price, fallback to last
                    current_price = price_data.get('mid') or price_data.get('last') or price_data.get('bid') or 0
                    
                    if current_price > 0:
                        entry_price = float(trade.get('executed_price', 0) or trade.get('intended_price', 0) or 0)
                        quantity = float(trade.get('quantity', 1) or 1)
                        
                        # Calculate P&L
                        _is_option = (trade.get('asset_type') or '').lower() in ('option', 'options')
                        _multiplier = 100 if _is_option else 1
                        pnl = (current_price - entry_price) * quantity * _multiplier
                        pnl_percent = ((current_price - entry_price) / entry_price * 100) if entry_price > 0 else 0
                        
                        # Update trade in database
                        db.update_trade_price(trade.get('id'), current_price, pnl, pnl_percent)
                        updated_count += 1
            
            print(f"[API] Refreshed prices for {updated_count}/{len(open_trades)} positions")
            return jsonify({
                'success': True,
                'updated': updated_count,
                'total': len(open_trades)
            })
            
        except Exception as e:
            print(f"[API] Error refreshing prices: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/trades/realtime-prices', methods=['POST'])
    def get_realtime_prices():
        """Get real-time bid/ask/mid prices for multiple positions"""
        if _bot_instance is None or not hasattr(_bot_instance, 'loop'):
            return jsonify({'prices': {}})
        
        try:
            data = request.json
            if not data:
                return jsonify({'prices': {}})
                
            positions = data.get('positions', [])
            
            if not positions:
                return jsonify({'prices': {}})
            
            # Run async call in executor
            future = asyncio.run_coroutine_threadsafe(
                _get_realtime_prices(positions),
                _bot_instance.loop
            )
            result = future.result(timeout=15)
            return jsonify(result)
                
        except Exception as e:
            print(f"[API] Error fetching real-time prices: {e}")
            return jsonify({'prices': {}})
    
    async def _get_realtime_prices(positions):
        """Helper to fetch real-time prices from Webull or fallback sources"""
        
        def _get_yfinance_quote(symbol: str) -> dict:
            """Fallback to yfinance for stock quotes (safe import)"""
            try:
                import yfinance as yf
            except ImportError:
                return None
            try:
                ticker = yf.Ticker(symbol)
                info = ticker.info
                if info:
                    bid = float(info.get('bid', 0) or 0)
                    ask = float(info.get('ask', 0) or 0)
                    last = float(info.get('regularMarketPrice', 0) or info.get('previousClose', 0) or 0)
                    mid = (bid + ask) / 2 if bid and ask else last
                    return {'bid': bid, 'ask': ask, 'mid': mid, 'last': last}
            except Exception as e:
                print(f"[API] yfinance fallback error for {symbol}: {e}")
            return None
        
        wb = None
        if hasattr(_bot_instance, 'broker') and _bot_instance.broker:
            wb = _bot_instance.broker._client
        
        def _blocking_call():
            prices = {}
            for pos in positions:
                try:
                    trade_id = pos['trade_id']
                    symbol = pos['symbol']
                    asset_type = pos['asset_type']
                    
                    if asset_type == 'option':
                        # Get option quote
                        option_id = pos.get('option_id')
                        strike = pos.get('strike')
                        expiry = pos.get('expiry')
                        call_put = pos.get('call_put')
                        
                        # If option_id not provided, search for it
                        if not option_id and strike and expiry and call_put:
                            # Get option chain
                            option_data = wb.get_options(symbol, count=-1)
                            if option_data and 'data' in option_data:
                                for date_obj in option_data['data']:
                                    if date_obj.get('expireDate') == expiry:
                                        call_list = date_obj.get('call', []) if call_put.upper() == 'C' else []
                                        put_list = date_obj.get('put', []) if call_put.upper() == 'P' else []
                                        
                                        for opt in call_list + put_list:
                                            if opt.get('strikePrice') == strike:
                                                option_id = opt.get('tickerId')
                                                break
                        
                        if option_id:
                            hub_hit = False
                            try:
                                from src.services.webull_data_hub import get_webull_data_hub
                                import time as _hub_time
                                _hub = get_webull_data_hub()
                                _hq = _hub.get_quote(str(option_id))
                                if _hq and _hq.timestamp and (_hub_time.time() - _hq.timestamp) < 15:
                                    if _hq.bid > 0 or _hq.ask > 0 or _hq.last > 0:
                                        prices[str(trade_id)] = {
                                            'bid': _hq.bid,
                                            'ask': _hq.ask,
                                            'mid': (_hq.bid + _hq.ask) / 2 if _hq.bid > 0 and _hq.ask > 0 else _hq.last,
                                            'last': _hq.last
                                        }
                                        hub_hit = True
                            except Exception:
                                pass
                            if not hub_hit:
                                quote = wb.get_option_quote(optionId=option_id)
                                if quote:
                                    prices[str(trade_id)] = {
                                        'bid': float(quote.get('bidPrice', 0) or 0),
                                        'ask': float(quote.get('askPrice', 0) or 0),
                                        'mid': float((float(quote.get('bidPrice', 0) or 0) + float(quote.get('askPrice', 0) or 0)) / 2),
                                        'last': float(quote.get('lastPrice', 0) or quote.get('close', 0) or 0)
                                    }
                    else:
                        quote_data = None
                        _pos_broker = (pos.get('broker') or '').upper()

                        if 'SCHWAB' in _pos_broker:
                            try:
                                from src.services.schwab_data_hub import get_schwab_data_hub
                                _sh = get_schwab_data_hub()
                                _shq = _sh.get_quote_price(symbol)
                                if _shq and _shq > 0:
                                    quote_data = {'bid': 0, 'ask': 0, 'mid': _shq, 'last': _shq}
                                if not quote_data:
                                    _sh_pos = _sh.get_positions(detailed=True)
                                    if _sh_pos:
                                        for _sp in _sh_pos:
                                            if (_sp.get('symbol') or '').upper() == symbol.upper() and _sp.get('current_price', 0) > 0:
                                                _cp = float(_sp['current_price'])
                                                quote_data = {'bid': 0, 'ask': 0, 'mid': _cp, 'last': _cp}
                                                break
                            except Exception:
                                pass

                        if not quote_data and 'IBKR' in _pos_broker:
                            try:
                                from src.services.ibkr_data_hub import get_ibkr_data_hub
                                _ih = get_ibkr_data_hub()
                                _ihq = _ih.get_quote(symbol)
                                if _ihq and getattr(_ihq, 'last', 0) > 0:
                                    quote_data = {'bid': getattr(_ihq, 'bid', 0), 'ask': getattr(_ihq, 'ask', 0), 'mid': getattr(_ihq, 'last', 0), 'last': getattr(_ihq, 'last', 0)}
                            except Exception:
                                pass

                        if not quote_data and 'TASTYTRADE' in _pos_broker:
                            try:
                                from src.services.tastytrade_data_hub import get_tastytrade_data_hub
                                _th = get_tastytrade_data_hub()
                                _thq = _th.get_quote(symbol)
                                if _thq and getattr(_thq, 'last', 0) > 0:
                                    quote_data = {'bid': getattr(_thq, 'bid', 0), 'ask': getattr(_thq, 'ask', 0), 'mid': getattr(_thq, 'last', 0), 'last': getattr(_thq, 'last', 0)}
                            except Exception:
                                pass

                        if not quote_data:
                            try:
                                from src.services.webull_data_hub import get_webull_data_hub
                                import time as _hub_time
                                _hub = get_webull_data_hub()
                                _hq = _hub.get_quote(symbol)
                                if _hq and _hq.timestamp and (_hub_time.time() - _hq.timestamp) < 15:
                                    if _hq.last > 0 or (_hq.bid > 0 and _hq.ask > 0):
                                        mid = (_hq.bid + _hq.ask) / 2 if _hq.bid > 0 and _hq.ask > 0 else _hq.last
                                        quote_data = {'bid': _hq.bid, 'ask': _hq.ask, 'mid': mid, 'last': _hq.last}
                            except Exception:
                                pass
                        if not quote_data and wb:
                            try:
                                ticker_id = None
                                try:
                                    from src.services.webull_data_hub import get_webull_data_hub
                                    _hub = get_webull_data_hub()
                                    cached_tid = _hub.get_ticker_id(symbol)
                                    if cached_tid:
                                        ticker_id = int(cached_tid)
                                except Exception:
                                    pass
                                if not ticker_id:
                                    ticker_id = wb.get_ticker(symbol)
                                if ticker_id:
                                    quote = wb.get_quote(ticker_id)
                                    if quote:
                                        bid = float(quote.get('bidPrice', 0) or 0)
                                        ask = float(quote.get('askPrice', 0) or 0)
                                        last = float(quote.get('lastPrice', 0) or quote.get('close', 0) or 0)
                                        if last > 0 or (bid > 0 and ask > 0):
                                            mid = (bid + ask) / 2 if bid and ask else last
                                            quote_data = {'bid': bid, 'ask': ask, 'mid': mid, 'last': last}
                                            print(f"[API] Webull quote for {symbol}: last=${last:.2f}")
                            except Exception as e:
                                print(f"[API] Webull quote error for {symbol}: {e}")
                        
                        if not quote_data and 'SCHWAB' in _pos_broker:
                            try:
                                _schwab_b = None
                                if hasattr(_bot_instance, 'schwab_broker') and _bot_instance.schwab_broker:
                                    _schwab_b = _bot_instance.schwab_broker
                                if _schwab_b and _schwab_b.is_authenticated():
                                    import asyncio as _sq_aio
                                    _sq_future = _sq_aio.run_coroutine_threadsafe(
                                        _schwab_b.get_quote(symbol), _bot_instance.loop)
                                    _sq_price = _sq_future.result(timeout=10)
                                    if _sq_price and _sq_price > 0:
                                        quote_data = {'bid': 0, 'ask': 0, 'mid': _sq_price, 'last': _sq_price}
                                        print(f"[API] Schwab REST quote for {symbol}: ${_sq_price:.4f}")
                            except Exception as _sq_err:
                                print(f"[API] Schwab REST quote error for {symbol}: {_sq_err}")

                        # Fallback to yfinance for non-Webull positions (Robinhood, Alpaca, etc.)
                        if not quote_data:
                            print(f"[API] Using yfinance fallback for {symbol}")
                            quote_data = _get_yfinance_quote(symbol)
                            if quote_data:
                                print(f"[API] yfinance quote for {symbol}: last=${quote_data.get('last', 0):.2f}")
                        
                        if quote_data:
                            prices[str(trade_id)] = quote_data
                except Exception as e:
                    print(f"[API] Error fetching price for {pos.get('symbol')}: {e}")
                    continue
            
            return {'prices': prices}
        
        return await run_async_safely(_blocking_call)
    
