    @app.route('/api/streaming/quotes', methods=['GET'])
    @login_required
    def api_streaming_quotes():
        """Lightweight endpoint returning only streaming quote data for active positions.
        Reads FRESH prices from streaming hubs on each call (not stale snapshot).
        Designed for fast 1-2s polling from the frontend to update prices in-place.
        """
        try:
            from gui_app.live_snapshot import get_live_snapshot
            snapshot = get_live_snapshot()
            positions = snapshot.get('positions', [])

            wb_hub = None
            wb_streaming = False
            sch_hub = None
            sch_streaming = False
            ibkr_hub = None
            ibkr_streaming = False
            try:
                from src.services.webull_data_hub import get_webull_data_hub
                wb_hub = get_webull_data_hub()
                wb_streaming = wb_hub.is_streaming()
            except Exception:
                pass
            try:
                from src.services.schwab_data_hub import get_schwab_data_hub
                sch_hub = get_schwab_data_hub()
                sch_streaming = sch_hub.is_streaming()
            except Exception:
                pass
            try:
                from src.services.ibkr_data_hub import get_ibkr_data_hub
                ibkr_hub = get_ibkr_data_hub()
                ibkr_streaming = ibkr_hub.is_streaming()
            except Exception:
                pass

            now = time.time()
            quotes = {}
            for pos in positions:
                pid = pos.get('id')
                if pid is None:
                    pid = f"{pos.get('broker','')}__{pos.get('symbol','')}"
                    if pid == '__':
                        continue
                symbol = pos.get('symbol', '')
                broker = (pos.get('broker') or '').upper()
                entry = pos.get('entry_price', 0)
                qty = pos.get('quantity', 0)
                is_option = pos.get('asset_type') == 'option'

                last = pos.get('last', pos.get('current_price', 0))
                bid = pos.get('bid', 0)
                ask = pos.get('ask', 0)
                source = 'rest'
                age = -1

                fresh_quote = None
                if symbol and not is_option:
                    if 'WEBULL' in broker and wb_hub and wb_streaming:
                        fresh_quote = wb_hub.get_quote_detailed(symbol)
                        if fresh_quote and fresh_quote.get('last', 0) > 0:
                            source = 'stream'
                    elif broker == 'SCHWAB' and sch_hub and sch_streaming:
                        fresh_quote = sch_hub.get_quote_detailed(symbol)
                        if fresh_quote and fresh_quote.get('last', 0) > 0:
                            source = 'stream'
                    elif 'IBKR' in broker and ibkr_hub and ibkr_streaming:
                        fresh_quote = ibkr_hub.get_quote_detailed(symbol)
                        if fresh_quote and fresh_quote.get('last', 0) > 0:
                            source = 'stream'
                    else:
                        if wb_hub and wb_streaming:
                            fresh_quote = wb_hub.get_quote_detailed(symbol)
                            if fresh_quote and fresh_quote.get('last', 0) > 0:
                                source = 'stream_cross'
                        if (not fresh_quote or fresh_quote.get('last', 0) <= 0) and sch_hub and sch_streaming:
                            fresh_quote = sch_hub.get_quote_detailed(symbol)
                            if fresh_quote and fresh_quote.get('last', 0) > 0:
                                source = 'stream_cross'
                        if (not fresh_quote or fresh_quote.get('last', 0) <= 0) and ibkr_hub and ibkr_streaming:
                            fresh_quote = ibkr_hub.get_quote_detailed(symbol)
                            if fresh_quote and fresh_quote.get('last', 0) > 0:
                                source = 'stream_cross'

                if fresh_quote and fresh_quote.get('last', 0) > 0:
                    last = fresh_quote['last']
                    bid = fresh_quote.get('bid', 0) or bid
                    ask = fresh_quote.get('ask', 0) or ask
                    age = round(now - fresh_quote.get('timestamp', 0), 1)

                mid = round((bid + ask) / 2, 4) if bid > 0 and ask > 0 else 0
                pnl_pct = pos.get('pnl_pct', 0)
                unrealized = pos.get('unrealized_pnl', 0)
                if entry > 0 and last > 0 and source != 'rest':
                    pnl_pct = round(((last - entry) / entry) * 100, 2)
                    unrealized = round((last - entry) * qty * (100 if is_option else 1), 2)

                quotes[str(pid)] = {
                    'last': last,
                    'bid': bid,
                    'ask': ask,
                    'mid': mid,
                    'pnl_pct': pnl_pct,
                    'unrealized_pnl': unrealized,
                    'source': source,
                    'age': age,
                }

            return jsonify({
                'success': True,
                'quotes': quotes,
                'streaming_status': {
                    'webull': wb_streaming,
                    'schwab': sch_streaming,
                    'ibkr': ibkr_streaming,
                },
                'snapshot_age': round(now - snapshot.get('last_updated', 0), 1),
            })
        except Exception as e:
            return jsonify({'success': False, 'quotes': {}, 'error': str(e)})

    @app.route('/api/streaming/stock-quote', methods=['GET'])
    @login_required
    def api_streaming_stock_quote():
        """Return streaming quote for a single symbol from the appropriate broker data hub.
        Used by Quick Trade panel for real-time underlying stock price.
        """
        symbol = request.args.get('symbol', '').upper()
        broker = request.args.get('broker', '').upper()
        if not symbol:
            return jsonify({'success': False, 'error': 'Symbol required'})

        result = {'success': True, 'symbol': symbol, 'source': 'none', 'streaming': False}

        def _try_hub(hub, source_label):
            if not hub.is_streaming():
                return False
            quote = hub.get_quote_detailed(symbol)
            if quote and quote.get('last', 0) > 0:
                result.update({
                    'last': quote['last'],
                    'bid': quote.get('bid', 0),
                    'ask': quote.get('ask', 0),
                    'mid': round((quote.get('bid', 0) + quote.get('ask', 0)) / 2, 4) if quote.get('bid', 0) > 0 and quote.get('ask', 0) > 0 else 0,
                    'source': source_label,
                    'streaming': True,
                    'age': round(time.time() - quote.get('timestamp', 0), 1),
                })
                return True
            return False

        try:
            if 'SCHWAB' in broker:
                from src.services.schwab_data_hub import get_schwab_data_hub
                _try_hub(get_schwab_data_hub(), 'schwab_stream')
            elif 'WEBULL' in broker:
                from src.services.webull_data_hub import get_webull_data_hub
                _try_hub(get_webull_data_hub(), 'webull_stream')
        except Exception:
            pass

        return jsonify(result)

    @app.route('/api/trades/close-all', methods=['POST'])
    @login_required
    def api_close_all_positions():
        """Close all open positions across all brokers in parallel."""
        if _bot_instance is None:
            return jsonify({'success': False, 'error': 'Bot not initialized'}), 500
        
        try:
            from gui_app.live_snapshot import get_live_snapshot
            snapshot = get_live_snapshot()
            open_positions = [p for p in snapshot.get('positions', []) if p.get('status') in ('OPEN', None) or p.get('source') == 'live_brokerage']
            
            if not open_positions:
                return jsonify({'success': True, 'message': 'No open positions to close', 'results': []})
            
            data = request.get_json(silent=True) or {}
            order_type = data.get('order_type', 'market')
            
            results = []
            import concurrent.futures
            
            def _close_single(pos):
                trade_id = pos.get('id')
                symbol = pos.get('symbol', 'Unknown')
                broker = str(pos.get('broker', '')).upper()
                quantity = int(pos.get('quantity') or 1)
                asset_type = pos.get('asset_type', 'stock')
                limit_price = None
                if order_type == 'bid' and pos.get('bid', 0) > 0:
                    limit_price = pos['bid']
                elif order_type == 'mid' and pos.get('mid', 0) > 0:
                    limit_price = pos['mid']
                
                try:
                    broker_obj = None
                    broker_attr_map = {
                        'SCHWAB': 'schwab_broker',
                        'IBKR': 'ibkr_broker',
                        'INTERACTIVE': 'ibkr_broker',
                        'TASTYTRADE': 'tastytrade_broker',
                        'TASTY': 'tastytrade_broker',
                        'ROBINHOOD': 'robinhood_broker',
                        'ALPACA': 'alpaca_paper_broker',
                        'TRADING212': 'trading212_broker',
                    }
                    
                    for key, attr in broker_attr_map.items():
                        if key in broker:
                            broker_obj = getattr(_bot_instance, attr, None) or getattr(getattr(_bot_instance, 'broker_manager', None), attr, None)
                            break
                    
                    if 'WEBULL' in broker:
                        wb = getattr(_bot_instance, 'webull_live', None) or getattr(_bot_instance, 'webull_paper', None)
                        if wb:
                            if asset_type == 'option':
                                result = wb.place_option_order(symbol, pos.get('strike'), pos.get('expiry'), pos.get('call_put'), 'STC', quantity, limit_price)
                            else:
                                result = wb.place_order(symbol=symbol, action='SELL', quant=quantity, price=limit_price)
                            db.close_trade(trade_id, limit_price or 0, 'manual_close_all')
                            return {'trade_id': trade_id, 'symbol': symbol, 'success': True, 'message': 'Webull close sent'}
                    
                    if broker_obj:
                        if asset_type == 'option':
                            future = asyncio.run_coroutine_threadsafe(
                                broker_obj.place_option_order(symbol, pos.get('strike'), pos.get('expiry'), pos.get('call_put'), 'STC', quantity, limit_price),
                                _bot_instance.loop
                            )
                        else:
                            future = asyncio.run_coroutine_threadsafe(
                                broker_obj.place_stock_order(symbol, 'STC', quantity, limit_price),
                                _bot_instance.loop
                            )
                        result = future.result(timeout=25)
                        if result and result.success:
                            db.close_trade(trade_id, result.price or limit_price or 0, 'manual_close_all')
                            return {'trade_id': trade_id, 'symbol': symbol, 'success': True, 'message': f'{broker} close sent'}
                        else:
                            return {'trade_id': trade_id, 'symbol': symbol, 'success': False, 'message': f'{broker} close failed: {result.message if result else "Unknown"}'}
                    
                    db.close_trade(trade_id, limit_price or 0, 'manual_close_all')
                    return {'trade_id': trade_id, 'symbol': symbol, 'success': True, 'message': 'DB position closed (no broker match)'}
                except Exception as e:
                    return {'trade_id': trade_id, 'symbol': symbol, 'success': False, 'message': str(e)}
            
            with concurrent.futures.ThreadPoolExecutor(max_workers=8) as executor:
                futures = {executor.submit(_close_single, pos): pos for pos in open_positions}
                for f in concurrent.futures.as_completed(futures, timeout=30):
                    try:
                        results.append(f.result(timeout=25))
                    except Exception as e:
                        pos = futures[f]
                        results.append({'trade_id': pos.get('id'), 'symbol': pos.get('symbol'), 'success': False, 'message': str(e)})
            
            success_count = sum(1 for r in results if r.get('success'))
            return jsonify({
                'success': True,
                'message': f'Closed {success_count}/{len(results)} positions',
                'results': results
            })
        except Exception as e:
            print(f"[API] Close-all error: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500

    @app.route('/api/trades/merged', methods=['GET'])
    def get_merged_trades():
        """Get trades merged with live Webull positions"""
        if _bot_instance is None:
            return jsonify({'trades': []})
        
        # Get filter parameters
        status_filter = request.args.get('status')
        broker_filter = request.args.get('broker')
        limit = int(request.args.get('limit', 1000))
        
        try:
            # Get database trades with filters, enriched with remaining_qty from execution_lots
            db_trades = db.get_trades(status=status_filter, broker=broker_filter, limit=limit)
            
            # Enrich each trade with remaining_qty from canonical execution_lots
            for trade in db_trades:
                if trade.get('direction') == 'BTO' and trade.get('id'):
                    qty_info = db.get_trade_remaining_qty(trade['id'])
                    if qty_info:
                        trade['original_qty'] = qty_info['original_qty']
                        trade['remaining_qty'] = qty_info['remaining_qty']
                        trade['realized_pnl'] = qty_info['realized_pnl']
                        # Show partial status if quantity reduced
                        if qty_info['remaining_qty'] < qty_info['original_qty'] and qty_info['remaining_qty'] > 0:
                            trade['display_status'] = 'PARTIAL'
                        else:
                            trade['display_status'] = trade['status']
            
            # Get live positions from cached snapshot (already enriched with fuzzy matching)
            live_positions = []
            webull_orders = []
            alpaca_orders = []
            
            broker_filter_upper = broker_filter.upper() if broker_filter else None
            
            try:
                from gui_app.live_snapshot import get_live_snapshot
                snapshot = get_live_snapshot()
                cached_positions = snapshot.get('positions', [])
                for pos in cached_positions:
                    if pos.get('source') != 'live_brokerage':
                        continue
                    pos_broker = pos.get('broker', '').upper()
                    if broker_filter_upper and broker_filter_upper not in pos_broker:
                        continue
                    live_positions.append({
                        'symbol': pos.get('symbol', ''),
                        'asset': pos.get('asset_type', 'stock'),
                        'asset_type': pos.get('asset_type', 'stock'),
                        'strike': pos.get('strike'),
                        'expiry': pos.get('expiry'),
                        'call_put': pos.get('call_put', ''),
                        'direction': pos.get('call_put', ''),
                        'quantity': pos.get('quantity', 0),
                        'avg_cost': pos.get('entry_price', 0),
                        'current_price': pos.get('current_price', 0),
                        'unrealized_pl': pos.get('unrealized_pnl', 0),
                        'broker': pos.get('broker', ''),
                        'bid': pos.get('bid', 0),
                        'ask': pos.get('ask', 0),
                        'mid': pos.get('mid', 0),
                        'last': pos.get('last', 0),
                        'option_id': pos.get('option_id'),
                    })
            except Exception as e:
                print(f"[API] Snapshot cache read error: {e}")
            
            if not broker_filter_upper or broker_filter_upper in ['WEBULL']:
                try:
                    if hasattr(_bot_instance, 'broker') and _bot_instance.broker:
                        wb = getattr(_bot_instance.broker, '_client', None)
                        if wb:
                            webull_orders = None
                            try:
                                from src.services.webull_data_hub import get_webull_data_hub
                                _hub = get_webull_data_hub()
                                cached_orders = _hub.get_pending_orders(max_age_seconds=15)
                                if cached_orders is not None:
                                    webull_orders = cached_orders
                            except Exception:
                                pass
                            if webull_orders is None:
                                webull_orders = wb.get_current_orders() or []
                except Exception as e:
                    print(f"[API] Webull orders fetch error: {e}")
            
            # Create order_id -> status mapping for quick lookup
            order_status_map = {order.get('order_id', ''): order.get('status', '') for order in webull_orders if order.get('order_id')}
            
            _SYMBOL_ALIASES = {'SPXW': 'SPX', 'NDXP': 'NDX', 'RUTW': 'RUT'}
            def normalize_option_symbol(sym):
                s = (sym or '').upper().strip()
                return _SYMBOL_ALIASES.get(s, s)

            # Helper to normalize call_put to single character
            def normalize_call_put(val):
                val = (val or '').upper().strip()
                if val in ['CALL', 'C', 'BTO']:
                    return 'C'
                elif val in ['PUT', 'P', 'STO']:
                    return 'P'
                return val[:1] if val else ''
            
            # Helper to normalize expiry to MMDD format for matching
            def normalize_expiry(val):
                if not val:
                    return ''
                val = str(val).strip()
                # Handle various formats: 12/12, 2024-12-12, 12-12-24, etc.
                import re
                # Try to extract month and day
                # Format: MM/DD or M/D
                match = re.match(r'^(\d{1,2})/(\d{1,2})$', val)
                if match:
                    return f"{int(match.group(1)):02d}{int(match.group(2)):02d}"
                # Format: YYYY-MM-DD
                match = re.match(r'^(\d{4})-(\d{1,2})-(\d{1,2})$', val)
                if match:
                    return f"{int(match.group(2)):02d}{int(match.group(3)):02d}"
                # Format: MM-DD-YY or MM-DD-YYYY
                match = re.match(r'^(\d{1,2})-(\d{1,2})-(\d{2,4})$', val)
                if match:
                    return f"{int(match.group(1)):02d}{int(match.group(2)):02d}"
                # Format: MM/DD/YY or MM/DD/YYYY
                match = re.match(r'^(\d{1,2})/(\d{1,2})/(\d{2,4})$', val)
                if match:
                    return f"{int(match.group(1)):02d}{int(match.group(2)):02d}"
                return val  # Return as-is if can't parse
            
            # Create a merged list
            merged = []
            tracked_positions = set()
            
            # Create position key -> live position mapping for merging prices
            # Include broker in key to properly separate multi-broker positions
            live_position_map = {}
            for pos in live_positions:
                direction = pos.get('direction') or pos.get('call_put') or ''
                call_put_norm = normalize_call_put(direction)
                expiry_norm = normalize_expiry(pos.get('expiry', ''))
                broker_norm = str(pos.get('broker', '')).upper()
                
                pos_asset = pos.get('asset', pos.get('asset_type', 'stock'))
                sym_norm = normalize_option_symbol(pos.get('symbol', ''))
                if pos_asset == 'option':
                    pos_key = f"{broker_norm}|{sym_norm}_{pos.get('strike', '')}_{expiry_norm}_{call_put_norm}"
                else:
                    pos_key = f"{broker_norm}|{sym_norm}_stock"
                live_position_map[pos_key] = pos
            
            # Group database trades by position key (including broker) for consolidation
            position_groups = {}
            for trade in db_trades:
                call_put_norm = normalize_call_put(trade.get('call_put', ''))
                expiry_norm = normalize_expiry(trade.get('expiry', ''))
                broker_norm = str(trade.get('broker', '')).upper()
                
                sym_norm = normalize_option_symbol(trade.get('symbol', ''))
                if trade['asset_type'] == 'option':
                    pos_key = f"{broker_norm}|{sym_norm}_{trade.get('strike', '')}_{expiry_norm}_{call_put_norm}"
                else:
                    pos_key = f"{broker_norm}|{sym_norm}_stock"
                
                if pos_key not in position_groups:
                    position_groups[pos_key] = []
                position_groups[pos_key].append(trade)
            
            # Process each position group and enrich with source_display
            for pos_key, trades in position_groups.items():
                # DEDUPLICATION: Sort trades to prefer discord source over sync
                # Priority: discord > sync_discord > sync (stale entries without order_id)
                def trade_priority(t):
                    source = (t.get('source') or '').lower()
                    has_order_id = bool(t.get('order_id'))
                    if source == 'discord' and has_order_id:
                        return 0  # Highest priority
                    elif source == 'sync_discord' and has_order_id:
                        return 1
                    elif source == 'discord':
                        return 2
                    elif source == 'sync_discord':
                        return 3
                    elif source == 'sync' and has_order_id:
                        return 4
                    else:
                        return 5  # Lowest priority (stale sync without order_id)
                
                trades = sorted(trades, key=trade_priority)
                
                # Enrich trades with source_display for UI badges
                for trade in trades:
                    trade['source_display'] = db.get_trade_source_display(trade)
                tracked_positions.add(pos_key)
                
                # Check if this position has a live broker match
                has_live_position = pos_key in live_position_map
                
                _TRUSTED_UI_SOURCES = ('discord', 'signal', 'sync_routing')
                if has_live_position:
                    # CONSOLIDATE: Show single row with LIVE broker quantity and current price
                    live_pos = live_position_map[pos_key]
                    # Use best trade (sorted by priority) for metadata
                    first_trade = trades[0]
                    
                    # Use broker's avg_cost as authoritative source for live positions
                    # Broker tracks ALL orders including those made outside this bot
                    broker_avg_cost = live_pos.get('avg_cost', 0)
                    
                    # Fallback: Calculate from database if broker doesn't provide avg_cost
                    if not broker_avg_cost or broker_avg_cost <= 0:
                        total_qty = sum(t.get('quantity', 0) for t in trades if t['status'] == 'OPEN')
                        total_cost = sum(t.get('quantity', 0) * (t.get('executed_price') or t.get('intended_price', 0)) 
                                       for t in trades if t['status'] == 'OPEN')
                        broker_avg_cost = (total_cost / total_qty) if total_qty > 0 else 0
                    channel_id = first_trade.get('channel_id')
                    first_source = (first_trade.get('source') or '').lower().strip()
                    first_status = (first_trade.get('status') or '').upper()
                    channel_info = None
                    if channel_id and first_source in _TRUSTED_UI_SOURCES and first_status in ('OPEN', 'PENDING', 'PARTIAL'):
                        try:
                            channel_info = db.get_channel_by_discord_id(channel_id)
                        except:
                            pass
                    
                    live_qty = live_pos['quantity']
                    live_qty_int = int(live_qty) if live_qty == int(live_qty) else live_qty
                    merged.append({
                        **first_trade,
                        'quantity': live_qty_int,
                        'remaining_qty': live_qty_int,
                        'original_qty': live_qty_int,
                        'entry_price': broker_avg_cost,
                        'current_price': live_pos['current_price'],
                        'pnl': live_pos['unrealized_pl'],
                        'pnl_percent': ((live_pos['current_price'] - broker_avg_cost) / broker_avg_cost * 100) if broker_avg_cost > 0 else 0,
                        'source': 'live_brokerage',
                        'status': 'OPEN',
                        'fill_status': 'Filled',
                        'option_id': live_pos.get('option_id') or first_trade.get('option_id'),
                        'source_display': first_trade.get('source_display') or db.get_trade_source_display(first_trade),
                        'channel_name': channel_info.get('name') if channel_info else 'Global',
                        'channel_id': channel_id if channel_info else None,
                        'profit_target_1_pct': channel_info.get('profit_target_1_pct', 20) if channel_info else 20,
                        'profit_target_2_pct': channel_info.get('profit_target_2_pct', 50) if channel_info else 50,
                        'profit_target_3_pct': channel_info.get('profit_target_3_pct', 100) if channel_info else 100,
                        'stop_loss_pct': channel_info.get('stop_loss_pct', 10) if channel_info else 10
                    })
                elif not has_live_position:
                    # No live position: Add each database trade separately
                    for trade in trades:
                        fill_status = 'Filled'
                        order_id = trade.get('order_id')
                        
                        if order_id and order_id in order_status_map:
                            fill_status = order_status_map[order_id]
                        elif trade['status'] == 'OPEN':
                            fill_status = 'Filled'
                        
                        channel_id = trade.get('channel_id')
                        trade_source = (trade.get('source') or '').lower().strip()
                        trade_status = (trade.get('status') or '').upper()
                        channel_info = None
                        if channel_id and trade_source in _TRUSTED_UI_SOURCES and trade_status in ('OPEN', 'PENDING', 'PARTIAL'):
                            try:
                                channel_info = db.get_channel_by_discord_id(channel_id)
                            except:
                                pass
                        
                        merged.append({
                            **trade,
                            'entry_price': trade.get('executed_price') or trade.get('intended_price'),
                            'source': 'bot_tracked',
                            'fill_status': fill_status,
                            'source_display': trade.get('source_display') or db.get_trade_source_display(trade),
                            'channel_name': channel_info.get('name') if channel_info else 'Global',
                            'channel_id': channel_id if channel_info else None,
                            'profit_target_1_pct': channel_info.get('profit_target_1_pct', 20) if channel_info else 20,
                            'profit_target_2_pct': channel_info.get('profit_target_2_pct', 50) if channel_info else 50,
                            'profit_target_3_pct': channel_info.get('profit_target_3_pct', 100) if channel_info else 100,
                            'stop_loss_pct': channel_info.get('stop_loss_pct', 10) if channel_info else 10
                        })
            
            # Add live positions not tracked by bot (all brokers)
            for pos in live_positions:
                direction = pos.get('direction') or pos.get('call_put') or ''
                call_put_norm = normalize_call_put(direction)
                expiry_norm = normalize_expiry(pos.get('expiry', ''))
                broker_norm = str(pos.get('broker', '')).upper()
                
                pos_asset = pos.get('asset', pos.get('asset_type', 'stock'))
                sym_norm = normalize_option_symbol(pos.get('symbol', ''))
                if pos_asset == 'option':
                    pos_key = f"{broker_norm}|{sym_norm}_{pos.get('strike', '')}_{expiry_norm}_{call_put_norm}"
                else:
                    pos_key = f"{broker_norm}|{sym_norm}_stock"
                
                if pos_key not in tracked_positions and (not status_filter or status_filter == 'OPEN'):
                    import hashlib
                    stable_id = 'live_' + hashlib.md5(pos_key.encode()).hexdigest()[:12]
                    
                    pos_broker = pos.get('broker', 'Webull')
                    
                    recovered_channel = None
                    recovered_channel_info = None
                    try:
                        conn_ch = db.get_connection()
                        cur_ch = conn_ch.cursor()
                        if pos_asset == 'option':
                            cur_ch.execute('''
                                SELECT t.channel_id, c.name as channel_name, c.profit_target_1_pct, c.profit_target_2_pct, 
                                       c.profit_target_3_pct, c.stop_loss_pct
                                FROM trades t
                                LEFT JOIN channels c ON (t.channel_id = c.discord_channel_id 
                                    OR t.channel_id = CAST(c.id AS TEXT)
                                    OR t.channel_id = c.telegram_chat_id)
                                WHERE t.symbol = ? AND t.asset_type = 'option' AND LOWER(t.broker) = LOWER(?)
                                AND t.direction = 'BTO'
                                AND t.status IN ('OPEN', 'PENDING', 'PARTIAL')
                                AND COALESCE(LOWER(TRIM(t.source)), '') IN ('discord', 'signal', 'sync_routing')
                                ORDER BY t.id DESC LIMIT 1
                            ''', (pos['symbol'], pos_broker))
                        else:
                            cur_ch.execute('''
                                SELECT t.channel_id, c.name as channel_name, c.profit_target_1_pct, c.profit_target_2_pct, 
                                       c.profit_target_3_pct, c.stop_loss_pct
                                FROM trades t
                                LEFT JOIN channels c ON (t.channel_id = c.discord_channel_id 
                                    OR t.channel_id = CAST(c.id AS TEXT)
                                    OR t.channel_id = c.telegram_chat_id)
                                WHERE t.symbol = ? AND t.asset_type = 'stock' AND LOWER(t.broker) = LOWER(?)
                                AND t.direction = 'BTO'
                                AND t.status IN ('OPEN', 'PENDING', 'PARTIAL')
                                AND COALESCE(LOWER(TRIM(t.source)), '') IN ('discord', 'signal', 'sync_routing')
                                ORDER BY t.id DESC LIMIT 1
                            ''', (pos['symbol'], pos_broker))
                        recovered_channel = cur_ch.fetchone()
                        if recovered_channel and recovered_channel[1]:
                            recovered_channel_info = {
                                'channel_id': recovered_channel[0],
                                'channel_name': recovered_channel[1],
                                'profit_target_1_pct': recovered_channel[2] or 20,
                                'profit_target_2_pct': recovered_channel[3] or 50,
                                'profit_target_3_pct': recovered_channel[4] or 100,
                                'stop_loss_pct': recovered_channel[5] or 10,
                            }
                    except Exception:
                        pass
                    
                    untracked_qty = pos['quantity']
                    ch_name = recovered_channel_info['channel_name'] if recovered_channel_info else 'Global'
                    live_pos_trade = {
                        'id': stable_id,
                        'symbol': pos['symbol'],
                        'asset_type': pos_asset,
                        'side': 'BTO',
                        'quantity': int(untracked_qty) if untracked_qty == int(untracked_qty) else untracked_qty,
                        'entry_price': pos['avg_cost'],
                        'current_price': pos['current_price'],
                        'pnl': pos['unrealized_pl'],
                        'pnl_percent': ((pos['current_price'] - pos['avg_cost']) / pos['avg_cost'] * 100) if pos['avg_cost'] > 0 else 0,
                        'status': 'OPEN',
                        'broker': pos_broker,
                        'executed_at': None,
                        'strike': pos.get('strike'),
                        'expiry': pos.get('expiry'),
                        'call_put': call_put_norm,
                        'option_id': pos.get('option_id'),
                        'source': 'sync',
                        'fill_status': 'Filled',
                        'channel_id': recovered_channel_info['channel_id'] if recovered_channel_info else None,
                        'channel_name': ch_name,
                        'profit_target_1_pct': recovered_channel_info['profit_target_1_pct'] if recovered_channel_info else 20,
                        'profit_target_2_pct': recovered_channel_info['profit_target_2_pct'] if recovered_channel_info else 50,
                        'profit_target_3_pct': recovered_channel_info['profit_target_3_pct'] if recovered_channel_info else 100,
                        'stop_loss_pct': recovered_channel_info['stop_loss_pct'] if recovered_channel_info else 10,
                    }
                    if recovered_channel_info:
                        live_pos_trade['source_display'] = db.get_trade_source_display(live_pos_trade)
                    else:
                        live_pos_trade['source_display'] = {
                            'name': f'{pos_broker} Sync',
                            'color': 'gray',
                            'icon': '🔄',
                            'full_name': f'Position from {pos_broker}'
                        }
                    merged.append(live_pos_trade)
            
            # Add pending Webull orders not tracked in database (only if status filter allows)
            if not status_filter or status_filter == 'PENDING':
                tracked_order_ids = {trade.get('order_id') for trade in db_trades if trade.get('order_id')}
                # Also track pending symbols to avoid duplicates
                tracked_pending_symbols = {(trade.get('symbol'), trade.get('quantity')) 
                                           for trade in merged 
                                           if trade.get('status') == 'PENDING'}
                
                for order in webull_orders:
                    order_id = order.get('order_id', '')
                    order_symbol = order.get('symbol', '')
                    order_qty = order.get('quantity', 0)
                    order_status = order.get('status', '')
                    
                    if not order_id or not order_symbol:
                        continue
                    
                    symbol_qty_key = (order_symbol, order_qty)
                    
                    # Skip if already tracked by order_id OR by symbol+quantity
                    if order_id in tracked_order_ids:
                        continue
                    if symbol_qty_key in tracked_pending_symbols:
                        continue
                    if order_status not in ['Submitted', 'Working']:
                        continue
                        
                    # Generate stable ID for pending order
                    import hashlib
                    stable_id = 'pending_' + hashlib.md5(str(order_id).encode()).hexdigest()[:12]
                    
                    limit_price = order.get('limit_price', 0) or order.get('lmtPrice', 0) or 0
                    
                    merged.append({
                        'id': stable_id,
                        'symbol': order_symbol,
                        'asset_type': order.get('asset_type', 'option'),
                        'side': order.get('action', 'BTO'),
                        'quantity': order_qty,
                        'entry_price': limit_price,
                        'current_price': limit_price,
                        'pnl': 0,
                        'pnl_percent': 0,
                        'status': 'PENDING',
                        'fill_status': order_status,
                        'broker': 'Webull',
                        'executed_at': None,
                        'order_id': order_id,
                        'source': 'pending_order',
                        'profit_target_percent': None,
                        'stop_loss_percent': None,
                        'trailing_stop_enabled': False,
                        'trailing_stop_percent': None
                    })
            
            # Alpaca positions are already synced to database by BrokerSyncService
            # No need to add live positions again from API - they would show as duplicates
            # Only add Alpaca pending orders if broker filter matches AND not already tracked
            if broker_filter in ['ALPACA', 'ALPACA_PAPER']:
                import hashlib
                if not status_filter or status_filter == 'PENDING':
                    # Build set of already tracked order IDs and symbol+qty combinations
                    tracked_order_ids = {str(trade.get('order_id')) for trade in merged if trade.get('order_id')}
                    tracked_pending_symbols = {(trade.get('symbol'), trade.get('quantity')) 
                                               for trade in merged 
                                               if trade.get('status') == 'PENDING'}
                    
                    for order in alpaca_orders:
                        order_id = str(order.get('order_id', ''))
                        symbol = order.get('symbol', '')
                        if not symbol:
                            continue
                        qty = int(float(order.get('quantity', 0)))
                        symbol_qty_key = (symbol, qty)
                        
                        # Skip if already tracked by order_id OR by symbol+quantity
                        if order_id in tracked_order_ids:
                            continue
                        if symbol_qty_key in tracked_pending_symbols:
                            continue
                        
                        stable_id = 'alpaca_order_' + hashlib.md5(order_id.encode()).hexdigest()[:12]
                        
                        merged.append({
                            'id': stable_id,
                            'symbol': symbol,
                            'asset_type': 'stock',
                            'side': order.get('action', 'BUY'),
                            'quantity': qty,
                            'entry_price': float(order.get('price', 0)),
                            'current_price': float(order.get('price', 0)),
                            'pnl': 0,
                            'pnl_percent': 0,
                            'status': 'PENDING',
                            'fill_status': order.get('status', 'pending'),
                            'broker': 'Alpaca',
                            'executed_at': None,
                            'order_id': order_id,
                            'source': 'pending_order',
                            'profit_target_percent': None,
                            'stop_loss_percent': None,
                            'trailing_stop_enabled': False,
                            'trailing_stop_percent': None
                        })
            
            # Safety net: Ensure all trades have a fill_status field
            for trade in merged:
                if 'fill_status' not in trade or trade['fill_status'] is None:
                    if trade.get('status') == 'OPEN':
                        trade['fill_status'] = 'Filled'
                    elif trade.get('status') == 'CLOSED':
                        trade['fill_status'] = 'Filled'
                    elif trade.get('status') == 'PENDING':
                        trade['fill_status'] = 'Submitted'
                    else:
                        trade['fill_status'] = 'Unknown'
            
            # Deduplicate: Remove duplicate position entries that can occur when
            # live broker positions and DB trades have subtle key format mismatches
            seen_position_keys = {}
            deduped_merged = []
            for trade in merged:
                call_put_val = normalize_call_put(trade.get('call_put', ''))
                expiry_val = normalize_expiry(trade.get('expiry', ''))
                strike_val = trade.get('strike', '')
                if strike_val is not None and strike_val != '':
                    try:
                        strike_val = float(strike_val)
                    except (ValueError, TypeError):
                        pass
                broker_val = str(trade.get('broker', '')).upper().replace('_PAPER', '').replace('_LIVE', '')
                
                if trade.get('asset_type') == 'option':
                    dedup_key = f"{trade.get('symbol', '')}_{strike_val}_{expiry_val}_{call_put_val}_{broker_val}"
                else:
                    dedup_key = f"{trade.get('symbol', '')}_stock_{broker_val}"
                
                if dedup_key in seen_position_keys:
                    existing = seen_position_keys[dedup_key]
                    existing_has_db_id = isinstance(existing.get('id'), int)
                    current_has_db_id = isinstance(trade.get('id'), int)
                    if current_has_db_id and not existing_has_db_id:
                        deduped_merged = [t for t in deduped_merged if t is not existing]
                        deduped_merged.append(trade)
                        seen_position_keys[dedup_key] = trade
                else:
                    seen_position_keys[dedup_key] = trade
                    deduped_merged.append(trade)
            
            merged = deduped_merged
            
            # Enrich trades with source display info for UI
            for trade in merged:
                if not trade.get('source_display'):
                    trade['source_display'] = db.get_trade_source_display(trade)
            
            return jsonify({'trades': merged})
            
        except Exception as e:
            print(f"[API] Error fetching merged trades: {type(e).__name__}: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e), 'trades': []}), 500
    
    async def _get_webull_positions():
        """Helper to fetch live Webull positions"""
        if not hasattr(_bot_instance, 'broker') or _bot_instance.broker is None:
            return []
        
        # Get the Webull broker instance
        broker = _bot_instance.broker
        
        # Check if it's the multi-broker manager
        if hasattr(broker, 'brokers'):
            # Find Webull broker
            webull_broker = broker.brokers.get('Webull')
            if webull_broker and hasattr(webull_broker, 'get_positions_detailed'):
                return await webull_broker.get_positions_detailed()
        elif hasattr(broker, 'get_positions_detailed'):
            # Direct broker instance
            return await broker.get_positions_detailed()
        
        return []
    
