    @app.route('/api/performance/pnl')
    def get_pnl_performance():
        """Get PNL performance metrics with filters"""
        from datetime import datetime, timedelta
        
        channel_id = request.args.get('channel_id', type=int)
        period = request.args.get('period', 'all')  # weekly, monthly, yearly, all
        
        # Calculate period boundaries
        period_start = None
        period_end = datetime.now()
        
        if period == 'weekly':
            period_start = period_end - timedelta(days=7)
        elif period == 'monthly':
            period_start = period_end - timedelta(days=30)
        elif period == 'yearly':
            period_start = period_end - timedelta(days=365)
        
        try:
            from . import database as db_module
            
            # Parse channel_id from query parameter (already retrieved above)
            metrics = db_module.get_performance_metrics(
                channel_id=channel_id,
                period_start=period_start,
                period_end=period_end
            )
            
            # Format results
            results = []
            for row in metrics:
                # Calculate win rate
                total_trades = row['total_trades'] or 0
                wins = row['wins'] or 0
                win_rate = (wins / total_trades * 100) if total_trades > 0 else 0
                
                # Format symbol display
                symbol_display = row['symbol']
                if row['asset_type'] == 'option' and row['strike']:
                    symbol_display += f" ${row['strike']}{row['call_put']} {row['expiry']}"
                
                results.append({
                    'symbol': symbol_display,
                    'asset_type': row['asset_type'],
                    'total_trades': total_trades,
                    'wins': wins,
                    'losses': row['losses'] or 0,
                    'win_rate': round(win_rate, 1),
                    'total_pnl': round(row['total_pnl'] or 0, 2),
                    'avg_pnl': round(row['avg_pnl'] or 0, 2),
                    'avg_pnl_percent': round(row['avg_pnl_percent'] or 0, 1),
                    'avg_holding_days': round(row['avg_holding_days'] or 0, 4)
                })
            
            # Calculate summary
            summary = {
                'total_symbols': len(results),
                'total_trades': sum(r['total_trades'] for r in results),
                'total_pnl': round(sum(r['total_pnl'] for r in results), 2),
                'avg_win_rate': round(sum(r['win_rate'] for r in results) / len(results), 1) if results else 0
            }
            
            return jsonify({
                'results': results,
                'summary': summary,
                'period': period,
                'period_start': period_start.isoformat() if period_start else None,
                'period_end': period_end.isoformat()
            })
            
        except Exception as e:
            print(f"[API] Error fetching PNL performance: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/performance/pnl/users')
    def get_pnl_performance_by_user():
        """Get PNL performance metrics grouped by user"""
        from datetime import datetime, timedelta
        
        channel_id = request.args.get('channel_id', type=int)
        period = request.args.get('period', 'all')
        
        # Build date filter based on period
        date_filter = ""
        if period == 'weekly':
            date_filter = "AND lc.closed_at >= datetime('now', '-7 days')"
        elif period == 'monthly':
            date_filter = "AND lc.closed_at >= datetime('now', '-30 days')"
        elif period == 'yearly':
            date_filter = "AND lc.closed_at >= datetime('now', '-365 days')"
        
        try:
            conn = db.get_connection()
            cursor = conn.cursor()
            
            # Build channel filter
            channel_filter = ""
            params = []
            if channel_id:
                channel_filter = "AND s.channel_id = ?"
                params.append(channel_id)
            
            # Query to get user-level performance from lot_closures
            query = f"""
                SELECT 
                    s.author_name as author,
                    COUNT(DISTINCT lc.id) as total_closures,
                    SUM(CASE WHEN lc.pnl > 0 THEN 1 ELSE 0 END) as wins,
                    SUM(CASE WHEN lc.pnl <= 0 THEN 1 ELSE 0 END) as losses,
                    SUM(lc.pnl) as total_pnl,
                    AVG(lc.pnl) as avg_pnl,
                    AVG(lc.pnl_percent) as avg_pnl_percent,
                    MAX(lc.pnl) as best_trade,
                    MIN(lc.pnl) as worst_trade,
                    AVG(lc.holding_days) as avg_holding_days
                FROM lot_closures lc
                JOIN signal_lots sl ON lc.lot_id = sl.id
                JOIN signals s ON sl.signal_id = s.id
                WHERE 1=1 {date_filter} {channel_filter}
                GROUP BY s.author_name
                ORDER BY total_pnl DESC
            """
            
            cursor.execute(query, params)
            users = cursor.fetchall()
            conn.close()
            
            # Format results with all necessary fields
            results = []
            for user in users:
                total_closures = user['total_closures'] or 0
                wins = user['wins'] or 0
                win_rate = (wins / total_closures * 100) if total_closures > 0 else 0
                
                results.append({
                    'author_name': user['author'] or 'Unknown',
                    'total_trades': total_closures,
                    'wins': wins,
                    'losses': user['losses'] or 0,
                    'win_rate': round(win_rate, 1),
                    'total_pnl': round(user['total_pnl'] or 0, 2),
                    'avg_pnl': round(user['avg_pnl'] or 0, 2),
                    'avg_pnl_percent': round(user['avg_pnl_percent'] or 0, 1),
                    'best_trade': round(user['best_trade'] or 0, 2),
                    'worst_trade': round(user['worst_trade'] or 0, 2),
                    'avg_holding_days': round(user['avg_holding_days'] or 0, 4)
                })

            # Calculate summary with proper aggregation
            total_wins = sum(r['wins'] for r in results)
            total_trades = sum(r['total_trades'] for r in results)
            
            summary = {
                'total_users': len(results),
                'total_trades': total_trades,
                'total_pnl': round(sum(r['total_pnl'] for r in results), 2),
                'avg_win_rate': round((total_wins / total_trades * 100) if total_trades > 0 else 0, 1)
            }
            
            return jsonify({
                'results': results,
                'summary': summary,
                'period': period
            })
            
        except Exception as e:
            print(f"[API] Error fetching user PNL performance: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    # Setup Wizard API - VERSION 2025-12-21-v3
    @app.route('/api/wizard/launch', methods=['POST'])
    def api_launch_wizard():
        """Launch the PySide6 setup wizard"""
        import subprocess
        import sys
        import os
        import threading
        import time
        
        # Collect debug info to return in response
        debug_info = {
            'api_version': '2025-12-21-v3',
            'timestamp': time.strftime('%Y-%m-%d %H:%M:%S'),
            'frozen': getattr(sys, 'frozen', False),
            'executable': sys.executable,
            'meipass': getattr(sys, '_MEIPASS', None),
            'cwd': os.getcwd(),
            'log_file_result': None
        }
        
        # Console logging
        print("=" * 60, flush=True)
        print(f"[Wizard API v3] === ENDPOINT CALLED ===", flush=True)
        print(f"[Wizard API v3] sys.frozen = {debug_info['frozen']}", flush=True)
        print(f"[Wizard API v3] sys.executable = {debug_info['executable']}", flush=True)
        print(f"[Wizard API v3] _MEIPASS = {debug_info['meipass']}", flush=True)
        sys.stdout.flush()
        
        # Try multiple log locations
        log_locations = []
        try:
            import tempfile
            log_locations.append(os.path.join(tempfile.gettempdir(), 'botifytrades_wizard_debug.log'))
        except:
            pass
        
        # Also try EXE directory
        try:
            if debug_info['frozen']:
                exe_dir = os.path.dirname(debug_info['executable'])
                log_locations.append(os.path.join(exe_dir, 'wizard_debug.log'))
        except:
            pass
        
        # Try to write to each location
        for log_path in log_locations:
            try:
                with open(log_path, 'a') as f:
                    f.write(f"\n{'=' * 60}\n")
                    f.write(f"[Wizard API v3] === ENDPOINT CALLED ===\n")
                    f.write(f"[Wizard API v3] Timestamp: {debug_info['timestamp']}\n")
                    f.write(f"[Wizard API v3] sys.frozen = {debug_info['frozen']}\n")
                    f.write(f"[Wizard API v3] sys.executable = {debug_info['executable']}\n")
                    f.write(f"[Wizard API v3] _MEIPASS = {debug_info['meipass']}\n")
                debug_info['log_file_result'] = f"Written to: {log_path}"
                print(f"[Wizard API v3] Log written to: {log_path}", flush=True)
                break
            except Exception as log_err:
                debug_info['log_file_result'] = f"Failed: {log_err}"
                print(f"[Wizard API v3] Could not write to {log_path}: {log_err}", flush=True)
        
        try:
            # Check if PySide6 or PyQt5 is available
            pyside_available = False
            pyqt_available = False
            
            try:
                import PySide6
                pyside_available = True
            except ImportError:
                pass
            
            try:
                import PyQt5
                pyqt_available = True
            except ImportError:
                pass
            
            debug_info['pyside_available'] = pyside_available
            debug_info['pyqt_available'] = pyqt_available
            
            if not pyside_available and not pyqt_available:
                return jsonify({
                    'success': False,
                    'error': 'PySide6 or PyQt5 is not installed. Install with: pip install PySide6',
                    'debug': debug_info
                })
            
            # Check if running as frozen EXE (PyInstaller bundle)
            is_frozen = getattr(sys, 'frozen', False)
            
            if is_frozen:
                # Running inside PyInstaller EXE - launch wizard via subprocess with --wizard flag
                # This spawns a new EXE process that runs only the wizard
                print("=" * 60, flush=True)
                print("[Wizard API] WIZARD LAUNCH TRIGGERED", flush=True)
                print(f"[Wizard API] Frozen EXE detected, launching wizard via subprocess...", flush=True)
                print(f"[Wizard API] Executable: {sys.executable}", flush=True)
                print(f"[Wizard API] PySide6 available: {pyside_available}, PyQt5 available: {pyqt_available}", flush=True)
                sys.stdout.flush()
                
                import subprocess
                
                # Launch a new instance of the EXE with --wizard flag
                # This flag is handled in selfbot_webull.py to run only the wizard
                try:
                    # Use CREATE_NEW_CONSOLE on Windows for a clean separate window
                    creation_flags = 0
                    if sys.platform == 'win32':
                        creation_flags = subprocess.CREATE_NEW_CONSOLE
                    
                    wizard_process = subprocess.Popen(
                        [sys.executable, '--wizard'],
                        creationflags=creation_flags,
                        start_new_session=True if sys.platform != 'win32' else False
                    )
                    
                    debug_info['process_started'] = True
                    debug_info['process_pid'] = wizard_process.pid
                    debug_info['launch_method'] = 'subprocess_with_wizard_flag'
                    print(f"[Wizard API] Wizard subprocess started: PID={wizard_process.pid}", flush=True)
                    print("=" * 60, flush=True)
                    sys.stdout.flush()
                    
                    return jsonify({
                        'success': True,
                        'launched': True,
                        'message': 'Setup Wizard launched! Check your desktop.',
                        'debug': debug_info
                    })
                except Exception as subprocess_err:
                    print(f"[Wizard API] Subprocess launch failed: {subprocess_err}", flush=True)
                    debug_info['subprocess_error'] = str(subprocess_err)
                    return jsonify({
                        'success': False,
                        'error': f'Failed to launch wizard subprocess: {subprocess_err}',
                        'debug': debug_info
                    })
            else:
                # Development mode - launch as subprocess
                project_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
                wizard_script = os.path.join(project_root, 'ui', 'wizard', 'launcher.py')
                debug_info['mode'] = 'development'
                debug_info['wizard_script'] = wizard_script
                debug_info['script_exists'] = os.path.exists(wizard_script)
                
                if os.path.exists(wizard_script):
                    subprocess.Popen(
                        [sys.executable, '-m', 'ui.wizard.launcher', '--force'],
                        cwd=project_root,
                        start_new_session=True
                    )
                    return jsonify({
                        'success': True,
                        'launched': True,
                        'message': 'Setup Wizard launched! Check your desktop.',
                        'debug': debug_info
                    })
                else:
                    return jsonify({
                        'success': False,
                        'error': 'Wizard script not found',
                        'debug': debug_info
                    })
                
        except Exception as e:
            print(f"[API v3] Error launching wizard: {e}")
            debug_info['exception'] = str(e)
            return jsonify({'success': False, 'error': str(e), 'debug': debug_info})
    
