    @app.route('/api/conditional_orders/status', methods=['GET'])
    def api_get_conditional_order_service_status():
        """Get diagnostic status of the conditional order service (router-based)"""
        try:
            from src.services.conditional_orders.router import conditional_order_router
            
            all_brokers = []
            total_monitors = 0
            any_running = False
            market_status = {}
            
            for market, service in conditional_order_router._services.items():
                is_running = service.is_running
                brokers = list(service.broker_instances.keys())
                monitors = len(service.monitors)
                
                market_status[market] = {
                    'running': is_running,
                    'brokers': brokers,
                    'monitors': monitors,
                    'active_order_ids': list(service.monitors.keys())
                }
                
                all_brokers.extend(brokers)
                total_monitors += monitors
                if is_running:
                    any_running = True
            
            return jsonify({
                'success': True,
                'service_running': any_running,
                'thread_alive': any_running,
                'thread_id': None,
                'monitors_count': total_monitors,
                'pending_orders_count': 0,
                'registered_brokers': all_brokers,
                'loop_running': any_running,
                'active_monitor_ids': [],
                'recent_logs': [],
                'market_services': market_status
            })
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/conditional_orders/live_prices', methods=['GET'])
    def api_get_conditional_order_live_prices():
        """Get live streaming prices for all active conditional orders."""
        try:
            from src.services.conditional_orders.router import conditional_order_router
            
            active_orders = db.get_active_conditional_orders()
            prices = {}
            
            for order in active_orders:
                symbol = order.get('symbol', '')
                order_id = order.get('id')
                broker = order.get('broker', '')
                
                if not symbol:
                    continue
                
                price_info = {
                    'symbol': symbol,
                    'price': None,
                    'source': 'none',
                    'trigger_price': order.get('trigger_price'),
                    'direction': order.get('direction', 'ABOVE'),
                    'status': order.get('status'),
                    'data_source': order.get('data_source_active', ''),
                }
                
                broker_normalized = broker.lower().replace('_paper', '').replace('_live', '') if broker else ''
                for market, service in conditional_order_router._services.items():
                    if broker_normalized:
                        hub = service.get_data_hub(broker_normalized)
                        if hub:
                            hub_price = hub.get_quote_price(symbol)
                            if hub_price and hub_price > 0:
                                price_info['price'] = hub_price
                                price_info['source'] = 'streaming'
                                if hasattr(hub, 'is_delayed') and hub.is_delayed():
                                    price_info['delayed'] = True
                                quote = hub.get_quote(symbol)
                                if quote:
                                    price_info['age'] = round(time.time() - quote.timestamp, 1) if hasattr(quote, 'timestamp') else 0
                                break
                    if not price_info['price'] and hasattr(service, 'data_hubs'):
                        for hub_key, hub_obj in service.data_hubs.items():
                            if hub_obj and hub_key != broker_normalized:
                                try:
                                    hp = hub_obj.get_quote_price(symbol)
                                    if hp and hp > 0:
                                        price_info['price'] = hp
                                        price_info['source'] = 'streaming'
                                        break
                                except Exception:
                                    pass
                    if price_info['price']:
                        break
                
                if not price_info['price']:
                    for market, service in conditional_order_router._services.items():
                        monitor = service.monitors.get(order_id)
                        if monitor and hasattr(monitor, 'last_price') and monitor.last_price:
                            price_info['price'] = monitor.last_price
                            price_info['source'] = 'monitor'
                            break
                
                prices[str(order_id)] = price_info
            
            return jsonify({'success': True, 'prices': prices})
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/conditional_orders/<int:order_id>/offset', methods=['POST'])
    def api_update_conditional_order_offset(order_id):
        """Update trigger offset for a conditional order (supports percent and dollar modes)"""
        try:
            data = request.json or {}
            offset_mode = data.get('offset_mode', 'percent') or 'percent'
            
            if offset_mode == 'dollar':
                offset_val = float(data.get('offset_value', 0))
                if offset_val < -1000 or offset_val > 1000:
                    return jsonify({'error': 'Dollar offset must be between -$1000 and +$1000'}), 400
            else:
                offset_val = float(data.get('offset_percent', data.get('offset_value', 0)))
                if offset_val < -50 or offset_val > 50:
                    return jsonify({'error': 'Percent offset must be between -50% and +50%'}), 400
            
            success = db.update_conditional_order_trigger_offset(
                order_id,
                offset_percent=offset_val if offset_mode == 'percent' else None,
                offset_mode=offset_mode,
                offset_value=offset_val if offset_mode == 'dollar' else None
            )
            
            if success:
                order = db.get_conditional_order_by_id(order_id)
                adjusted_price = order.get('adjusted_trigger_price') if order else None
                limit_price = order.get('limit_price') if order else None
                
                try:
                    from src.services.conditional_orders.base import conditional_order_services
                    for market, service in conditional_order_services.items():
                        if order_id in service.pending_orders:
                            service.pending_orders[order_id]['adjusted_trigger_price'] = adjusted_price
                            service.pending_orders[order_id]['trigger_offset'] = offset_val
                            if limit_price is not None:
                                service.pending_orders[order_id]['limit_price'] = limit_price
                            print(f"[API] Updated in-memory order #{order_id} adjusted_trigger_price={adjusted_price}, limit_price={limit_price}")
                            break
                except Exception as mem_err:
                    print(f"[API] Warning: Could not update in-memory order: {mem_err}")
                
                if offset_mode == 'dollar':
                    msg = f'Offset updated to {"+" if offset_val >= 0 else ""}{offset_val:.2f}'
                else:
                    msg = f'Offset updated to {offset_val:+.1f}%'
                
                return jsonify({
                    'success': True,
                    'message': msg,
                    'adjusted_trigger_price': adjusted_price,
                    'limit_price': limit_price
                })
            else:
                return jsonify({'error': 'Failed to update offset'}), 500
                
        except Exception as e:
            print(f"[API] Error updating conditional order offset: {e}")
            return jsonify({'error': str(e)}), 500
    
