    @app.route('/api/telegram/channels', methods=['POST'])
    @login_required
    def api_add_telegram_channel():
        """Add a new Telegram channel with execution/tracking settings"""
        try:
            from gui_app.database import add_telegram_channel
            
            data = request.json
            telegram_chat_id = data.get('telegram_chat_id')
            name = data.get('name')
            chat_type = data.get('chat_type', 'group')
            username = data.get('username')
            category = data.get('category', 'TRACK')
            execute_enabled = data.get('execute_enabled', category == 'EXECUTE')
            track_enabled = data.get('track_enabled', True)
            market = data.get('market', 'US')
            enabled_brokers = data.get('enabled_brokers', [])
            
            if not telegram_chat_id or not name:
                return jsonify({'success': False, 'error': 'Chat ID and name are required'}), 400
            
            channel_id = add_telegram_channel(
                telegram_chat_id=telegram_chat_id,
                name=name,
                chat_type=chat_type,
                username=username,
                category=category,
                execute_enabled=execute_enabled,
                track_enabled=track_enabled,
                market=market,
                enabled_brokers=enabled_brokers
            )
            
            if channel_id:
                try:
                    import sys
                    main_mod = sys.modules.get('__main__') or sys.modules.get('src.selfbot_webull')
                    get_tg = getattr(main_mod, 'get_telegram_listener', None) if main_mod else None
                    if get_tg:
                        listener = get_tg()
                        if listener:
                            listener.reload_channels_from_db()
                            print(f"[API] Telegram listener reloaded after adding channel")
                except Exception as reload_err:
                    print(f"[API] Warning: Could not reload Telegram listener: {reload_err}")
                
                return jsonify({'success': True, 'channel_id': channel_id, 'message': 'Telegram channel added'})
            else:
                return jsonify({'success': False, 'error': 'Failed to add channel'}), 500
        except Exception as e:
            print(f"[API] Error adding Telegram channel: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/telegram/channels/<int:channel_id>', methods=['PUT'])
    @login_required
    def api_update_telegram_channel(channel_id):
        """Update a Telegram channel (uses same update_channel as Discord)"""
        try:
            data = request.json
            
            # Mutual exclusivity enforcement: Early Trailing vs Legacy Trailing Stop
            current_channel = db.get_channel_by_id(channel_id) or {}
            enable_early = data.get('enable_early_trailing', current_channel.get('enable_early_trailing', 0))
            trailing_stop = data.get('trailing_stop_pct', current_channel.get('trailing_stop_pct'))
            
            if enable_early:
                data['trailing_stop_pct'] = None
                data['trailing_activation_pct'] = None
            elif trailing_stop and float(trailing_stop) > 0:
                data['enable_early_trailing'] = 0
            
            success = db.update_channel(channel_id, **data)
            
            if success:
                try:
                    import sys
                    main_mod = sys.modules.get('__main__') or sys.modules.get('src.selfbot_webull')
                    get_tg = getattr(main_mod, 'get_telegram_listener', None) if main_mod else None
                    if get_tg:
                        listener = get_tg()
                        if listener:
                            listener.reload_channels_from_db()
                            print(f"[API] Telegram listener reloaded channel configs")
                except Exception as reload_err:
                    print(f"[API] Warning: Could not reload Telegram listener: {reload_err}")
                return jsonify({'success': True, 'message': 'Telegram channel updated'})
            else:
                return jsonify({'success': False, 'error': 'Failed to update channel'}), 500
        except Exception as e:
            print(f"[API] Error updating Telegram channel: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
