    @app.route('/api/discord/send-signal', methods=['POST'])
    def api_send_discord_signal():
        """Send a trading signal to Discord via webhook - supports global webhook or per-channel webhook"""
        try:
            import requests as http_requests
            
            data = request.json
            signal = data.get('signal', '').strip()
            channel_id = data.get('channel_id')
            
            if not signal:
                return jsonify({'success': False, 'error': 'Signal message is required'}), 400
            
            webhook_url = None
            bot_name = ''

            if channel_id:
                try:
                    from . import webhook_service
                    channel = webhook_service.get_webhook_channel(int(channel_id))
                    if channel and channel.get('webhook_url'):
                        webhook_url = channel['webhook_url']
                        bot_name = channel.get('bot_name', '')
                        print(f"[DISCORD] Using webhook channel: {channel.get('name', 'Unknown')}")
                    else:
                        return jsonify({'success': False, 'error': f'Webhook channel {channel_id} not found or has no URL'}), 400
                except Exception as e:
                    print(f"[DISCORD] Channel lookup failed: {e}")

            if not webhook_url:
                from .config_service import get_discord_notifications
                settings = get_discord_notifications()
                webhook_url = settings.get('webhook_url', '')

                if not webhook_url:
                    return jsonify({'success': False, 'error': 'No webhook URL available. Either select a webhook channel or configure a global webhook in Settings → Notifications.'}), 400

                if not settings.get('enabled', True):
                    return jsonify({'success': False, 'error': 'Discord notifications are disabled. Enable them in Settings → Notifications.'}), 400

            payload = {
                "content": signal
            }
            if bot_name:
                payload["username"] = bot_name
            
            response = http_requests.post(webhook_url, json=payload, timeout=5)
            
            if response.status_code in [200, 204]:
                print(f"[DISCORD] Signal sent: {signal}")
                return jsonify({'success': True, 'message': 'Signal sent to Discord'})
            else:
                print(f"[DISCORD] Webhook failed: {response.status_code} - {response.text}")
                return jsonify({'success': False, 'error': f'Discord webhook failed: {response.status_code}'}), 500
                
        except Exception as e:
            print(f"[API] Error sending Discord signal: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/discord/send-channels', methods=['GET'])
    def api_list_send_channels():
        try:
            channels = []

            try:
                from . import webhook_service
                wh_channels = webhook_service.get_webhook_channels()
                for ch in wh_channels:
                    if ch.get('enabled', 1):
                        channels.append({
                            'id': f"wh_{ch['id']}",
                            'name': ch.get('name', f"Webhook {ch['id']}"),
                            'type': 'webhook',
                            'writable': True
                        })
            except Exception as e:
                print(f"[SEND_CHANNELS] Webhook channels error: {e}")

            if _bot_instance and hasattr(_bot_instance, 'guilds'):
                try:
                    from .database import get_channels as db_get_channels
                    db_channels = db_get_channels()
                    monitored_map = {}
                    for dbc in db_channels:
                        dc_id = dbc.get('discord_channel_id')
                        if dc_id:
                            monitored_map[str(dc_id)] = dbc

                    for guild in _bot_instance.guilds:
                        me = guild.me
                        for ch in guild.text_channels:
                            try:
                                perms = ch.permissions_for(me) if me else None
                                can_send = getattr(perms, 'send_messages', False) if perms else False
                            except Exception:
                                can_send = False
                            if not can_send:
                                continue
                            db_ch = monitored_map.get(str(ch.id))
                            is_monitored = db_ch is not None
                            ch_name = db_ch.get('name', f"#{ch.name}") if db_ch else f"#{ch.name}"
                            channels.append({
                                'id': f"dc_{ch.id}",
                                'name': ch_name,
                                'server': guild.name,
                                'type': 'discord',
                                'writable': True,
                                'monitored': is_monitored
                            })
                except Exception as e:
                    print(f"[SEND_CHANNELS] Discord channels error: {e}")

            return jsonify({'success': True, 'channels': channels})
        except Exception as e:
            print(f"[API] Error listing send channels: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500

    @app.route('/api/discord/send-signal-multi', methods=['POST'])
    def api_send_discord_signal_multi():
        try:
            import requests as http_requests
            data = request.json
            signal = data.get('signal', '').strip()
            target_ids = data.get('targets', [])

            if not signal:
                return jsonify({'success': False, 'error': 'Signal message is required'}), 400
            if not target_ids:
                return jsonify({'success': False, 'error': 'No channels selected'}), 400

            skip_tag = data.get('no_qt_tag', False)

            results = []
            for tid in target_ids:
                tid = str(tid)
                try:
                    if tid.startswith('wh_'):
                        wh_id = int(tid[3:])
                        from . import webhook_service
                        channel = webhook_service.get_webhook_channel(wh_id)
                        if not channel or not channel.get('webhook_url'):
                            results.append({'id': tid, 'ok': False, 'error': 'Channel not found'})
                            continue
                        if not channel.get('enabled', 1):
                            results.append({'id': tid, 'ok': False, 'error': 'Channel disabled'})
                            continue
                        bot_name = channel.get('bot_name', '')
                        payload = {"content": signal}
                        if bot_name:
                            payload["username"] = bot_name
                        resp = http_requests.post(channel['webhook_url'], json=payload, timeout=5)
                        if resp.status_code in [200, 204]:
                            results.append({'id': tid, 'ok': True, 'name': channel.get('name')})
                            print(f"[DISCORD] Signal sent to webhook '{channel.get('name')}': {signal}")
                        else:
                            results.append({'id': tid, 'ok': False, 'error': f'HTTP {resp.status_code}'})

                    elif tid.startswith('dc_'):
                        dc_id = tid[3:]
                        if not _bot_instance:
                            results.append({'id': tid, 'ok': False, 'error': 'Discord bot not connected'})
                            continue
                        dc_channel = _bot_instance.get_channel(int(dc_id))
                        if not dc_channel:
                            results.append({'id': tid, 'ok': False, 'error': 'Channel not accessible'})
                            continue
                        guild = getattr(dc_channel, 'guild', None)
                        me = getattr(guild, 'me', None) if guild else None
                        if me:
                            try:
                                perms = dc_channel.permissions_for(me)
                                if not getattr(perms, 'send_messages', False):
                                    results.append({'id': tid, 'ok': False, 'error': 'No write permission'})
                                    continue
                            except Exception:
                                pass
                        loop = get_webull_loop()
                        if not loop or loop.is_closed():
                            results.append({'id': tid, 'ok': False, 'error': 'Event loop unavailable'})
                            continue
                        import asyncio
                        send_msg = signal
                        future = asyncio.run_coroutine_threadsafe(dc_channel.send(send_msg), loop)
                        future.result(timeout=5)
                        results.append({'id': tid, 'ok': True, 'name': f"#{dc_channel.name}"})
                        print(f"[DISCORD] Signal sent to #{dc_channel.name}: {send_msg}")
                    else:
                        results.append({'id': tid, 'ok': False, 'error': 'Unknown channel type'})
                except Exception as e:
                    results.append({'id': tid, 'ok': False, 'error': str(e)})

            sent = sum(1 for r in results if r.get('ok'))
            failed = len(results) - sent
            return jsonify({
                'success': sent > 0,
                'sent': sent,
                'failed': failed,
                'results': results
            })
        except Exception as e:
            print(f"[API] Error sending multi-signal: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500

    @app.route('/api/settings/test_webhook', methods=['POST'])
    def api_test_webhook():
        """Test Discord webhook and return channel information"""
        try:
            data = request.json
            webhook_url = data.get('webhook_url', '').strip()
            
            if not webhook_url:
                return jsonify({'success': False, 'error': 'Webhook URL is required'}), 400
            
            # Send test message
            import requests
            from datetime import datetime
            
            embed = {
                "title": "🔔 Webhook Test",
                "description": "**Test notification from BotifyTrades**\n\nYour webhook is configured correctly!",
                "color": 0x0A84FF,  # Blue
                "timestamp": datetime.utcnow().isoformat(),
                "footer": {
                    "text": "BotifyTrades"
                }
            }
            
            payload = {
                "embeds": [embed],
                "username": "BotifyTrades"
            }
            response = requests.post(webhook_url, json=payload, timeout=5)
            
            if response.status_code == 204:
                # Get channel information from webhook URL
                # Webhook URL format: https://discord.com/api/webhooks/{webhook_id}/{webhook_token}
                # We need to query the webhook info to get channel name
                try:
                    # Extract webhook ID and token from URL
                    parts = webhook_url.rstrip('/').split('/')
                    if len(parts) >= 2:
                        webhook_id = parts[-2]
                        webhook_token = parts[-1]
                        
                        # Get webhook info (doesn't require auth)
                        info_url = f"https://discord.com/api/v10/webhooks/{webhook_id}/{webhook_token}"
                        info_response = requests.get(info_url, timeout=5)
                        
                        if info_response.status_code == 200:
                            webhook_info = info_response.json()
                            channel_name = webhook_info.get('channel_id', 'Unknown')
                            guild_name = webhook_info.get('guild_id', 'Unknown')
                            webhook_name = webhook_info.get('name', 'Unknown')
                            
                            return jsonify({
                                'success': True,
                                'message': 'Webhook test successful',
                                'channel_name': f"#{webhook_name}" if webhook_name != 'Unknown' else 'Unknown',
                                'guild_name': f"Server ID: {guild_name}",
                                'channel_id': channel_name
                            })
                except Exception as info_error:
                    print(f"[WEBHOOK] Could not fetch webhook info: {info_error}")
                
                # Fallback if we can't get detailed info
                return jsonify({
                    'success': True,
                    'message': 'Webhook test successful',
                    'channel_name': 'Test message sent successfully',
                    'guild_name': 'Check your Discord channel'
                })
            else:
                return jsonify({
                    'success': False,
                    'error': f'Webhook returned status {response.status_code}: {response.text}'
                }), 400
                
        except Exception as e:
            print(f"[API] Error testing webhook: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
