    @app.route('/api/trades/clear-stale', methods=['POST'])
    @login_required
    def api_clear_stale_trades():
        """Clear stale trades for a specific broker - useful when switching API keys"""
        try:
            data = request.json or {}
            broker = data.get('broker', '').strip().upper()
            
            if not broker:
                return jsonify({'success': False, 'error': 'Broker name is required'}), 400
            
            conn = db.get_connection()
            cursor = conn.cursor()
            
            broker_like_map = {
                'ALPACA': '%ALPACA%',
                'WEBULL': '%Webull%',
                'SCHWAB': '%SCHWAB%',
                'IBKR': '%IBKR%',
                'TASTYTRADE': '%TASTYTRADE%',
                'ROBINHOOD': '%ROBINHOOD%',
                'QUESTRADE': '%QUESTRADE%',
                'DHAN': '%DHAN%',
                'UPSTOX': '%UPSTOX%',
                'ZERODHA': '%ZERODHA%',
                'TRADING212': '%TRADING212%',
            }
            
            like_pattern = None
            for key, pattern in broker_like_map.items():
                if key in broker:
                    like_pattern = pattern
                    break
            
            if like_pattern:
                cursor.execute("""
                    UPDATE trades 
                    SET status = 'CLOSED', 
                        close_reason = 'ACCOUNT_RESET',
                        closed_at = datetime('now')
                    WHERE UPPER(broker) LIKE UPPER(?) 
                    AND status IN ('OPEN', 'PENDING')
                """, (like_pattern,))
            else:
                cursor.execute("""
                    UPDATE trades 
                    SET status = 'CLOSED', 
                        close_reason = 'ACCOUNT_RESET',
                        closed_at = datetime('now')
                    WHERE UPPER(broker) = ? 
                    AND status IN ('OPEN', 'PENDING')
                """, (broker,))
            
            affected = cursor.rowcount
            conn.commit()
            conn.close()
            
            print(f"[API] ✓ Cleared {affected} stale {broker} trades (marked as CLOSED with ACCOUNT_RESET)")
            
            return jsonify({
                'success': True, 
                'message': f'Cleared {affected} stale {broker} trades',
                'trades_closed': affected
            })
            
        except Exception as e:
            print(f"[API] Error clearing stale trades: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/trades/stale-count', methods=['GET'])
    def api_get_stale_count():
        """Get count of open/pending trades by broker - for showing in settings"""
        try:
            conn = db.get_connection()
            cursor = conn.cursor()
            
            cursor.execute("""
                SELECT 
                    CASE 
                        WHEN UPPER(broker) LIKE '%ALPACA%' THEN 'ALPACA'
                        WHEN UPPER(broker) LIKE '%WEBULL%' THEN 'WEBULL'
                        WHEN UPPER(broker) LIKE '%SCHWAB%' THEN 'SCHWAB'
                        WHEN UPPER(broker) LIKE '%IBKR%' OR UPPER(broker) LIKE '%INTERACTIVE%' THEN 'IBKR'
                        WHEN UPPER(broker) LIKE '%TASTYTRADE%' OR UPPER(broker) LIKE '%TASTY%' THEN 'TASTYTRADE'
                        WHEN UPPER(broker) LIKE '%ROBINHOOD%' THEN 'ROBINHOOD'
                        WHEN UPPER(broker) LIKE '%QUESTRADE%' THEN 'QUESTRADE'
                        WHEN UPPER(broker) LIKE '%DHAN%' THEN 'DHAN'
                        WHEN UPPER(broker) LIKE '%UPSTOX%' THEN 'UPSTOX'
                        WHEN UPPER(broker) LIKE '%ZERODHA%' THEN 'ZERODHA'
                        WHEN UPPER(broker) LIKE '%TRADING212%' THEN 'TRADING212'
                        ELSE UPPER(broker)
                    END as broker_group,
                    COUNT(*) as count
                FROM trades 
                WHERE status IN ('OPEN', 'PENDING')
                GROUP BY broker_group
            """)
            
            counts = {}
            for row in cursor.fetchall():
                counts[row[0]] = row[1]
            
            conn.close()
            
            return jsonify({
                'success': True,
                'counts': counts,
                'total': sum(counts.values())
            })
            
        except Exception as e:
            print(f"[API] Error getting stale count: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
