    @app.route('/api/options/order', methods=['POST'])
    def api_place_option_order():
        """Place an option order (buy call/put) - routes to selected broker"""
        try:
            data = request.json
            symbol = data.get('symbol', '').upper()
            strike = float(data.get('strike', 0))
            expiry = data.get('expiry', '')
            option_type = data.get('option_type', '').upper()  # CALL or PUT
            quantity = int(data.get('quantity', 1))
            side = data.get('side', 'BUY').upper()  # BUY or SELL
            price = float(data.get('price', 0))
            option_id = data.get('option_id', '')  # REQUIRED: Webull option contract ID
            selected_broker = data.get('broker', 'WEBULL').upper()  # Broker selection
            tracking_channel_id = data.get('tracking_channel_id')  # Optional: Custom channel for tracking
            
            # Validate inputs - option_id only required for Webull
            if not all([symbol, strike, expiry, option_type, price]):
                return jsonify({'error': 'Missing required fields (symbol, strike, expiry, option_type, price)'}), 400
            
            # Webull requires option_id, other brokers don't
            if selected_broker in ['WEBULL'] and not option_id:
                return jsonify({'error': 'Missing option_id (required for Webull)'}), 400
            
            if option_type not in ['CALL', 'PUT']:
                return jsonify({'error': 'option_type must be CALL or PUT'}), 400
            
            if side not in ['BUY', 'SELL']:
                return jsonify({'error': 'side must be BUY or SELL'}), 400
            
            if quantity <= 0:
                return jsonify({'error': 'quantity must be positive'}), 400
            
            # Get bot instance
            if not _bot_instance:
                return jsonify({'error': 'Bot not initialized'}), 503
            
            # Route to appropriate broker based on selection
            broker_to_use = None
            broker_name = selected_broker
            
            if selected_broker == 'WEBULL':
                if hasattr(_bot_instance, 'broker') and _bot_instance.broker:
                    broker_to_use = _bot_instance.broker
                else:
                    return jsonify({'error': 'Webull LIVE broker not connected'}), 503
                    
            elif selected_broker == 'WEBULL_PAPER':
                return jsonify({'error': 'Webull PAPER trading is disabled'}), 503
                
            elif selected_broker == 'ALPACA':
                return jsonify({'error': 'Alpaca LIVE not configured. Use Alpaca PAPER for testing.'}), 400
                
            elif selected_broker == 'ALPACA_PAPER':
                if hasattr(_bot_instance, 'paper_broker') and _bot_instance.paper_broker:
                    broker_to_use = _bot_instance.paper_broker
                else:
                    return jsonify({'error': 'Alpaca PAPER broker not connected'}), 503
                    
            elif selected_broker == 'IBKR':
                return jsonify({'error': 'IBKR LIVE requires TWS connection. Please ensure TWS is running.'}), 400
                
            elif selected_broker == 'IBKR_PAPER':
                return jsonify({'error': 'IBKR PAPER requires TWS Paper Trading connection. Please ensure TWS Paper is running.'}), 400
            
            elif selected_broker in ['TASTYTRADE_LIVE', 'TASTYTRADE']:
                if hasattr(_bot_instance, 'tastytrade_broker') and _bot_instance.tastytrade_broker:
                    broker_to_use = _bot_instance.tastytrade_broker
                    broker_name = 'TASTYTRADE_LIVE'
                else:
                    return jsonify({'error': 'Tastytrade LIVE broker not connected'}), 503
            
            elif selected_broker == 'TASTYTRADE_PAPER':
                if hasattr(_bot_instance, 'tastytrade_paper_broker') and _bot_instance.tastytrade_paper_broker:
                    broker_to_use = _bot_instance.tastytrade_paper_broker
                    broker_name = 'TASTYTRADE_PAPER'
                else:
                    return jsonify({'error': 'Tastytrade PAPER broker not connected'}), 503
            
            elif selected_broker == 'SCHWAB':
                if hasattr(_bot_instance, 'schwab_broker') and _bot_instance.schwab_broker:
                    broker_to_use = _bot_instance.schwab_broker
                    broker_name = 'SCHWAB'
                else:
                    return jsonify({'error': 'Schwab broker not connected'}), 503
            
            elif selected_broker == 'ROBINHOOD':
                if hasattr(_bot_instance, 'robinhood_broker') and _bot_instance.robinhood_broker:
                    broker_to_use = _bot_instance.robinhood_broker
                    broker_name = 'ROBINHOOD'
                else:
                    return jsonify({'error': 'Robinhood broker not connected'}), 503
            
            elif selected_broker == 'IBKR':
                if hasattr(_bot_instance, 'ibkr_broker') and _bot_instance.ibkr_broker:
                    broker_to_use = _bot_instance.ibkr_broker
                    broker_name = 'IBKR'
                else:
                    return jsonify({'error': 'IBKR broker not connected. Ensure TWS is running.'}), 503
                
            else:
                return jsonify({'error': f'Unknown broker: {selected_broker}'}), 400
            
            print(f"[OPTIONS API] Routing order to {broker_name}: {side} {quantity} {symbol} ${strike}{option_type[0]} @ ${price}")
            
            # Place option order
            loop = asyncio.new_event_loop()
            asyncio.set_event_loop(loop)
            try:
                action_code = "BTO" if side == "BUY" else "STC"
                
                if broker_name in ['TASTYTRADE_LIVE', 'TASTYTRADE_PAPER', 'SCHWAB', 'ROBINHOOD', 'IBKR']:
                    result = loop.run_until_complete(
                        broker_to_use.place_option_order(
                            symbol=symbol,
                            strike=strike,
                            expiry=expiry,
                            option_type=option_type,
                            action=action_code,
                            quantity=quantity,
                            price=price
                        )
                    )
                elif hasattr(broker_to_use, 'place_option_order_simple'):
                    result = loop.run_until_complete(
                        broker_to_use.place_option_order_simple(
                            symbol=symbol,
                            strike=strike,
                            expiry=expiry,
                            option_type=option_type,
                            quantity=quantity,
                            side=side,
                            price=price,
                            option_id=option_id
                        )
                    )
                else:
                    result = loop.run_until_complete(
                        broker_to_use.place_option_order(
                            symbol=symbol,
                            strike=strike,
                            expiry=expiry,
                            option_type=option_type,
                            action=action_code,
                            quantity=quantity,
                            price=price
                        )
                    )
                
                # Debug: Print the actual result from Webull
                print(f"[DEBUG] Order result type: {type(result)}")
                print(f"[DEBUG] Order result: {result}")
                
                # Handle OrderResult object (from Alpaca) - convert to dict format
                from broker_interface import OrderResult
                if isinstance(result, OrderResult):
                    # Convert OrderResult to dict for uniform handling
                    result = {
                        'success': result.success,
                        'order_id': result.order_id,
                        'message': result.message,
                        'price': result.price,
                        'quantity': result.quantity,
                        'symbol': result.symbol,
                        'action': result.action
                    }
                    print(f"[DEBUG] Converted OrderResult to dict: {result}")
                
                # result is a dict, not an object
                if isinstance(result, dict):
                    # Check for success - Webull might use different field names
                    is_success = result.get('success', False)
                    
                    # If no 'success' field, check if there's an order ID or other success indicators
                    if 'success' not in result:
                        # Check for Webull success indicators
                        if 'orderId' in result or 'clientOrderId' in result:
                            is_success = True
                        # Check for error indicators
                        elif 'error' in result or 'msg' in result:
                            is_success = False
                    
                    print(f"[DEBUG] Interpreted success: {is_success}")
                    
                    if is_success:
                        action = "BTO" if side == "BUY" else "STC"
                        order_id = result.get('orderId') or result.get('clientOrderId') or result.get('order_id', 'UNKNOWN')
                        
                        # Get logged-in user ID for performance tracking
                        user_id = session.get('user_id')
                        
                        # Get risk settings from request (if provided)
                        stop_loss_pct = data.get('stop_loss_pct')
                        profit_target_pct = data.get('profit_target_pct')
                        trailing_stop_pct = data.get('trailing_stop_pct')
                        enable_risk_management = data.get('enable_risk_management', False)
                        
                        # Calculate stop/target prices if risk management enabled
                        stop_loss_price = None
                        profit_target_price = None
                        if enable_risk_management and price > 0:
                            if stop_loss_pct:
                                stop_loss_price = round(price * (1 - float(stop_loss_pct) / 100), 2)
                            if profit_target_pct:
                                profit_target_price = round(price * (1 + float(profit_target_pct) / 100), 2)
                        
                        # ====== TRACK TRADE IN DATABASE FOR PNL/LEADERBOARD ======
                        try:
                            from datetime import datetime
                            from gui_app.lot_matcher import get_matcher
                            
                            # Use custom tracking channel or fall back to GUI_EXEC
                            tracking_discord_id = None
                            tracking_db_channel_id = None
                            
                            if tracking_channel_id:
                                # User specified a custom tracking channel
                                channel_info = db.get_channel_by_id(int(tracking_channel_id))
                                if channel_info:
                                    tracking_discord_id = channel_info.get('discord_channel_id', f'GUI_CHANNEL_{tracking_channel_id}')
                                    tracking_db_channel_id = int(tracking_channel_id)
                                    print(f"[OPTIONS API] Using custom tracking channel: {channel_info.get('name', tracking_channel_id)}")
                                else:
                                    print(f"[OPTIONS API] Warning: Channel {tracking_channel_id} not found, using GUI_EXEC")
                            
                            # Fall back to GUI_EXEC if no custom channel
                            if not tracking_db_channel_id:
                                tracking_db_channel_id = db.get_gui_exec_channel_id()
                                tracking_discord_id = 'GUI_EXEC'
                            
                            if not tracking_db_channel_id:
                                print("[OPTIONS API] Warning: No tracking channel found, trade won't be tracked")
                            else:
                                # Generate a unique message ID for tracking
                                msg_id = f"GUI_{datetime.now().strftime('%Y%m%d%H%M%S')}_{order_id}"
                                
                                # Save signal to database
                                db.add_signal(
                                    discord_channel_id=tracking_discord_id,
                                    message_id=msg_id,
                                    signal_type=action,
                                    symbol=symbol,
                                    quantity=quantity,
                                    price=price,
                                    asset_type='option',
                                    author_name=session.get('username', 'GUI User'),
                                    strike=strike,
                                    expiry=expiry,
                                    call_put=option_type[0]  # 'C' or 'P'
                                )
                                
                                trade_data = {
                                    'channel_id': tracking_discord_id,
                                    'message_id': msg_id,
                                    'direction': action,
                                    'asset_type': 'option',
                                    'symbol': symbol,
                                    'strike': strike,
                                    'expiry': expiry,
                                    'call_put': option_type[0],
                                    'quantity': quantity,
                                    'intended_price': price,
                                    'executed_price': price,
                                    'executed': True,
                                    'status': 'OPEN',
                                    'broker': broker_name,
                                    'order_id': str(order_id),
                                    'stop_loss_price': stop_loss_price,
                                    'profit_target_price': profit_target_price,
                                    'user_id': user_id,
                                    'source': 'gui'
                                }
                                trade_id = db.add_trade(trade_data)
                                print(f"[OPTIONS API] ✓ Trade #{trade_id} saved as OPEN for tracking in channel {tracking_discord_id}")
                                
                                try:
                                    from src.risk.position_monitor import request_settings_invalidation
                                    if request_settings_invalidation():
                                        print(f"[OPTIONS API] ✓ Risk engine notified of new position")
                                    else:
                                        print(f"[OPTIONS API] Risk engine not available yet")
                                except Exception as risk_err:
                                    print(f"[OPTIONS API] Risk notification error: {risk_err}")
                                
                                # Process through lot_matcher for PNL tracking
                                matcher = get_matcher()
                                lot_signal = {
                                    'action': action,
                                    'symbol': symbol,
                                    'asset': 'option',
                                    'qty': quantity,
                                    'price': price,
                                    'strike': strike,
                                    'expiry': expiry,
                                    'opt_type': option_type[0],
                                    'channel_id': tracking_discord_id,
                                    'db_channel_id': tracking_db_channel_id,
                                    'received_at': datetime.now(),
                                    'author_name': session.get('username', 'GUI User'),
                                    'user_id': user_id
                                }
                                lot_result = matcher.process_signal(lot_signal)
                                if lot_result:
                                    if action == 'BTO':
                                        print(f"[OPTIONS API] ✓ Created lot #{lot_result[0]} for position tracking")
                                    else:
                                        print(f"[OPTIONS API] ✓ Closed {len(lot_result)} lot(s) for PNL calculation")
                                
                        except Exception as track_err:
                            print(f"[OPTIONS API] ⚠️ Trade tracking error: {track_err}")
                            import traceback
                            traceback.print_exc()
                        
                        # Send Discord notification for successful order
                        try:
                            from gui_app.discord_notifier import send_bto_notification, send_stc_notification
                            
                            if action == "BTO":
                                send_bto_notification(
                                    symbol=symbol,
                                    quantity=quantity,
                                    price=price,
                                    strike=strike,
                                    expiry=expiry,
                                    call_put=option_type
                                )
                            elif action == "STC":
                                send_stc_notification(
                                    symbol=symbol,
                                    quantity=quantity,
                                    price=price,
                                    entry_price=0.0,
                                    strike=strike,
                                    expiry=expiry,
                                    call_put=option_type
                                )
                        except Exception as e:
                            print(f"[NOTIFICATION] Failed to send Discord notification: {e}")
                        
                        # Server-side webhook send for tracking channel (correct strike/price guaranteed)
                        webhook_sent = False
                        if tracking_channel_id:
                            try:
                                import requests as http_requests
                                from . import webhook_service
                                wh_channel = webhook_service.get_webhook_channel(int(tracking_channel_id))
                                if wh_channel and wh_channel.get('webhook_url'):
                                    strike_d = f"{int(strike)}" if strike == int(strike) else f"{strike:.2f}"
                                    expiry_fmt = expiry
                                    if expiry and '-' in expiry:
                                        parts = expiry.split('-')
                                        if len(parts) == 3:
                                            expiry_fmt = f"{parts[1]}/{parts[2]}"
                                    signal_msg = f"{action} {quantity} {symbol} {strike_d}{option_type[0].lower()} {expiry_fmt} @ {price:.2f}"
                                    _qt_bot_name = wh_channel.get('bot_name', '')
                                    wh_payload = {"content": signal_msg}
                                    if _qt_bot_name:
                                        wh_payload["username"] = _qt_bot_name
                                    wh_resp = http_requests.post(wh_channel['webhook_url'], json=wh_payload, timeout=5)
                                    if wh_resp.status_code in [200, 204]:
                                        webhook_sent = True
                                        print(f"[OPTIONS API] ✓ Server-side webhook sent: {signal_msg}")
                                    else:
                                        print(f"[OPTIONS API] Webhook send failed: {wh_resp.status_code}")
                            except Exception as wh_err:
                                print(f"[OPTIONS API] Webhook send error: {wh_err}")
                        
                        return jsonify({
                            'success': True,
                            'order_id': order_id,
                            'trade_id': trade_id if 'trade_id' in dir() else None,
                            'broker': broker_name,
                            'order_status': 'PENDING',
                            'webhook_sent': webhook_sent,
                            'message': f'Order submitted to {broker_name}: {side} {quantity} {symbol} ${strike}{option_type[0]} — pending fill',
                            'tracked': tracking_db_channel_id is not None if 'tracking_db_channel_id' in dir() else False,
                            'tracking_channel': tracking_discord_id if 'tracking_discord_id' in dir() else None,
                            'risk_management': {
                                'enabled': enable_risk_management,
                                'stop_loss_price': stop_loss_price,
                                'profit_target_price': profit_target_price
                            } if enable_risk_management else None,
                            'details': {
                                'symbol': symbol,
                                'strike': strike,
                                'expiry': expiry,
                                'option_type': option_type,
                                'quantity': quantity,
                                'side': side,
                                'price': price,
                                'option_id': option_id,
                                'broker': broker_name
                            },
                            'raw_response': result  # Include full response for debugging
                        })
                    else:
                        error_msg = result.get('msg') or result.get('error') or result.get('message') or 'Order placement failed'
                        print(f"[ERROR] Order failed: {error_msg}")
                        return jsonify({
                            'success': False,
                            'error': error_msg,
                            'raw_response': result
                        }), 400
                else:
                    # Unexpected response type
                    print(f"[ERROR] Unexpected result type: {type(result)}")
                    return jsonify({
                        'success': False,
                        'error': f'Unexpected response type: {type(result)}'
                    }), 500
                    
            finally:
                loop.close()
                
        except Exception as e:
            print(f"[API] Error placing option order: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    # ============ ENHANCED PNL TRACKING & LEADERBOARD ============

    def _compute_exec_speed(row):
        """Compute execution speed as signal_detected → order_submitted (bot reaction time).
        Falls back to pending_order_metadata timestamps when execution_lots is missing.
        Only falls back to latency_total_ms - latency_broker_ms as last resort.
        Caps at 30s — anything higher is corrupted data, not real bot latency."""
        _MAX_SPEED_MS = 30000
        from datetime import datetime as _dt
        def _get(key):
            try:
                return row[key]
            except (IndexError, KeyError):
                return None
        detected = _get('el_detected_at') or _get('pm_detected_at')
        submitted = _get('el_submitted_at') or _get('pm_submitted_at')
        if detected and submitted:
            try:
                d = _dt.fromisoformat(str(detected).replace('Z', '+00:00'))
                s = _dt.fromisoformat(str(submitted).replace('Z', '+00:00'))
                ms = int((s - d).total_seconds() * 1000)
                if 0 <= ms <= _MAX_SPEED_MS:
                    return ms
            except Exception:
                pass
        total = _get('latency_total_ms')
        broker = _get('latency_broker_ms')
        if total and broker and total > broker:
            val = total - broker
            if 0 < val <= _MAX_SPEED_MS:
                return val
        parse = _get('latency_parse_ms')
        if parse and 0 < parse <= _MAX_SPEED_MS:
            return parse
        if total and 0 < total <= _MAX_SPEED_MS:
            return total
        return None

    @app.route('/api/pnl/detailed', methods=['GET'])
    def api_get_detailed_pnl():
        """
        Get detailed PNL breakdown showing:
        - Individual STC closures with PNL and PNL%
        - Grouped by position (BTO → multiple STCs)
        - User attribution
        - Aggregate P/L per position
        
        Query params:
            - channel_id: Filter by channel
            - author: Filter by author/user name
            - status: Filter by position status (OPEN, PARTIAL, CLOSED)
            - start_date: Filter positions opened on or after this date (YYYY-MM-DD)
            - end_date: Filter positions opened on or before this date (YYYY-MM-DD)
            - market: Filter by market ('US' or 'INDIA')
            - page: Page number for pagination (default: 1)
            - per_page: Items per page (default: 100, max: 500)
        """
        channel_id = request.args.get('channel_id', type=int)
        author_filter = request.args.get('author', '').strip()
        status_filter = request.args.get('status', '').strip().upper()
        start_date = request.args.get('start_date', '').strip()
        end_date = request.args.get('end_date', '').strip()
        market = request.args.get('market', 'US').strip().upper()
        page = request.args.get('page', 1, type=int)
        per_page = min(request.args.get('per_page', 100, type=int), 500)
        
        try:
            conn = db.get_connection()
            cursor = conn.cursor()
            
            # Query to get all positions with their closures
            query = '''
                SELECT 
                    sl.id as lot_id,
                    sl.symbol,
                    sl.executed_symbol,
                    sl.executed_strike,
                    sl.asset_type,
                    sl.strike,
                    sl.expiry,
                    sl.call_put,
                    sl.original_qty,
                    sl.open_price,
                    sl.opened_at,
                    sl.author_name,
                    sl.status,
                    sl.entry_fill_price,
                    sl.entry_fill_broker,
                    sl.entry_filled_at,
                    
                    -- Closure details
                    lc.id as closure_id,
                    lc.closed_qty,
                    lc.close_price,
                    lc.closed_at,
                    lc.pnl,
                    lc.pnl_percent,
                    lc.holding_days,
                    lc.exit_reason,
                    lc.exit_fill_price,
                    lc.exit_fill_broker,
                    lc.exit_filled_at,
                    lc.exit_source,
                    
                    -- Channel info
                    c.name as channel_name,
                    c.discord_channel_id,

                    -- Latency (from first execution_lot for this signal)
                    (SELECT el2.latency_total_ms FROM execution_lots el2 WHERE el2.signal_lot_id = sl.id ORDER BY el2.order_filled_at ASC LIMIT 1) as latency_total_ms,
                    (SELECT el2.latency_parse_ms FROM execution_lots el2 WHERE el2.signal_lot_id = sl.id ORDER BY el2.order_filled_at ASC LIMIT 1) as latency_parse_ms,
                    (SELECT el2.latency_broker_ms FROM execution_lots el2 WHERE el2.signal_lot_id = sl.id ORDER BY el2.order_filled_at ASC LIMIT 1) as latency_broker_ms,
                    -- Execution speed: signal_detected → order_submitted (from execution_lots or pending_order_metadata fallback)
                    (SELECT el2.signal_detected_at FROM execution_lots el2 WHERE el2.signal_lot_id = sl.id ORDER BY el2.order_filled_at ASC LIMIT 1) as el_detected_at,
                    (SELECT el2.order_submitted_at FROM execution_lots el2 WHERE el2.signal_lot_id = sl.id ORDER BY el2.order_filled_at ASC LIMIT 1) as el_submitted_at,
                    -- Fallback timestamps from pending_order_metadata when no execution_lot exists
                    (SELECT pm.signal_detected_at FROM pending_order_metadata pm WHERE pm.signal_lot_id = sl.id AND pm.action IN ('BTO','BUY') ORDER BY pm.id ASC LIMIT 1) as pm_detected_at,
                    (SELECT pm.order_submitted_at FROM pending_order_metadata pm WHERE pm.signal_lot_id = sl.id AND pm.action IN ('BTO','BUY') ORDER BY pm.id ASC LIMIT 1) as pm_submitted_at

                FROM signal_lots sl
                LEFT JOIN lot_closures lc ON sl.id = lc.lot_id
                LEFT JOIN channels c ON sl.channel_id = c.id
                LEFT JOIN signals s ON sl.signal_id = s.id
                WHERE 1=1
            '''
            
            params = []
            
            # Market filter (filter via signals.market column)
            if market and market in ('US', 'INDIA'):
                query += ' AND COALESCE(s.market, \'US\') = ?'
                params.append(market)
            
            if channel_id:
                query += ' AND sl.channel_id = ?'
                params.append(channel_id)
            
            if author_filter:
                query += ' AND sl.author_name = ?'
                params.append(author_filter)
            
            if status_filter in ('OPEN', 'PARTIAL', 'CLOSED'):
                query += ' AND sl.status = ?'
                params.append(status_filter)
            
            # Date range filtering
            if start_date:
                query += ' AND DATE(sl.opened_at) >= ?'
                params.append(start_date)
            
            if end_date:
                query += ' AND DATE(sl.opened_at) <= ?'
                params.append(end_date)
            
            query += ' ORDER BY sl.opened_at DESC, lc.closed_at ASC'
            
            cursor.execute(query, params)
            rows = cursor.fetchall()
            
            # Group by position (lot_id)
            positions = {}
            for row in rows:
                lot_id = row['lot_id']
                
                if lot_id not in positions:
                    # Create position entry - use executed_symbol if available (for NDX→QQQ conversions)
                    display_symbol = row['executed_symbol'] or row['symbol']
                    display_strike = row['executed_strike'] or row['strike']
                    option_desc = ''
                    if row['asset_type'] == 'option':
                        option_desc = f" {display_strike}{row['call_put']} {row['expiry']}"
                    
                    entry_fill = row['entry_fill_price']
                    positions[lot_id] = {
                        'lot_id': lot_id,
                        'symbol': display_symbol,
                        'original_symbol': row['symbol'] if row['executed_symbol'] else None,
                        'asset_type': row['asset_type'],
                        'description': f"{display_symbol}{option_desc}",
                        'strike': display_strike,
                        'expiry': row['expiry'],
                        'call_put': row['call_put'],
                        'bto_qty': row['original_qty'],
                        'entry_price': entry_fill if entry_fill is not None else row['open_price'],
                        'signal_entry_price': row['open_price'],
                        'entry_fill_price': entry_fill,
                        'entry_fill_broker': row['entry_fill_broker'],
                        'entry_filled_at': row['entry_filled_at'],
                        'has_fill_data': entry_fill is not None,
                        'opened_at': row['opened_at'],
                        'author': row['author_name'] or 'Unknown',
                        'status': row['status'],
                        'channel_name': row['channel_name'],
                        'latency_ms': _compute_exec_speed(row),
                        'latency_total_ms': row['latency_total_ms'],
                        'latency_parse_ms': row['latency_parse_ms'],
                        'latency_broker_ms': row['latency_broker_ms'],
                        'closures': [],
                        'total_closed_qty': 0,
                        'remaining_qty': 0,
                        'total_pnl': 0,
                        'avg_pnl_percent': 0,
                        'total_holding_days': 0
                    }
                
                # Add closure if exists
                if row['closure_id']:
                    exit_fill = row['exit_fill_price']
                    positions[lot_id]['closures'].append({
                        'closure_id': row['closure_id'],
                        'stc_qty': row['closed_qty'],
                        'exit_price': exit_fill if exit_fill is not None else row['close_price'],
                        'signal_exit_price': row['close_price'],
                        'exit_fill_price': exit_fill,
                        'exit_fill_broker': row['exit_fill_broker'],
                        'exit_filled_at': row['exit_filled_at'],
                        'exit_source': row['exit_source'],
                        'has_fill_data': exit_fill is not None,
                        'closed_at': row['closed_at'],
                        'pnl': row['pnl'],
                        'pnl_percent': row['pnl_percent'],
                        'holding_days': row['holding_days'],
                        'exit_reason': row['exit_reason'] or row['exit_source']
                    })
                    positions[lot_id]['total_closed_qty'] += row['closed_qty']
                    positions[lot_id]['total_pnl'] += row['pnl']
                    positions[lot_id]['total_holding_days'] = row['holding_days']  # Latest holding days
            
            # Calculate aggregates
            for lot_id, pos in positions.items():
                pos['remaining_qty'] = pos['bto_qty'] - pos['total_closed_qty']
                if pos['closures']:
                    # Weighted average PNL%
                    total_pnl_weighted = sum(c['pnl_percent'] * c['stc_qty'] for c in pos['closures'])
                    pos['avg_pnl_percent'] = total_pnl_weighted / pos['total_closed_qty'] if pos['total_closed_qty'] > 0 else 0
            
            positions_list = list(positions.values())
            positions_list.sort(key=lambda x: x['opened_at'], reverse=True)
            
            total_positions = len(positions_list)
            total_pages = max(1, (total_positions + per_page - 1) // per_page)
            page = max(1, min(page, total_pages))
            start_idx = (page - 1) * per_page
            end_idx = start_idx + per_page
            paginated = positions_list[start_idx:end_idx]
            
            return jsonify({
                'success': True,
                'positions': paginated,
                'total_positions': total_positions,
                'page': page,
                'per_page': per_page,
                'total_pages': total_pages,
                'has_next': page < total_pages,
                'has_prev': page > 1
            })
            
        except Exception as e:
            print(f"[API] Error getting detailed PNL: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/pnl/users', methods=['GET'])
    def api_get_pnl_users():
        """
        Get unique list of users/authors from PNL data for filtering.
        """
        try:
            conn = db.get_connection()
            cursor = conn.cursor()
            
            cursor.execute('''
                SELECT DISTINCT author_name 
                FROM signal_lots 
                WHERE author_name IS NOT NULL AND author_name != ''
                ORDER BY author_name ASC
            ''')
            
            users = [row['author_name'] for row in cursor.fetchall()]
            
            return jsonify({
                'success': True,
                'users': users
            })
            
        except Exception as e:
            print(f"[API] Error getting PNL users: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/leaderboard/users', methods=['GET'])
    def api_get_user_leaderboard():
        """
        Get user performance leaderboard with Trader Quality Score (TQS) ranking.
        
        TQS Formula: (0.40 × Normalized PNL) + (0.25 × Profit Factor) + (0.20 × Win Rate) + (0.15 × Avg %PNL)
        
        Query params:
            - channel_id: Optional channel filter
            - period: 'today', '7d', '30d', 'year', 'all', or 'custom'
            - start_date: For custom period (YYYY-MM-DD)
            - end_date: For custom period (YYYY-MM-DD)
            - market: 'US' or 'INDIA' for market-specific filtering
        """
        channel_id = request.args.get('channel_id', type=int)
        time_period = request.args.get('period', 'all')
        start_date = request.args.get('start_date')
        end_date = request.args.get('end_date')
        market = request.args.get('market', 'US').strip().upper()
        
        try:
            conn = db.get_connection()
            cursor = conn.cursor()
            
            # Get date bounds based on period (filters by close_date)
            date_start, date_end = db.get_date_filter_bounds(time_period, start_date, end_date)
            
            # Build date filter SQL
            date_filter = ""
            date_params = []
            if date_start and date_end:
                date_filter = "AND lc.closed_at >= ? AND lc.closed_at <= ?"
                date_params = [date_start, date_end]
            
            # Build market filter using channels.market directly
            market_filter = ""
            if market and market in ('US', 'INDIA'):
                market_filter = "AND COALESCE(c.market, 'US') = ?"

            query = f'''
                SELECT
                    sl.author_name,
                    COUNT(DISTINCT sl.id) as total_positions,
                    SUM(sl.original_qty) as total_contracts,

                    -- Closures stats
                    COUNT(lc.id) as total_closures,
                    SUM(lc.closed_qty) as total_closed_qty,
                    SUM(CASE WHEN lc.pnl > 0 THEN 1 ELSE 0 END) as wins,
                    SUM(CASE WHEN lc.pnl <= 0 THEN 1 ELSE 0 END) as losses,

                    -- P/L stats
                    SUM(lc.pnl) as total_pnl,
                    AVG(lc.pnl) as avg_pnl,
                    MAX(lc.pnl) as best_trade,
                    MIN(lc.pnl) as worst_trade,

                    -- Cost basis: US options multiply by 100, India F&O uses 1× (lot sizing in qty)
                    SUM(sl.open_price * lc.closed_qty *
                        CASE
                            WHEN sl.asset_type = 'option' AND COALESCE(c.market, 'US') = 'US' THEN 100
                            ELSE 1
                        END
                    ) as total_cost_basis,

                    AVG(lc.holding_days) as avg_holding_days,

                    -- Gross profit/loss for TQS calculation
                    SUM(CASE WHEN lc.pnl > 0 THEN lc.pnl ELSE 0 END) as gross_profit,
                    SUM(CASE WHEN lc.pnl < 0 THEN lc.pnl ELSE 0 END) as gross_loss

                FROM signal_lots sl
                JOIN lot_closures lc ON sl.id = lc.lot_id
                JOIN channels c ON CAST(sl.channel_id AS INTEGER) = c.id
                WHERE sl.author_name IS NOT NULL {date_filter} {market_filter}
            '''
            
            params = date_params.copy()
            if market and market in ('US', 'INDIA'):
                params.append(market)
            if channel_id:
                query += ' AND c.id = ?'
                params.append(channel_id)

            query += ' GROUP BY sl.author_name'
            query += ' HAVING COUNT(lc.id) > 0'

            cursor.execute(query, params)
            rows = cursor.fetchall()

            users = []
            for row in rows:
                win_count = row['wins'] or 0
                loss_count = row['losses'] or 0
                total_closures = row['total_closures'] or 0
                win_rate = (win_count / total_closures * 100) if total_closures > 0 else 0
                
                # Calculate weighted average % return based on cost basis
                total_pnl = row['total_pnl'] or 0
                total_cost_basis = row['total_cost_basis'] or 0
                if total_cost_basis > 0:
                    weighted_avg_pnl_percent = (total_pnl / total_cost_basis) * 100
                else:
                    weighted_avg_pnl_percent = 0
                
                users.append({
                    'author': row['author_name'],
                    'total_positions': row['total_positions'],
                    'total_contracts': row['total_contracts'],
                    'total_closures': total_closures,
                    'wins': win_count,
                    'losses': loss_count,
                    'win_rate': round(win_rate, 1),
                    'total_pnl': round(total_pnl, 2),
                    'avg_pnl': round(row['avg_pnl'] or 0, 2),
                    'best_trade': round(row['best_trade'] or 0, 2),
                    'worst_trade': round(row['worst_trade'] or 0, 2),
                    'avg_pnl_percent': round(weighted_avg_pnl_percent, 1),
                    'avg_holding_days': round(row['avg_holding_days'] or 0, 4),
                    'gross_profit': round(row['gross_profit'] or 0, 2),
                    'gross_loss': round(row['gross_loss'] or 0, 2)
                })
            
            # Calculate min/max total_pnl for TQS normalization (handles negative values)
            if users:
                max_total_pnl = max((u['total_pnl'] for u in users), default=0)
                min_total_pnl = min((u['total_pnl'] for u in users), default=0)
            else:
                max_total_pnl = 1
                min_total_pnl = 0
            
            # Calculate TQS score for each user
            for user in users:
                # Calculate profit factor for display (not capped for display)
                if user['gross_loss'] == 0:
                    user['profit_factor'] = 2.0 if user['gross_profit'] > 0 else 0.0
                else:
                    user['profit_factor'] = round(min(user['gross_profit'] / abs(user['gross_loss']), 10.0), 2)
                
                tqs_stats = {
                    'total_pnl': user['total_pnl'],
                    'gross_profit': user['gross_profit'],
                    'gross_loss': user['gross_loss'],
                    'win_trades': user['wins'],
                    'loss_trades': user['losses'],
                    'avg_pct_pnl': user['avg_pnl_percent']
                }
                user['score'] = db.calculate_trader_quality_score(tqs_stats, max_total_pnl, min_total_pnl)
            
            # Sort by TQS score (primary), then total_pnl (secondary)
            users.sort(key=lambda u: (-u['score'], -u['total_pnl']))
            
            # Add rankings based on new sort order
            for i, user in enumerate(users, 1):
                user['rank'] = i
            
            # Calculate aggregates
            total_users = len(users)
            total_wins_all = sum(u['wins'] for u in users)
            total_closures_all = sum(u['total_closures'] for u in users)
            total_pnl_all = sum(u['total_pnl'] for u in users)
            
            avg_win_rate_all = (total_wins_all / total_closures_all * 100) if total_closures_all > 0 else 0
            
            # Direction breakdown per user (Stocks / Calls / Puts)
            dir_query = f'''
                SELECT
                    sl.author_name,
                    CASE
                        WHEN sl.asset_type = 'option' AND sl.call_put = 'C' THEN 'calls'
                        WHEN sl.asset_type = 'option' AND sl.call_put = 'P' THEN 'puts'
                        ELSE 'stocks'
                    END as direction,
                    COUNT(lc.id) as trades,
                    SUM(CASE WHEN lc.pnl > 0 THEN 1 ELSE 0 END) as wins,
                    COALESCE(SUM(lc.pnl), 0) as pnl
                FROM signal_lots sl
                JOIN lot_closures lc ON sl.id = lc.lot_id
                JOIN channels c ON CAST(sl.channel_id AS INTEGER) = c.id
                WHERE sl.author_name IS NOT NULL {date_filter} {market_filter}
                GROUP BY sl.author_name, direction
            '''
            dir_params = date_params.copy()
            if market and market in ('US', 'INDIA'):
                dir_params.append(market)
            cursor.execute(dir_query, dir_params)
            dir_map = {}
            for dr in cursor.fetchall():
                author = dr['author_name']
                if author not in dir_map:
                    dir_map[author] = {}
                t = dr['trades'] or 0
                w = dr['wins'] or 0
                dir_map[author][dr['direction']] = {
                    'trades': t,
                    'wins': w,
                    'losses': t - w,
                    'win_rate': round((w / t * 100) if t > 0 else 0, 1),
                    'pnl': round(float(dr['pnl'] or 0), 2)
                }

            # Rename author to author_name for frontend consistency
            for user in users:
                author_key = user['author']
                user['author_name'] = user.pop('author')
                user['total_trades'] = user['total_closures']
                user['avg_return'] = user['avg_pnl']
                user['direction_breakdown'] = dir_map.get(author_key, {})

            return jsonify({
                'success': True,
                'users': users,
                'total_users': total_users,
                'total_trades': total_closures_all,
                'total_pnl': round(total_pnl_all, 2),
                'avg_win_rate': round(avg_win_rate_all, 1)
            })

        except Exception as e:
            print(f"[API] Error getting user leaderboard: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/leaderboard/enhanced', methods=['GET'])
    def api_get_enhanced_leaderboard():
        """
        Get enhanced channel leaderboard with comprehensive metrics:
        - Win rate, total P/L, avg return
        - Best/worst trades
        - Top performers (users) per channel
        - Recent activity
        
        Query params:
            - market: 'US' or 'INDIA' for market-specific filtering
        """
        try:
            market = request.args.get('market', 'US').strip().upper()
            
            conn = db.get_connection()
            cursor = conn.cursor()
            
            # Build market filter using channels.market directly
            market_filter = ""
            params = []
            if market and market in ('US', 'INDIA'):
                market_filter = "AND COALESCE(c.market, 'US') = ?"
                params.append(market)

            # Get channel performance
            query = f'''
                SELECT
                    c.id as channel_id,
                    c.name as channel_name,
                    c.discord_channel_id,

                    -- Position stats
                    COUNT(DISTINCT sl.id) as total_positions,
                    SUM(sl.original_qty) as total_contracts,
                    COUNT(DISTINCT sl.author_name) as total_users,

                    -- Closure stats
                    COUNT(lc.id) as total_closures,
                    SUM(CASE WHEN lc.pnl > 0 THEN 1 ELSE 0 END) as wins,
                    SUM(CASE WHEN lc.pnl <= 0 THEN 1 ELSE 0 END) as losses,

                    -- P/L stats
                    SUM(lc.pnl) as total_pnl,
                    AVG(lc.pnl) as avg_pnl,
                    MAX(lc.pnl) as best_trade,
                    MIN(lc.pnl) as worst_trade,
                    AVG(lc.pnl_percent) as avg_return,

                    -- Recent activity
                    MAX(lc.closed_at) as last_activity,
                    AVG(lc.holding_days) as avg_holding_days

                FROM channels c
                JOIN signal_lots sl ON CAST(sl.channel_id AS INTEGER) = c.id
                JOIN lot_closures lc ON sl.id = lc.lot_id
                WHERE c.is_active = 1 {market_filter}
                GROUP BY c.id, c.name, c.discord_channel_id
                HAVING COUNT(lc.id) > 0
            '''
            
            cursor.execute(query, params)
            rows = cursor.fetchall()
            
            channels = []
            for row in rows:
                win_count = row['wins'] or 0
                total_closures = row['total_closures'] or 0
                win_rate = (win_count / total_closures * 100) if total_closures > 0 else 0
                
                # Get top user for this channel
                cursor.execute('''
                    SELECT 
                        sl.author_name,
                        SUM(lc.pnl) as user_pnl,
                        COUNT(lc.id) as user_trades
                    FROM signal_lots sl
                    JOIN lot_closures lc ON sl.id = lc.lot_id
                    WHERE sl.channel_id = ? AND sl.author_name IS NOT NULL
                    GROUP BY sl.author_name
                    ORDER BY user_pnl DESC
                    LIMIT 1
                ''', (row['channel_id'],))
                top_user_row = cursor.fetchone()
                top_user = top_user_row['author_name'] if top_user_row else None
                
                channels.append({
                    'channel_id': row['channel_id'],
                    'channel_name': row['channel_name'],
                    'discord_channel_id': row['discord_channel_id'],
                    'total_positions': row['total_positions'],
                    'total_contracts': row['total_contracts'],
                    'total_users': row['total_users'],
                    'total_closures': total_closures,
                    'wins': win_count,
                    'losses': row['losses'] or 0,
                    'win_rate': round(win_rate, 1),
                    'total_pnl': round(row['total_pnl'] or 0, 2),
                    'avg_pnl': round(row['avg_pnl'] or 0, 2),
                    'best_trade': round(row['best_trade'] or 0, 2),
                    'worst_trade': round(row['worst_trade'] or 0, 2),
                    'avg_return': round(row['avg_return'] or 0, 1),
                    'last_activity': row['last_activity'],
                    'avg_holding_days': round(row['avg_holding_days'] or 0, 4),
                    'top_user': top_user
                })
            
            # Sort by total P/L descending
            channels.sort(key=lambda x: x['total_pnl'], reverse=True)
            
            # Add rankings
            for i, channel in enumerate(channels, 1):
                channel['rank'] = i
            
            return jsonify({
                'success': True,
                'channels': channels,
                'total_channels': len(channels)
            })
            
        except Exception as e:
            print(f"[API] Error getting enhanced leaderboard: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500
    
