    @app.route('/api/reset/pnl', methods=['POST'])
    def api_reset_pnl_data():
        """Reset all PNL tracking data (signals, lots, closures)"""
        try:
            import sqlite3
            conn = sqlite3.connect(db.get_db_path(), timeout=30.0)
            cursor = conn.cursor()
            
            # Delete in correct order (foreign key constraints)
            cursor.execute('DELETE FROM lot_closures')
            cursor.execute('DELETE FROM signal_lots')
            cursor.execute('DELETE FROM signals')
            
            conn.commit()
            
            deleted_closures = cursor.rowcount if cursor.rowcount > 0 else 0
            
            conn.close()
            
            print(f"[API] Reset PNL data - cleared all signals, lots, and closures")
            
            return jsonify({
                'success': True,
                'message': 'All PNL tracking data has been reset successfully'
            })
            
        except Exception as e:
            print(f"[API] Error resetting PNL data: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/pnl/purge/by-date', methods=['POST'])
    def api_purge_pnl_by_date():
        """Purge PNL data for a specific date or date range"""
        try:
            import sqlite3
            data = request.json
            start_date = data.get('start_date')  # YYYY-MM-DD
            end_date = data.get('end_date')  # YYYY-MM-DD (optional, defaults to start_date)
            
            if not start_date:
                return jsonify({'error': 'start_date is required'}), 400
            
            if not end_date:
                end_date = start_date
            
            conn = sqlite3.connect(db.get_db_path(), timeout=30.0)
            cursor = conn.cursor()
            
            # Initialize counters
            closures_deleted = 0
            
            # First, get all signal_lots that will be affected
            cursor.execute('''
                SELECT id FROM signal_lots 
                WHERE date(opened_at) BETWEEN ? AND ?
            ''', (start_date, end_date))
            lot_ids = [row[0] for row in cursor.fetchall()]
            
            # Delete lot_closures for those lots
            if lot_ids:
                placeholders = ','.join(['?'] * len(lot_ids))
                cursor.execute(f'''
                    DELETE FROM lot_closures 
                    WHERE lot_id IN ({placeholders})
                ''', lot_ids)
                closures_deleted = cursor.rowcount
            
            # Also delete closures by date (catches any orphaned closures)
            cursor.execute('''
                DELETE FROM lot_closures 
                WHERE date(closed_at) BETWEEN ? AND ?
            ''', (start_date, end_date))
            closures_deleted += cursor.rowcount
            
            # Delete ALL signal_lots for the date range (regardless of status)
            cursor.execute('''
                DELETE FROM signal_lots 
                WHERE date(opened_at) BETWEEN ? AND ?
            ''', (start_date, end_date))
            lots_deleted = cursor.rowcount
            
            # Only delete signals that no longer have any associated lots
            cursor.execute('''
                DELETE FROM signals 
                WHERE date(timestamp) BETWEEN ? AND ?
                AND id NOT IN (SELECT DISTINCT signal_id FROM signal_lots WHERE signal_id IS NOT NULL)
            ''', (start_date, end_date))
            signals_deleted = cursor.rowcount
            
            conn.commit()
            conn.close()
            
            print(f"[API] Purged PNL data for {start_date} to {end_date}: {closures_deleted} closures, {lots_deleted} lots, {signals_deleted} signals")
            
            return jsonify({
                'success': True,
                'message': f'Purged data from {start_date} to {end_date}',
                'deleted': {
                    'closures': closures_deleted,
                    'lots': lots_deleted,
                    'signals': signals_deleted
                }
            })
            
        except Exception as e:
            print(f"[API] Error purging PNL by date: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'error': str(e)}), 500

