    @app.route('/api/brokers/status', methods=['GET'])
    def api_get_broker_status():
        """Get connection status of all brokers - checks actual bot connections"""
        try:
            from .broker_credentials_service import get_all_broker_status, get_enabled_brokers, set_broker_status
            
            # Get stored status as baseline
            status = get_all_broker_status()
            enabled = get_enabled_brokers()
            
            # Check actual connections from bot instance and update status accordingly
            if _bot_instance:
                # Discord connection
                discord_connected = _bot_instance.is_ready() if hasattr(_bot_instance, 'is_ready') else False
                if discord_connected:
                    user_info = str(_bot_instance.user) if hasattr(_bot_instance, 'user') and _bot_instance.user else None
                    set_broker_status('discord', True, 'connected', account_info={'user': user_info})
                    status['discord'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'user': user_info}}
                else:
                    set_broker_status('discord', False, 'disconnected')
                    status['discord'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # Webull Live broker - check if actually logged in AND tokens are valid
                # Check both 'broker' and 'webull_broker' attributes
                webull_broker = getattr(_bot_instance, 'webull_broker', None) or getattr(_bot_instance, 'broker', None)
                # Check if it's actually a Webull broker
                if webull_broker and 'Webull' not in type(webull_broker).__name__:
                    webull_broker = None
                # Use multiple checks - is_authenticated() is strict (requires valid tokens),
                # fall back to _logged_in or connected flags which persist through token refresh cycles
                webull_logged_in = False
                if webull_broker:
                    try:
                        if hasattr(webull_broker, 'is_authenticated'):
                            webull_logged_in = webull_broker.is_authenticated()
                        else:
                            webull_logged_in = getattr(webull_broker, '_logged_in', False)
                    except Exception:
                        webull_logged_in = getattr(webull_broker, '_logged_in', False)
                    if not webull_logged_in and getattr(webull_broker, '_tokens_valid', True) is False:
                        webull_logged_in = False
                
                if webull_logged_in:
                    set_broker_status('webull_live', True, 'connected')
                    status['webull_live'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': None}
                else:
                    error_msg = 'Auth tokens expired' if webull_broker and getattr(webull_broker, '_tokens_valid', True) is False else None
                    set_broker_status('webull_live', False, 'disconnected', error=error_msg)
                    status['webull_live'] = {'connected': False, 'status': 'disconnected', 'error': error_msg, 'account_info': None}
                
                status['webull_paper'] = {'connected': False, 'status': 'disabled', 'error': None, 'account_info': None}
                
                # Paper broker - detect type (Alpaca)
                paper_broker = getattr(_bot_instance, 'paper_broker', None)
                paper_broker_type = type(paper_broker).__name__ if paper_broker else ''
                
                # Alpaca Paper
                if paper_broker and ('Alpaca' in paper_broker_type or 'TradingClient' in paper_broker_type):
                    set_broker_status('alpaca_paper', True, 'connected')
                    status['alpaca_paper'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': None}
                else:
                    status['alpaca_paper'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # Alpaca Live broker
                live_broker = getattr(_bot_instance, 'live_broker', None)
                live_broker_type = type(live_broker).__name__ if live_broker else ''
                if live_broker and ('Alpaca' in live_broker_type or 'TradingClient' in live_broker_type):
                    set_broker_status('alpaca_live', True, 'connected')
                    status['alpaca_live'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': None}
                else:
                    status['alpaca_live'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # IBKR broker - check actual IB connection state
                ibkr_broker = getattr(_bot_instance, 'ibkr_broker', None)
                ibkr_actually_connected = (ibkr_broker 
                    and getattr(ibkr_broker, 'connected', False) 
                    and hasattr(ibkr_broker, 'ib') 
                    and ibkr_broker.ib.isConnected())
                if ibkr_actually_connected:
                    set_broker_status('ibkr_live', True, 'connected')
                    status['ibkr_live'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': None}
                elif ibkr_broker:
                    set_broker_status('ibkr_live', False, 'disconnected', error='TWS connection lost')
                    status['ibkr_live'] = {'connected': False, 'status': 'disconnected', 'error': 'TWS connection lost', 'account_info': None}
                else:
                    status['ibkr_live'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # Robinhood broker (LIVE only - no paper mode)
                rh_broker = getattr(_bot_instance, 'robinhood_broker', None)
                rh_connected = rh_broker and getattr(rh_broker, 'connected', False)
                if rh_connected:
                    set_broker_status('robinhood', True, 'connected')
                    status['robinhood'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['robinhood'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # Tastytrade broker - check if connected property is True
                tastytrade_broker = getattr(_bot_instance, 'tastytrade_broker', None)
                if tastytrade_broker:
                    is_connected = getattr(tastytrade_broker, 'connected', False)
                    is_paper = getattr(tastytrade_broker, 'paper_trade', True)
                    broker_id = 'tastytrade_paper' if is_paper else 'tastytrade_live'
                    if is_connected:
                        set_broker_status(broker_id, True, 'connected')
                        status[broker_id] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'PAPER' if is_paper else 'LIVE'}}
                    else:
                        status[broker_id] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                else:
                    status['tastytrade_live'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                    status['tastytrade_paper'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # India Brokers - Upstox
                upstox_broker = getattr(_bot_instance, 'upstox_broker', None)
                if upstox_broker and getattr(upstox_broker, 'connected', False):
                    status['upstox'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['upstox'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # India Brokers - DhanQ
                dhanq_broker = getattr(_bot_instance, 'dhanq_broker', None)
                if dhanq_broker and getattr(dhanq_broker, 'connected', False):
                    status['dhanq'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['dhanq'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # India Brokers - Zerodha
                zerodha_broker = getattr(_bot_instance, 'zerodha_broker', None)
                if zerodha_broker and getattr(zerodha_broker, 'connected', False):
                    status['zerodha'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['zerodha'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}
                
                # Schwab broker
                schwab_broker = getattr(_bot_instance, 'schwab_broker', None)
                if schwab_broker and getattr(schwab_broker, 'connected', False):
                    set_broker_status('schwab', True, 'connected')
                    status['schwab'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['schwab'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}

                # Webull Official API broker
                wo_broker = getattr(_bot_instance, 'webull_official_broker', None)
                if wo_broker and getattr(wo_broker, 'connected', False):
                    set_broker_status('webull_official', True, 'connected')
                    status['webull_official'] = {'connected': True, 'status': 'connected', 'error': None, 'account_info': {'mode': 'LIVE'}}
                else:
                    status['webull_official'] = {'connected': False, 'status': 'disconnected', 'error': None, 'account_info': None}

            try:
                from src.services.broker_health_monitor import get_health_monitor
                health_monitor = get_health_monitor()
                health_statuses = health_monitor.get_all_broker_statuses()
                
                for broker_key, health_info in health_statuses.items():
                    if not health_info.get('is_connected', False):
                        reason = health_info.get('reason', '')
                        error_code = health_info.get('error_code', '')
                        
                        broker_map = {
                            'WEBULL': 'webull_live',
                            'WEBULL_LIVE': 'webull_live',
                            'WEBULL_OFFICIAL': 'webull_official',
                            'ALPACA_PAPER': 'alpaca_paper',
                            'ALPACA_LIVE': 'alpaca_live',
                            'ROBINHOOD': 'robinhood',
                            'SCHWAB': 'schwab',
                            'IBKR_PAPER': 'ibkr_paper',
                            'IBKR_LIVE': 'ibkr_live',
                            'TASTYTRADE_PAPER': 'tastytrade_paper',
                            'TASTYTRADE_LIVE': 'tastytrade_live',
                            'UPSTOX': 'upstox',
                            'ZERODHA': 'zerodha',
                            'DHANQ': 'dhanq'
                        }
                        
                        status_key = broker_map.get(broker_key.upper())
                        if status_key and status_key in status:
                            status[status_key]['connected'] = False
                            status[status_key]['status'] = 'error'
                            status[status_key]['error'] = reason
                            status[status_key]['error_code'] = error_code
            except Exception as hm_err:
                print(f"[API] Health monitor status merge error: {hm_err}")
            
            return jsonify({
                'success': True,
                'status': status,
                'enabled': enabled
            })
        except Exception as e:
            print(f"[API] Error getting broker status: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
