    @app.route('/api/brokers/credentials/webull', methods=['POST'])
    def api_save_webull_credentials():
        """Save Webull credentials with token validation"""
        try:
            from .broker_credentials_service import save_webull_credentials, get_webull_credentials
            
            data = request.json
            
            existing = get_webull_credentials()
            
            new_email = data.get('email', existing.get('email', ''))
            new_password = data.get('password', existing.get('password', ''))
            
            credentials_changed = (
                new_email != existing.get('email', '') or
                (new_password and new_password != existing.get('password', ''))
            )
            
            if credentials_changed:
                access_token = ''
                refresh_token = ''
                # Clear region data too when credentials change
                zone_id = ''
                rzone = ''
                region_id = ''
                print("[Webull] Credentials changed - clearing old tokens and region data for fresh authentication")
            else:
                access_token = data.get('access_token', existing.get('access_token', ''))
                refresh_token = data.get('refresh_token', existing.get('refresh_token', ''))
                # PRESERVE region metadata from existing credentials (fixes rzone error)
                zone_id = data.get('zone_id', existing.get('zone_id', ''))
                rzone = data.get('rzone', existing.get('rzone', ''))
                region_id = data.get('region_id', existing.get('region_id', ''))
            
            # NOTE: Tokens starting with 'dc_' are standard Webull tokens - this is normal
            # Previous warning was incorrect - dc_ tokens work fine for trading
            
            save_webull_credentials(
                email=new_email,
                password=new_password,
                trade_pin=data.get('trade_pin', existing.get('trade_pin', '')),
                device_id=data.get('device_id', existing.get('device_id', '')),
                access_token=access_token,
                refresh_token=refresh_token,
                paper_mode=data.get('paper_mode', existing.get('paper_mode', True)),
                zone_id=zone_id,
                rzone=rzone,
                region_id=region_id,
                paper_account_enabled=data.get('paper_account_enabled', existing.get('paper_account_enabled', False)),
                account_type=data.get('account_type', existing.get('account_type', 'margin'))
            )
            
            message = 'Webull credentials saved.'
            if credentials_changed:
                message += ' Old tokens cleared - please use Connect button to authenticate with new credentials.'
            else:
                message += ' Use Connect button to connect.'
            
            return jsonify({
                'success': True,
                'message': message,
                'tokens_cleared': credentials_changed
            })
        except Exception as e:
            print(f"[API] Error saving Webull credentials: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
    
