    @app.route('/api/health/full', methods=['GET'])
    @login_required
    def api_system_health():
        """Get comprehensive system health data for user validation"""
        try:
            from .broker_credentials_service import get_all_broker_status
            import configparser
            
            health_data = {
                'timestamp': time.strftime('%Y-%m-%d %H:%M:%S'),
                'core_systems': {},
                'brokers': {},
                'features': {},
                'channels': {},
                'risk_management': {},
                'positions': {},
                'recent_activity': {}
            }
            
            # Core Systems
            bot_connected = bool(_bot_instance and _bot_instance.is_ready())
            bot_user = str(_bot_instance.user) if _bot_instance and hasattr(_bot_instance, 'user') and _bot_instance.user else 'Not connected'
            
            health_data['core_systems'] = {
                'discord_bot': {
                    'status': 'connected' if bot_connected else 'disconnected',
                    'user': bot_user,
                    'ok': bot_connected
                },
                'web_panel': {
                    'status': 'running',
                    'port': int(os.environ.get('GUI_PORT', 5000)),
                    'ok': True
                },
                'order_worker': {
                    'status': 'running' if _bot_instance else 'stopped',
                    'ok': bool(_bot_instance)
                },
                'sync_service': {
                    'status': 'running' if _bot_instance else 'stopped',
                    'ok': bool(_bot_instance)
                }
            }
            
            # Broker Connections - Check actual bot instance for real status
            broker_status = {}
            
            # Check Webull Live
            webull_connected = False
            webull_buying_power = 0
            webull_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'broker') and _bot_instance.broker:
                try:
                    broker = _bot_instance.broker
                    if hasattr(broker, '_client') and broker._client:
                        webull_connected = True
                        try:
                            account = broker._client.get_account()
                            if account:
                                for field in ['settledFunds', 'cashBalance', 'buyingPower', 'dayBuyingPower']:
                                    if field in account:
                                        val = account[field]
                                        if isinstance(val, (int, float)):
                                            webull_buying_power = float(val)
                                            break
                                        elif isinstance(val, str):
                                            try:
                                                webull_buying_power = float(val.replace(',', ''))
                                                break
                                            except:
                                                continue
                            positions = broker._client.get_positions()
                            webull_positions = len(positions) if positions else 0
                        except:
                            pass
                except:
                    pass
            
            broker_status['webull_live'] = {
                'connected': webull_connected,
                'status': 'connected' if webull_connected else 'disconnected',
                'account_type': 'LIVE',
                'buying_power': webull_buying_power,
                'positions': webull_positions
            }
            
            # Check Alpaca Paper
            alpaca_connected = False
            alpaca_buying_power = 0
            alpaca_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'paper_broker') and _bot_instance.paper_broker:
                try:
                    broker = _bot_instance.paper_broker
                    if hasattr(broker, 'trading_client') and broker.trading_client:
                        alpaca_connected = True
                        try:
                            account = broker.trading_client.get_account()
                            if account:
                                alpaca_buying_power = float(account.buying_power)
                            positions = broker.trading_client.get_all_positions()
                            alpaca_positions = len(positions) if positions else 0
                        except:
                            pass
                except:
                    pass
            
            broker_status['alpaca_paper'] = {
                'connected': alpaca_connected,
                'status': 'connected' if alpaca_connected else 'disconnected',
                'account_type': 'PAPER',
                'buying_power': alpaca_buying_power,
                'positions': alpaca_positions
            }
            
            schwab_connected = False
            schwab_buying_power = 0
            schwab_positions = 0
            schwab_token_expiry = None
            if _bot_instance and hasattr(_bot_instance, 'schwab_broker') and _bot_instance.schwab_broker:
                try:
                    broker = _bot_instance.schwab_broker
                    import asyncio
                    loop = getattr(_bot_instance, 'loop', None)
                    if loop and loop.is_running():
                        if hasattr(broker, 'is_authenticated'):
                            try:
                                future = asyncio.run_coroutine_threadsafe(broker.is_authenticated(), loop)
                                schwab_connected = future.result(timeout=5)
                            except:
                                schwab_connected = False
                        if schwab_connected:
                            try:
                                future = asyncio.run_coroutine_threadsafe(broker.get_account_info(), loop)
                                account = future.result(timeout=5)
                                if account:
                                    schwab_buying_power = float(account.get('buying_power', 0) or 0)
                                future = asyncio.run_coroutine_threadsafe(broker.get_positions_detailed(), loop)
                                positions = future.result(timeout=5)
                                schwab_positions = len(positions) if positions else 0
                            except:
                                pass
                    if hasattr(broker, 'token_expiry'):
                        schwab_token_expiry = str(broker.token_expiry) if broker.token_expiry else None
                except:
                    pass
            
            # Use the correct credentials source (same as schwab_auth.py)
            from .schwab_auth import get_schwab_credentials
            schwab_creds = get_schwab_credentials()
            schwab_configured = bool(schwab_creds and schwab_creds.get('client_id') and schwab_creds.get('client_secret'))
            
            broker_status['schwab'] = {
                'connected': schwab_connected,
                'status': 'connected' if schwab_connected else ('configured' if schwab_configured else 'not_configured'),
                'account_type': 'PAPER' if (schwab_creds.get('dry_run', False) if schwab_creds else True) else 'LIVE',
                'buying_power': schwab_buying_power,
                'positions': schwab_positions,
                'token_expiry': schwab_token_expiry,
                'configured': schwab_configured
            }
            
            # Check Robinhood (LIVE ONLY - no paper trading)
            robinhood_connected = False
            robinhood_buying_power = 0
            robinhood_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'robinhood_broker') and _bot_instance.robinhood_broker:
                try:
                    broker = _bot_instance.robinhood_broker
                    import asyncio
                    loop = getattr(_bot_instance, 'loop', None)
                    if loop and loop.is_running():
                        if hasattr(broker, 'is_connected'):
                            try:
                                future = asyncio.run_coroutine_threadsafe(broker.is_connected(), loop)
                                robinhood_connected = future.result(timeout=5)
                            except:
                                robinhood_connected = getattr(broker, '_connected', False)
                        if robinhood_connected:
                            try:
                                future = asyncio.run_coroutine_threadsafe(broker.get_account_info(), loop)
                                account = future.result(timeout=5)
                                if account:
                                    robinhood_buying_power = float(account.get('buying_power', 0) or 0)
                                future = asyncio.run_coroutine_threadsafe(broker.get_positions(), loop)
                                positions = future.result(timeout=5)
                                robinhood_positions = len(positions) if positions else 0
                            except:
                                pass
                except:
                    pass
            
            robinhood_creds = db.get_robinhood_settings() if hasattr(db, 'get_robinhood_settings') else None
            robinhood_configured = bool(robinhood_creds and robinhood_creds.get('username') and robinhood_creds.get('password'))
            
            broker_status['robinhood'] = {
                'connected': robinhood_connected,
                'status': 'connected' if robinhood_connected else ('configured' if robinhood_configured else 'not_configured'),
                'account_type': 'LIVE',  # Robinhood has no paper trading
                'buying_power': robinhood_buying_power,
                'positions': robinhood_positions,
                'configured': robinhood_configured
            }
            
            t212_connected = False
            t212_buying_power = 0
            t212_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'trading212_broker') and _bot_instance.trading212_broker:
                try:
                    broker = _bot_instance.trading212_broker
                    import asyncio
                    loop = getattr(_bot_instance, 'loop', None)
                    t212_connected = getattr(broker, 'connected', False)
                    if not t212_connected and hasattr(broker, 'is_connected'):
                        if loop and loop.is_running():
                            try:
                                future = asyncio.run_coroutine_threadsafe(broker.is_connected(), loop)
                                t212_connected = future.result(timeout=5)
                            except:
                                pass
                    if loop and loop.is_running() and t212_connected:
                        try:
                            future = asyncio.run_coroutine_threadsafe(broker.get_account_info(), loop)
                            account = future.result(timeout=10)
                            if account:
                                t212_buying_power = float(account.get('buying_power', 0) or 0)
                            future = asyncio.run_coroutine_threadsafe(broker.get_positions(), loop)
                            positions = future.result(timeout=10)
                            t212_positions = len(positions) if positions else 0
                        except:
                            cached = getattr(broker, '_account_cache', None)
                            if cached:
                                t212_buying_power = float(cached.get('buying_power', 0) or 0)
                            cached_pos = getattr(broker, '_positions_cache', None)
                            if cached_pos:
                                t212_positions = len(cached_pos)
                except:
                    pass
            
            t212_creds = None
            try:
                from .broker_credentials_service import get_trading212_credentials
                t212_creds = get_trading212_credentials()
                t212_configured = bool(t212_creds and t212_creds.get('api_key'))
            except:
                t212_configured = False
            
            t212_env = t212_creds.get('environment', 'demo').upper() if (t212_configured and t212_creds) else 'DEMO'
            broker_status['trading212'] = {
                'connected': t212_connected,
                'status': 'connected' if t212_connected else ('configured' if t212_configured else 'not_configured'),
                'account_type': 'LIVE' if t212_env == 'LIVE' else 'PAPER',
                'buying_power': t212_buying_power,
                'positions': t212_positions,
                'configured': t212_configured
            }
            
            # Check IBKR
            ibkr_connected = False
            ibkr_buying_power = 0
            ibkr_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'ibkr_broker') and _bot_instance.ibkr_broker:
                try:
                    broker = _bot_instance.ibkr_broker
                    if hasattr(broker, '_connected') and broker._connected:
                        ibkr_connected = True
                        if hasattr(broker, 'get_account_info'):
                            import asyncio
                            loop = getattr(_bot_instance, 'loop', None)
                            if loop and loop.is_running():
                                try:
                                    future = asyncio.run_coroutine_threadsafe(broker.get_account_info(), loop)
                                    account = future.result(timeout=5)
                                    if account:
                                        ibkr_buying_power = float(account.get('buying_power', 0) or 0)
                                except:
                                    pass
                except:
                    pass
            
            ibkr_creds = db.get_ibkr_settings() if hasattr(db, 'get_ibkr_settings') else None
            ibkr_configured = bool(ibkr_creds and ibkr_creds.get('host'))
            
            broker_status['ibkr'] = {
                'connected': ibkr_connected,
                'status': 'connected' if ibkr_connected else ('configured' if ibkr_configured else 'not_configured'),
                'account_type': 'PAPER' if (ibkr_creds and ibkr_creds.get('paper_trading', True)) else 'LIVE',
                'buying_power': ibkr_buying_power,
                'positions': ibkr_positions,
                'configured': ibkr_configured
            }
            
            # Check Tastytrade
            tastytrade_connected = False
            tastytrade_buying_power = 0
            tastytrade_positions = 0
            if _bot_instance and hasattr(_bot_instance, 'tastytrade_broker') and _bot_instance.tastytrade_broker:
                try:
                    broker = _bot_instance.tastytrade_broker
                    if hasattr(broker, '_connected') and broker._connected:
                        tastytrade_connected = True
                        if hasattr(broker, 'get_account_info'):
                            import asyncio
                            loop = getattr(_bot_instance, 'loop', None)
                            if loop and loop.is_running():
                                try:
                                    future = asyncio.run_coroutine_threadsafe(broker.get_account_info(), loop)
                                    account = future.result(timeout=5)
                                    if account:
                                        tastytrade_buying_power = float(account.get('buying_power', 0) or 0)
                                except:
                                    pass
                except:
                    pass
            
            tastytrade_creds = db.get_tastytrade_settings() if hasattr(db, 'get_tastytrade_settings') else None
            if not tastytrade_creds:
                try:
                    from .broker_credentials_service import get_tastytrade_credentials
                    tastytrade_creds = get_tastytrade_credentials()
                except Exception:
                    pass
            tastytrade_configured = bool(tastytrade_creds and tastytrade_creds.get('client_secret') and tastytrade_creds.get('refresh_token'))
            
            broker_status['tastytrade'] = {
                'connected': tastytrade_connected,
                'status': 'connected' if tastytrade_connected else ('configured' if tastytrade_configured else 'not_configured'),
                'account_type': 'PAPER' if (tastytrade_creds and tastytrade_creds.get('paper_trading', True)) else 'LIVE',
                'buying_power': tastytrade_buying_power,
                'positions': tastytrade_positions,
                'configured': tastytrade_configured
            }
            
            health_data['brokers'] = broker_status
            
            # Feature Settings - Load from config.ini and database
            config_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), 'config.ini')
            config = configparser.ConfigParser()
            features = {}
            
            if os.path.exists(config_path):
                config.read(config_path)
                
                # AI Features
                features['ai_analysis'] = {
                    'enabled': config.getboolean('ai_analysis', 'enable_ai_analysis', fallback=False),
                    'model': config.get('ai_analysis', 'model', fallback='gpt-4o-mini'),
                    'description': 'Post-trade AI analysis'
                }
                features['ai_commands'] = {
                    'enabled': config.getboolean('ai_analysis', 'enable_ai_commands', fallback=False),
                    'channel': config.get('ai_analysis', 'ai_commands_channel_id', fallback=''),
                    'description': 'Interactive AI commands (!analyze, !ask)'
                }
                features['signal_conversion'] = {
                    'enabled': config.getboolean('ai_analysis', 'enable_signal_conversion', fallback=False),
                    'channel': config.get('ai_analysis', 'signal_conversion_channel_id', fallback=''),
                    'description': 'Natural language to signal conversion'
                }
                features['sentiment_analysis'] = {
                    'enabled': config.getboolean('ai_analysis', 'enable_sentiment_analysis', fallback=False),
                    'description': 'Market sentiment analysis'
                }
                
                # Analysis Tools
                features['alpha_vantage'] = {
                    'enabled': config.getboolean('alpha_vantage', 'enable_scanner', fallback=False),
                    'min_premium': config.get('alpha_vantage', 'min_premium', fallback='100000'),
                    'dte_range': f"{config.get('alpha_vantage', 'dte_min', fallback='7')}-{config.get('alpha_vantage', 'dte_max', fallback='45')} days",
                    'description': 'Option flow scanner'
                }
                features['swing_trading'] = {
                    'enabled': config.getboolean('swing_analysis', 'enable_swing_analysis', fallback=False),
                    'min_confidence': config.get('swing_analysis', 'min_confidence_score', fallback='60'),
                    'auto_reject': config.getboolean('swing_analysis', 'auto_reject_low_confidence', fallback=False),
                    'description': 'Pre-trade swing analysis'
                }
                features['news_service'] = {
                    'enabled': config.getboolean('news', 'enable_news_service', fallback=False),
                    'description': 'Market news integration'
                }
                
                # Risk Management
                risk_enabled = config.getboolean('risk_management', 'enable_risk_management', fallback=False)
                features['global_risk'] = {
                    'enabled': risk_enabled,
                    'profit_target_1': config.get('risk_management', 'profit_target_1_pct', fallback='30') if risk_enabled else 'N/A',
                    'stop_loss': config.get('risk_management', 'stop_loss_pct', fallback='50') if risk_enabled else 'N/A',
                    'description': 'Global risk management'
                }
                features['slippage_protection'] = {
                    'enabled': config.getboolean('risk_management', 'enable_slippage_protection', fallback=False),
                    'max_slippage': config.get('risk_management', 'max_slippage_pct', fallback='5'),
                    'description': 'Price slippage protection'
                }
            
            health_data['features'] = features
            
            # Channel Configuration
            channels = db.get_channels()
            channel_summary = {
                'total': len(channels),
                'execute_enabled': 0,
                'track_enabled': 0,
                'paper_enabled': 0,
                'with_risk_settings': 0,
                'with_position_sizing': 0,
                'channels': []
            }
            
            for ch in channels:
                if ch.get('execute_enabled'):
                    channel_summary['execute_enabled'] += 1
                if ch.get('track_enabled'):
                    channel_summary['track_enabled'] += 1
                if ch.get('paper_trade_enabled'):
                    channel_summary['paper_enabled'] += 1
                if ch.get('profit_target_1_pct') or ch.get('stop_loss_pct'):
                    channel_summary['with_risk_settings'] += 1
                if ch.get('position_size_pct') or ch.get('tracking_position_size_pct'):
                    channel_summary['with_position_sizing'] += 1
                
                if ch.get('execute_enabled') or ch.get('track_enabled') or ch.get('paper_trade_enabled'):
                    channel_summary['channels'].append({
                        'name': ch.get('name', 'Unknown'),
                        'execute': bool(ch.get('execute_enabled')),
                        'track': bool(ch.get('track_enabled')),
                        'paper': bool(ch.get('paper_trade_enabled')),
                        'position_size_pct': ch.get('position_size_pct'),
                        'paper_position_size_pct': ch.get('tracking_position_size_pct'),
                        'profit_target_1': ch.get('profit_target_1_pct'),
                        'stop_loss': ch.get('stop_loss_pct')
                    })
            
            health_data['channels'] = channel_summary
            
            # Open Positions
            open_trades = db.get_trades(status='OPEN')
            webull_count = sum(1 for t in open_trades if 'Webull' in str(t.get('broker', '')))
            alpaca_count = sum(1 for t in open_trades if 'Alpaca' in str(t.get('broker', '')) or 'ALPACA' in str(t.get('broker', '')))
            
            health_data['positions'] = {
                'total': len(open_trades),
                'webull': webull_count,
                'alpaca': alpaca_count,
                'symbols': list(set(t.get('symbol', '') for t in open_trades[:20]))
            }
            
            # Recent Activity (last 24h)
            recent_trades = db.get_recent_trades(hours=24) if hasattr(db, 'get_recent_trades') else []
            recent_errors = db.get_recent_errors(limit=5, hours=24) if hasattr(db, 'get_recent_errors') else []
            
            health_data['recent_activity'] = {
                'trades_24h': len(recent_trades) if recent_trades else 0,
                'errors_24h': len(recent_errors) if recent_errors else 0,
                'last_trade': recent_trades[0] if recent_trades else None,
                'has_critical_errors': any(e.get('severity') == 'critical' for e in recent_errors) if recent_errors else False
            }
            
            # Service Orchestrator Status
            services_status = {}
            try:
                service_registry = db.get_service_registry() if hasattr(db, 'get_service_registry') else []
                for svc in service_registry:
                    services_status[svc.get('service_id', 'unknown')] = {
                        'name': svc.get('display_name', 'Unknown'),
                        'enabled': bool(svc.get('enabled', 0)),
                        'status': svc.get('status', 'idle'),
                        'priority': svc.get('priority', 5),
                        'interval': svc.get('default_interval', 30),
                        'last_run': svc.get('last_run')
                    }
            except Exception:
                pass
            
            # Add per-channel risk count
            channels_with_risk = sum(1 for ch in channels if ch.get('risk_management_enabled'))
            services_status['risk_manager'] = services_status.get('risk_manager', {})
            services_status['risk_manager']['channels_with_risk'] = channels_with_risk
            services_status['risk_manager']['active'] = channels_with_risk > 0
            
            health_data['services'] = services_status
            
            # Broker Rate Limits
            rate_limits = {}
            try:
                from src.services.rate_limit_manager import get_rate_limit_manager
                rate_manager = get_rate_limit_manager()
                if rate_manager:
                    for broker in ['webull', 'alpaca', 'robinhood', 'ibkr', 'tastytrade', 'schwab']:
                        status = rate_manager.get_status(broker)
                        if status:
                            rate_limits[broker] = {
                                'requests_in_window': status.get('requests_in_window', 0),
                                'window_limit': status.get('window_limit', 0),
                                'utilization_pct': status.get('utilization_pct', 0),
                                'is_backing_off': status.get('is_backing_off', False),
                                'total_calls': status.get('total_calls', 0),
                                'rate_limit_hits': status.get('rate_limit_hits', 0)
                            }
            except ImportError:
                pass
            
            health_data['rate_limits'] = rate_limits
            
            return jsonify({'success': True, 'health': health_data})
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    @app.route('/api/health/test/<component>', methods=['POST'])
    @login_required
    def api_test_component(component):
        """Test a specific component"""
        try:
            result = {'success': False, 'message': 'Unknown component'}
            
            if component == 'discord':
                if _bot_instance and _bot_instance.is_ready():
                    result = {'success': True, 'message': f'Discord connected as {_bot_instance.user}'}
                else:
                    result = {'success': False, 'message': 'Discord not connected'}
            
            elif component == 'webull':
                if _bot_instance and hasattr(_bot_instance, 'broker') and _bot_instance.broker:
                    try:
                        broker = _bot_instance.broker
                        if hasattr(broker, '_client') and broker._client:
                            account = broker._client.get_account()
                            if account:
                                bp = 0.0
                                for field in ['settledFunds', 'cashBalance', 'buyingPower', 'dayBuyingPower']:
                                    if field in account:
                                        val = account[field]
                                        if isinstance(val, (int, float)):
                                            bp = float(val)
                                            break
                                        elif isinstance(val, str):
                                            try:
                                                bp = float(val.replace(',', ''))
                                                break
                                            except:
                                                continue
                                result = {'success': True, 'message': f'Webull connected - Buying Power: ${bp:,.2f}'}
                            else:
                                result = {'success': False, 'message': 'Could not fetch account info'}
                        else:
                            result = {'success': False, 'message': 'Webull client not initialized'}
                    except Exception as e:
                        result = {'success': False, 'message': f'Webull error: {str(e)}'}
                else:
                    result = {'success': False, 'message': 'Webull broker not available'}
            
            elif component == 'alpaca':
                if _bot_instance and hasattr(_bot_instance, 'paper_broker') and _bot_instance.paper_broker:
                    try:
                        broker = _bot_instance.paper_broker
                        if hasattr(broker, 'trading_client') and broker.trading_client:
                            account = broker.trading_client.get_account()
                            if account:
                                bp = float(account.buying_power)
                                result = {'success': True, 'message': f'Alpaca connected - Buying Power: ${bp:,.2f}'}
                            else:
                                result = {'success': False, 'message': 'Could not fetch account info'}
                        else:
                            result = {'success': False, 'message': 'Alpaca client not initialized'}
                    except Exception as e:
                        result = {'success': False, 'message': f'Alpaca error: {str(e)}'}
                else:
                    result = {'success': False, 'message': 'Alpaca broker not available'}
            
            return jsonify(result)
            
        except Exception as e:
            return jsonify({'success': False, 'message': str(e)})
    
    @app.route('/api/health/diagnostics', methods=['GET'])
    @login_required
    def api_system_diagnostics():
        """Run comprehensive system diagnostics - works in packaged builds"""
        try:
            results = {
                'checks': [],
                'summary': {'passed': 0, 'failed': 0, 'warnings': 0}
            }
            
            # 1. Database Integrity Check
            try:
                conn = db.get_connection()
                cursor = conn.cursor()
                
                required_tables = ['settings', 'channels', 'signals', 'trades', 'signal_lots', 'lot_closures', 'app_users']
                missing_tables = []
                for table in required_tables:
                    cursor.execute(f"SELECT name FROM sqlite_master WHERE type='table' AND name=?", (table,))
                    if not cursor.fetchone():
                        missing_tables.append(table)
                
                if missing_tables:
                    results['checks'].append({
                        'name': 'Database Tables',
                        'status': 'fail',
                        'message': f'Missing tables: {", ".join(missing_tables)}'
                    })
                    results['summary']['failed'] += 1
                else:
                    results['checks'].append({
                        'name': 'Database Tables',
                        'status': 'pass',
                        'message': f'All {len(required_tables)} required tables exist'
                    })
                    results['summary']['passed'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Database Tables',
                    'status': 'fail',
                    'message': f'Database error: {str(e)}'
                })
                results['summary']['failed'] += 1
            
            # 2. Channel Configuration Check
            try:
                channels = db.get_channels()
                execute_channels = [c for c in channels if c.get('execute_enabled')]
                track_channels = [c for c in channels if c.get('track_enabled')]
                
                if len(channels) == 0:
                    results['checks'].append({
                        'name': 'Channel Configuration',
                        'status': 'warning',
                        'message': 'No channels configured'
                    })
                    results['summary']['warnings'] += 1
                else:
                    results['checks'].append({
                        'name': 'Channel Configuration',
                        'status': 'pass',
                        'message': f'{len(channels)} channels ({len(execute_channels)} execute, {len(track_channels)} track)'
                    })
                    results['summary']['passed'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Channel Configuration',
                    'status': 'fail',
                    'message': f'Error: {str(e)}'
                })
                results['summary']['failed'] += 1
            
            # 3. Discord Bot Connection
            try:
                if _bot_instance and _bot_instance.is_ready():
                    bot_user = str(_bot_instance.user) if hasattr(_bot_instance, 'user') else 'Unknown'
                    results['checks'].append({
                        'name': 'Discord Bot',
                        'status': 'pass',
                        'message': f'Connected as {bot_user}'
                    })
                    results['summary']['passed'] += 1
                else:
                    results['checks'].append({
                        'name': 'Discord Bot',
                        'status': 'fail',
                        'message': 'Bot not connected'
                    })
                    results['summary']['failed'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Discord Bot',
                    'status': 'fail',
                    'message': f'Error: {str(e)}'
                })
                results['summary']['failed'] += 1
            
            # 4. Webull Broker Check
            try:
                if _bot_instance and hasattr(_bot_instance, 'broker') and _bot_instance.broker:
                    broker = _bot_instance.broker
                    if hasattr(broker, '_client') and broker._client:
                        try:
                            account = broker._client.get_account()
                            if account:
                                results['checks'].append({
                                    'name': 'Webull Live',
                                    'status': 'pass',
                                    'message': 'Connected and authenticated'
                                })
                                results['summary']['passed'] += 1
                            else:
                                results['checks'].append({
                                    'name': 'Webull Live',
                                    'status': 'warning',
                                    'message': 'Connected but account data unavailable'
                                })
                                results['summary']['warnings'] += 1
                        except:
                            results['checks'].append({
                                'name': 'Webull Live',
                                'status': 'warning',
                                'message': 'Client exists but account fetch failed'
                            })
                            results['summary']['warnings'] += 1
                    else:
                        results['checks'].append({
                            'name': 'Webull Live',
                            'status': 'warning',
                            'message': 'Broker configured but not connected'
                        })
                        results['summary']['warnings'] += 1
                else:
                    results['checks'].append({
                        'name': 'Webull Live',
                        'status': 'warning',
                        'message': 'Not configured'
                    })
                    results['summary']['warnings'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Webull Live',
                    'status': 'fail',
                    'message': f'Error: {str(e)}'
                })
                results['summary']['failed'] += 1
            
            # 5. Alpaca Broker Check
            try:
                if _bot_instance and hasattr(_bot_instance, 'paper_broker') and _bot_instance.paper_broker:
                    broker = _bot_instance.paper_broker
                    if hasattr(broker, 'trading_client') and broker.trading_client:
                        try:
                            account = broker.trading_client.get_account()
                            if account:
                                bp = float(account.buying_power)
                                results['checks'].append({
                                    'name': 'Alpaca Paper',
                                    'status': 'pass',
                                    'message': f'Connected - BP: ${bp:,.0f}'
                                })
                                results['summary']['passed'] += 1
                            else:
                                results['checks'].append({
                                    'name': 'Alpaca Paper',
                                    'status': 'warning',
                                    'message': 'Connected but no account data'
                                })
                                results['summary']['warnings'] += 1
                        except:
                            results['checks'].append({
                                'name': 'Alpaca Paper',
                                'status': 'warning',
                                'message': 'Client exists but account fetch failed'
                            })
                            results['summary']['warnings'] += 1
                    else:
                        results['checks'].append({
                            'name': 'Alpaca Paper',
                            'status': 'warning',
                            'message': 'Broker configured but not connected'
                        })
                        results['summary']['warnings'] += 1
                else:
                    results['checks'].append({
                        'name': 'Alpaca Paper',
                        'status': 'warning',
                        'message': 'Not configured'
                    })
                    results['summary']['warnings'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Alpaca Paper',
                    'status': 'fail',
                    'message': f'Error: {str(e)}'
                })
                results['summary']['failed'] += 1
            
            # 6. License Validation
            try:
                from src.license_client import LicenseClient
                license_key = db.get_setting('license_key', '')
                if not license_key:
                    results['checks'].append({
                        'name': 'License',
                        'status': 'warning',
                        'message': 'No license key configured'
                    })
                    results['summary']['warnings'] += 1
                else:
                    client = LicenseClient()
                    is_valid, result = client.validate_license(license_key)
                    if is_valid:
                        results['checks'].append({
                            'name': 'License',
                            'status': 'pass',
                            'message': 'Valid and active'
                        })
                        results['summary']['passed'] += 1
                    else:
                        error_msg = result.get('error', 'Invalid or expired') if isinstance(result, dict) else 'Invalid or expired'
                        results['checks'].append({
                            'name': 'License',
                            'status': 'fail',
                            'message': error_msg
                        })
                        results['summary']['failed'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'License',
                    'status': 'warning',
                    'message': f'Could not verify: {str(e)}'
                })
                results['summary']['warnings'] += 1
            
            # 7. Signal Pattern Check
            try:
                patterns = db.get_setting('signal_patterns')
                if patterns:
                    import json
                    pattern_list = json.loads(patterns) if isinstance(patterns, str) else patterns
                    results['checks'].append({
                        'name': 'Signal Patterns',
                        'status': 'pass',
                        'message': f'{len(pattern_list)} patterns configured'
                    })
                    results['summary']['passed'] += 1
                else:
                    results['checks'].append({
                        'name': 'Signal Patterns',
                        'status': 'warning',
                        'message': 'No custom patterns (using defaults)'
                    })
                    results['summary']['warnings'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Signal Patterns',
                    'status': 'warning',
                    'message': 'Using default patterns'
                })
                results['summary']['warnings'] += 1
            
            # 8. Open Positions Check
            try:
                cursor = db.get_connection().cursor()
                cursor.execute("SELECT COUNT(*) FROM signal_lots WHERE status != 'CLOSED'")
                open_lots = cursor.fetchone()[0]
                cursor.execute("SELECT COUNT(*) FROM trades WHERE status = 'OPEN'")
                open_trades = cursor.fetchone()[0]
                
                results['checks'].append({
                    'name': 'Open Positions',
                    'status': 'pass',
                    'message': f'{open_lots} lots, {open_trades} trades open'
                })
                results['summary']['passed'] += 1
            except Exception as e:
                results['checks'].append({
                    'name': 'Open Positions',
                    'status': 'warning',
                    'message': f'Could not check: {str(e)}'
                })
                results['summary']['warnings'] += 1
            
            # Calculate overall status
            if results['summary']['failed'] > 0:
                results['overall'] = 'fail'
            elif results['summary']['warnings'] > 0:
                results['overall'] = 'warning'
            else:
                results['overall'] = 'pass'
            
            return jsonify({'success': True, **results})
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)})
    
