    # ============ MULTI-BROKER DASHBOARD API ============
    
    @app.route('/api/v2/broker-states', methods=['GET'])
    @login_required
    def api_get_all_broker_states():
        """Get all broker states for multi-broker dashboard (no page reload)
        
        Industry-grade implementation:
        - Only returns CONFIGURED brokers (has credentials or connected)
        - Integrates with BrokerHealthMonitor for real-time status
        - Removes India region (USA + Canada only)
        """
        try:
            from datetime import datetime
            
            # Get live status from BrokerHealthMonitor singleton for real-time updates
            # BrokerHealthMonitor uses UPPERCASE normalized keys
            health_states = {}
            health_monitor = None
            try:
                from src.services.broker_health_monitor import get_health_monitor
                health_monitor = get_health_monitor()  # Use singleton instance
                # Use uppercase keys to match health monitor's normalization
                for broker_key in ['WEBULL', 'ALPACA_PAPER', 'ROBINHOOD', 'SCHWAB', 'IBKR', 'TASTYTRADE', 'QUESTRADE', 'TRADING212']:
                    state = health_monitor.get_broker_state(broker_key)
                    if state and state.get('status') != 'unknown':
                        health_states[broker_key.upper()] = state
            except Exception as e:
                print(f"[BROKER STATES] Health monitor error: {e}")
            
            configured_brokers = []
            
            if _bot_instance:
                broker_ready = getattr(_bot_instance, 'broker_ready', None)
                brokers_initialized = broker_ready and broker_ready.is_set() if broker_ready else False
                
                broker_mappings = [
                    ('WEBULL', 'broker', 'USA', 'USD', False),
                    ('ALPACA_PAPER', 'paper_broker', 'USA', 'USD', True),
                    ('ROBINHOOD', 'robinhood_broker', 'USA', 'USD', False),
                    ('SCHWAB', 'schwab_broker', 'USA', 'USD', False),
                    ('IBKR', 'ibkr_broker', 'USA', 'USD', False),
                    ('TASTYTRADE', 'tastytrade_broker', 'USA', 'USD', False),
                    ('QUESTRADE', 'questrade_broker', 'Canada', 'CAD', False),
                    ('TRADING212', 'trading212_broker', 'UK_EU', 'GBP', False),
                ]
                
                creds_check_map = {
                    'WEBULL': 'webull_credentials',
                    'ALPACA_PAPER': 'alpaca_credentials',
                    'IBKR': 'ibkr_credentials',
                    'SCHWAB': 'schwab_credentials',
                    'ROBINHOOD': 'robinhood_credentials',
                    'TASTYTRADE': 'tastytrade_credentials',
                    'QUESTRADE': 'questrade_credentials',
                    'TRADING212': 'trading212_credentials',
                }
                for broker_name, attr_name, region, currency, is_paper in broker_mappings:
                    broker_instance = getattr(_bot_instance, attr_name, None)
                    if broker_instance is None:
                        creds_key = creds_check_map.get(broker_name)
                        if creds_key:
                            try:
                                from gui_app.config_service import load_config as _load_creds_cfg
                                creds_data = _load_creds_cfg(creds_key)
                                _has_real_creds = False
                                if isinstance(creds_data, dict):
                                    _cred_vals = [v for k, v in creds_data.items() if k not in ('paper_mode', 'dry_run', 'account_type') and v]
                                    _has_real_creds = len(_cred_vals) > 0
                                elif creds_data:
                                    _has_real_creds = True
                                if _has_real_creds:
                                    fallback_paper = is_paper
                                    if isinstance(creds_data, dict):
                                        fallback_paper = creds_data.get('paper_mode', is_paper)
                                    broker_reason_map = {
                                        'IBKR': 'Broker configured but not connected — check gateway/TWS is running',
                                        'ROBINHOOD': 'Broker configured but not connected — check login credentials',
                                        'WEBULL': 'Broker configured but not connected — check credentials or tokens',
                                        'SCHWAB': 'Broker configured but not connected — check OAuth tokens',
                                        'ALPACA_PAPER': 'Broker configured but not connected — check API keys',
                                        'TASTYTRADE': 'Broker configured but not connected — check login credentials',
                                        'QUESTRADE': 'Broker configured but not connected — check API tokens',
                                        'TRADING212': 'Broker configured but not connected — check API key',
                                    }
                                    configured_brokers.append({
                                        'broker_name': broker_name,
                                        'region': region,
                                        'is_connected': False,
                                        'balance': 0,
                                        'buying_power': 0,
                                        'currency': currency,
                                        'is_paper': fallback_paper,
                                        'status': 'disconnected',
                                        'reason': broker_reason_map.get(broker_name, 'Broker configured but not connected — check credentials'),
                                        'error_code': None,
                                        'last_check': None
                                    })
                            except Exception:
                                pass
                        continue
                    
                    if broker_name in ('WEBULL',):
                        if hasattr(broker_instance, 'is_authenticated'):
                            instance_connected = broker_instance.is_authenticated()
                        else:
                            instance_connected = getattr(broker_instance, '_logged_in', False)
                            if instance_connected and hasattr(broker_instance, '_tokens_valid') and not broker_instance._tokens_valid:
                                instance_connected = False
                    else:
                        instance_connected = (
                            getattr(broker_instance, 'connected', False) or 
                            getattr(broker_instance, '_logged_in', False)
                        )
                    
                    broker_tokens_expired = (
                        broker_instance and 
                        hasattr(broker_instance, '_tokens_valid') and 
                        not broker_instance._tokens_valid
                    )
                    if not instance_connected and not brokers_initialized and not broker_tokens_expired:
                        continue
                    
                    # Get real-time status from health monitor (uses uppercase keys)
                    health_key = broker_name.upper()
                    health = health_states.get(health_key, {})
                    
                    if broker_tokens_expired:
                        is_connected = False
                    elif instance_connected:
                        is_connected = True
                    elif health:
                        is_connected = health.get('is_connected', False)
                    else:
                        is_connected = False
                    
                    # Show any broker that has an instance (means it's configured)
                    # Connected brokers show, disconnected brokers show with their error reason
                    
                    buying_power = 0
                    balance = 0
                    if health_monitor and is_connected:
                        cached_info = health_monitor.get_cached_account_info(health_key)
                        if cached_info:
                            buying_power = health_monitor._extract_buying_power(health_key, cached_info, 'options')
                            balance = cached_info.get('portfolio_value', cached_info.get('balance', 0))
                        else:
                            try:
                                from gui_app.database import get_broker_state
                                db_state = get_broker_state(broker_name)
                                if db_state:
                                    buying_power = float(db_state.get('buying_power', 0) or 0)
                                    balance = float(db_state.get('balance', 0) or 0)
                            except Exception:
                                pass
                    if is_connected and buying_power == 0 and balance == 0 and broker_instance:
                        broker_cache = getattr(broker_instance, '_account_cache', None)
                        if broker_cache:
                            buying_power = float(broker_cache.get('buying_power', 0) or 0)
                            balance = float(broker_cache.get('portfolio_value', broker_cache.get('balance', 0)) or 0)
                    
                    disconnect_reason = health.get('reason')
                    if not is_connected and not disconnect_reason and broker_instance:
                        if hasattr(broker_instance, '_tokens_valid') and not broker_instance._tokens_valid:
                            disconnect_reason = 'Auth tokens expired - please re-authenticate in Settings → Brokers'
                        elif hasattr(broker_instance, 'connected') and not broker_instance.connected:
                            last_error = getattr(broker_instance, '_last_error', None) or getattr(broker_instance, 'last_error', None)
                            if last_error:
                                disconnect_reason = str(last_error)
                            else:
                                disconnect_reason = 'Broker not connected'
                    
                    delayed_data = False
                    if broker_name == 'IBKR' and is_connected:
                        try:
                            from src.services.ibkr_data_hub import get_ibkr_data_hub
                            ibkr_hub = get_ibkr_data_hub()
                            if ibkr_hub and hasattr(ibkr_hub, 'is_delayed'):
                                delayed_data = ibkr_hub.is_delayed()
                        except Exception:
                            pass

                    state = {
                        'broker_name': broker_name,
                        'region': region,
                        'is_connected': is_connected,
                        'balance': balance,
                        'buying_power': buying_power,
                        'currency': currency,
                        'is_paper': is_paper or getattr(broker_instance, 'paper_trade', False),
                        'status': health.get('status', 'connected' if is_connected else 'disconnected'),
                        'reason': disconnect_reason,
                        'error_code': health.get('error_code'),
                        'last_check': health.get('last_check'),
                        'delayed_data': delayed_data
                    }
                    
                    configured_brokers.append(state)
            
            grouped = {'USA': [], 'Canada': [], 'UK_EU': []}
            for state in configured_brokers:
                region = state.get('region', 'USA')
                if region in grouped:
                    grouped[region].append(state)
            
            return jsonify({
                'success': True,
                'states': configured_brokers,
                'by_region': grouped,
                'timestamp': datetime.now().isoformat()
            })
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
    def _populate_broker_states_from_bot():
        """Populate broker states from connected bot brokers (USA + Canada only)"""
        import asyncio
        
        if not _bot_instance:
            print("[BROKER STATES] No bot instance available")
            return
        
        broker_ready = getattr(_bot_instance, 'broker_ready', None)
        brokers_initialized = broker_ready and broker_ready.is_set() if broker_ready else False
        
        broker_mappings = [
            ('webull', 'broker', 'US', 'USD'),
            ('alpaca_paper', 'paper_broker', 'US', 'USD'),
            ('tastytrade', 'tastytrade_broker', 'US', 'USD'),
            ('ibkr', 'ibkr_broker', 'US', 'USD'),
            ('robinhood', 'robinhood_broker', 'US', 'USD'),
            ('schwab', 'schwab_broker', 'US', 'USD'),
            ('questrade', 'questrade_broker', 'CA', 'CAD'),
            ('trading212', 'trading212_broker', 'UK', 'GBP'),
        ]
        
        loop = getattr(_bot_instance, 'loop', None)
        print(f"[BROKER STATES] Populating states, loop running: {loop and loop.is_running()}, brokers_initialized: {brokers_initialized}")
        
        for broker_name, attr_name, country, currency in broker_mappings:
            try:
                broker_instance = getattr(_bot_instance, attr_name, None)
                is_connected = broker_instance and getattr(broker_instance, 'connected', False)
                if not is_connected and broker_instance and broker_name == 'webull':
                    is_connected = getattr(broker_instance, '_logged_in', False)
                if is_connected and broker_instance and hasattr(broker_instance, '_tokens_valid'):
                    if not broker_instance._tokens_valid:
                        is_connected = False
                is_paper = getattr(broker_instance, 'paper_trade', False) if broker_instance else False
                is_paper = is_paper or 'paper' in broker_name.lower()
                
                state = {
                    'is_connected': is_connected,
                    'balance': 0,
                    'buying_power': 0,
                    'currency': currency,
                    'is_paper': is_paper,
                    'sync_error': None
                }
                
                if is_connected and loop and loop.is_running():
                    try:
                        future = asyncio.run_coroutine_threadsafe(
                            broker_instance.get_account_info(), loop
                        )
                        account_info = future.result(timeout=15)
                        print(f"[BROKER STATES] {broker_name} account_info: {account_info}")
                        state['balance'] = account_info.get('portfolio_value', 0) or account_info.get('net_liquidation', 0) or account_info.get('available_balance', 0)
                        state['buying_power'] = account_info.get('buying_power', 0) or account_info.get('cash', 0)
                        print(f"[BROKER STATES] {broker_name}: balance=${state['balance']:,.2f}, buying_power=${state['buying_power']:,.2f}")
                    except Exception as e:
                        state['sync_error'] = str(e)
                        print(f"[BROKER STATES] {broker_name} error: {e}")
                        cached = getattr(broker_instance, '_account_cache', None)
                        if cached:
                            state['balance'] = cached.get('portfolio_value', 0) or cached.get('balance', 0) or 0
                            state['buying_power'] = cached.get('buying_power', 0) or cached.get('cash', 0) or 0
                            state['sync_error'] = None
                            print(f"[BROKER STATES] {broker_name}: using cached data, balance=${state['balance']:,.2f}")
                
                if state['is_connected'] or brokers_initialized:
                    db.update_broker_state(broker_name, country, state)
            except Exception as e:
                print(f"[BROKER STATES] Error populating {broker_name}: {e}")
    
