    @app.route('/api/brokers/upstox/orders', methods=['GET'])
    @login_required
    def api_upstox_orders():
        """Get Upstox order book"""
        try:
            if not _bot_instance:
                return jsonify({'success': False, 'error': 'Bot not running'})
            
            upstox_broker = getattr(_bot_instance, 'upstox_broker', None)
            if not upstox_broker or not getattr(upstox_broker, 'connected', False):
                return jsonify({'success': False, 'error': 'Upstox not connected'})
            
            import asyncio
            loop = getattr(_bot_instance, 'loop', None)
            if loop and loop.is_running():
                future = asyncio.run_coroutine_threadsafe(
                    upstox_broker.get_order_book(), loop
                )
                orders = future.result(timeout=15)
                
                # Upstox uses various status strings - normalize matching
                def is_open_status(status):
                    if not status:
                        return False
                    s = status.lower()
                    return any(x in s for x in ['open', 'pending', 'trigger', 'validation', 'after market order req received'])
                
                def is_filled_status(status):
                    if not status:
                        return False
                    s = status.lower()
                    return any(x in s for x in ['complete', 'filled', 'traded'])
                
                def is_rejected_status(status):
                    if not status:
                        return False
                    s = status.lower()
                    return any(x in s for x in ['rejected', 'cancelled', 'cancel'])
                
                open_orders = [o for o in orders if is_open_status(o.get('status'))]
                filled_orders = [o for o in orders if is_filled_status(o.get('status'))]
                rejected_orders = [o for o in orders if is_rejected_status(o.get('status'))]
                
                return jsonify({
                    'success': True,
                    'orders': orders,
                    'open': open_orders,
                    'filled': filled_orders,
                    'rejected': rejected_orders
                })
            else:
                return jsonify({'success': False, 'error': 'Event loop not running'})
        except Exception as e:
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': str(e)}), 500
    
